                                        <p className="text-sm font-mono font-bold leading-relaxed">
                                            {currentReport.cleanedCount > 1
                                                ? `Este segmento foi auditado com base em ${currentReport.cleanedCount} amostras válidas. A análise estatística indica uma confiabilidade global de ${currentReport.consolidated.globalProbability.toFixed(1)}%, caracterizando o lote como ${currentReport.consolidated.globalProbability > 85 ? 'EXCELENTE para processamento industrial' : currentReport.consolidated.globalProbability > 70 ? 'ADEQUADO com ressalvas técnicas' : 'REQUER ATENÇÃO ESPECIAL'}. Os parâmetros críticos apresentam variação média controlada.`
                                                : "Análise baseada em amostra única. Os valores apresentados são medições pontuais e não permitem inferência estatística sobre a variabilidade do lote completo. Recomenda-se análise de amostras adicionais para validação."
                                            }
                                        </p>
                                    </div>
                                </div>

                                {/* TABELA TÉCNICA CONSOLIDADA */}
                                <div className="space-y-4">
                                    <h4 className="text-lg font-serif font-black italic uppercase flex items-center gap-3">
                                        <div className="h-1 w-10 bg-black" />
                                        Parâmetros Técnicos Consolidados
                                    </h4>
                                    <div className="border-2 border-black overflow-hidden shadow-lg">
                                        <table className="w-full">
                                            <thead className="bg-black text-white">
                                                <tr className="text-[10px] font-mono uppercase tracking-wider">
                                                    <th className="p-3 text-left border-r border-white/20">Parâmetro</th>
                                                    <th className="p-3 text-center border-r border-white/20">Média</th>
                                                    <th className="p-3 text-center border-r border-white/20">Desvio</th>
                                                    <th className="p-3 text-center border-r border-white/20">CV%</th>
                                                    <th className="p-3 text-center border-r border-white/20">Min</th>
                                                    <th className="p-3 text-center">Max</th>
                                                </tr>
                                            </thead>
                                            <tbody className="bg-white">
                                                {currentReport?.parameterAnalyses?.map((analysis: ParameterAnalysis, idx: number) => (
                                                    <tr key={analysis.param} className={cn("border-b border-black/10 hover:bg-neutral-50 transition-colors", idx % 2 === 0 ? "bg-white" : "bg-neutral-50/30")}>
                                                        <td className="p-3 font-serif font-black italic text-base border-r border-black/10">
                                                            {analysis.displayName}
                                                            <div className="text-[9px] font-mono font-normal opacity-50 mt-0.5">{getParamMeaning(analysis.param)}</div>
                                                        </td>
                                                        <td className="p-3 text-center font-mono font-black text-lg border-r border-black/10">{analysis.stats.mean.toFixed(2)}</td>
                                                        <td className="p-3 text-center font-mono text-sm text-neutral-500 border-r border-black/10">{analysis.stats.stdDev.toFixed(3)}</td>
                                                        <td className={cn("p-3 text-center font-mono font-black border-r border-black/10", analysis.stats.cv > 5 ? "text-red-600" : "text-blue-600")}>
                                                            {currentReport.cleanedCount > 1 ? analysis.stats.cv.toFixed(2) + '%' : '—'}
                                                        </td>
                                                        <td className="p-3 text-center font-mono text-sm opacity-60 border-r border-black/10">{analysis.stats.min.toFixed(2)}</td>
                                                        <td className="p-3 text-center font-mono text-sm opacity-60">{analysis.stats.max.toFixed(2)}</td>
                                                    </tr>
                                                )) || []}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>

                                {/* ANÁLISE VISUAL POR PARÂMETRO */}
                                <div className="space-y-16">
                                    <h4 className="text-lg font-serif font-black italic uppercase flex items-center gap-3">
                                        <div className="h-1 w-10 bg-black" />
                                        Análise Visual de Distribuição
                                    </h4>

                                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                                        {currentReport?.parameterAnalyses?.map((analysis: ParameterAnalysis) => {
                                            const interpretation = getInterpretation(analysis, currentReport.cleanedCount);
                                            return (
                                                <div key={analysis.param} className="border-2 border-black p-6 bg-white shadow-md hover:shadow-xl transition-shadow">
                                                    <div className="flex items-center justify-between mb-4 pb-3 border-b border-black/10">
                                                        <div className="flex items-center gap-3">
                                                            <h5 className="text-xl font-serif font-black italic">{analysis.displayName}</h5>
                                                            <span className={cn("px-2 py-0.5 text-[8px] font-mono font-black uppercase border border-black", interpretation.bg, interpretation.color)}>
                                                                {interpretation.label}
                                                            </span>
                                                        </div>
                                                        <span className="text-2xl font-serif font-black italic">{analysis.stats.mean.toFixed(2)}</span>
                                                    </div>

                                                    <div className="h-32 border border-black/20 bg-neutral-50/50 p-3 flex items-end gap-1 relative mb-3">
                                                        <div className="absolute top-1 left-1 text-[7px] font-mono opacity-20 uppercase font-black">Distribuição</div>
                                                        {(analysis.distribution || []).map((d: { label: string; value: number; percent: number }, i: number) => (
                                                            <div
                                                                key={i}
                                                                className="flex-1 bg-black/90 hover:bg-black transition-all cursor-pointer relative group h-dynamic"
                                                                style={{ '--dynamic-height': `${d.percent}%` } as React.CSSProperties}
                                                                title={`${d.label}: ${d.percent.toFixed(1)}%`}
                                                            >
                                                                <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[7px] px-1 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                                                                    {d.percent.toFixed(1)}%
                                                                </div>
                                                            </div>
                                                        ))}
                                                    </div>

                                                    <div className="grid grid-cols-3 gap-3 text-center text-[10px] font-mono">
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">Min</div>
                                                            <div className="font-black">{analysis.stats.min.toFixed(2)}</div>
                                                        </div>
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">CV%</div>
                                                            <div className={cn("font-black", analysis.stats.cv > 5 ? "text-red-600" : "text-blue-600")}>
                                                                {currentReport.cleanedCount > 1 ? analysis.stats.cv.toFixed(2) + '%' : '—'}
                                                            </div>
                                                        </div>
                                                        <div>
                                                            <div className="opacity-40 uppercase mb-0.5">Max</div>
                                                            <div className="font-black">{analysis.stats.max.toFixed(2)}</div>
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        }) || []}
                                    </div>
                                </div>

                                {/* RODAPÉ */}
                                <div className="border-t-4 border-black pt-10 flex flex-col md:flex-row justify-between items-center gap-6 opacity-40">
                                    <div className="flex items-center gap-4">
                                        <div className="h-10 w-10 border-2 border-black flex items-center justify-center font-black text-sm italic bg-black text-white">OR</div>
                                        <div className="flex flex-col">
                                            <span className="text-[10px] font-serif font-black italic uppercase">Laudo Técnico Certificado</span>
                                            <span className="text-[8px] font-mono font-black uppercase">Emitido em: {new Date().toLocaleString('pt-BR')}</span>
                                        </div>
                                    </div>
                                    <div className="text-[8px] font-mono font-black uppercase text-right">
                                        ORIGO Intelligence • Fiberscan Analytics Engine v4.3
                                    </div>
                                </div>

                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>,
        document.body
    );
}

import { useMemo, useState } from "react";
import type { Sample } from "@/entities/Sample";
import { cn } from "@/lib/utils";
import { formatDecimalBR } from "@/services/ocrExtraction";
import { TrendingUp, Activity, BarChart3, LineChart, AreaChart } from "lucide-react";

interface MovingAverageChartProps {
    samples: Sample[];
    windowSize?: number;
    onSampleHover?: (sampleId: string | null) => void;
}

// Todos os parâmetros HVI incluindo UNF
const FIELDS = [
    { key: 'mic', label: 'MIC' },
    { key: 'len', label: 'LEN' },
    { key: 'unf', label: 'UNF' },
    { key: 'str', label: 'STR' },
    { key: 'rd', label: 'RD' },
    { key: 'b', label: '+b' },
] as const;

// Tipos de gráfico disponíveis
const CHART_TYPES = [
    { key: 'line', label: 'Linhas', icon: LineChart },
    { key: 'area', label: 'Área', icon: AreaChart },
] as const;

// Labels em português sem termos normativos
const COLORS_MAP: Record<string, string> = {
    "#3b82f6": "GRUPO 1",
    "#10b981": "GRUPO 2",
    "#f59e0b": "GRUPO 3",
    "#ef4444": "GRUPO 4",
};

interface ChartSample extends Sample {
    parsedVal: number;
    globalIndex?: number;
}

export default function MovingAverageChart({ samples, windowSize = 3, onSampleHover }: MovingAverageChartProps) {
    const [selectedField, setSelectedField] = useState<typeof FIELDS[number]['key']>('mic');
    const [hoveredSample, setHoveredSample] = useState<ChartSample | null>(null);
    const [chartType, setChartType] = useState<typeof CHART_TYPES[number]['key']>('line');


    // Ordenar amostras por ID para ordem cronológica
    const sortedSamples = useMemo(() =>
        [...samples].sort((a, b) => {
            const idA = parseInt(a.amostra_id.replace(/\D/g, '')) || 0;
            const idB = parseInt(b.amostra_id.replace(/\D/g, '')) || 0;
            return idA - idB;
        }),
        [samples]);

    const chartData = useMemo(() => {
        const fieldKey = selectedField;

        // Parse robusto de dados
        const validSamples = sortedSamples.filter(s => {
            const rawVal = (s as any)[fieldKey];
            let val = rawVal;
            if (typeof rawVal === 'string') {
                val = parseFloat(rawVal.replace(',', '.'));
            }
            return typeof val === 'number' && !isNaN(val) && val > 0;
        }).map(s => ({
            ...s,
            parsedVal: typeof (s as any)[fieldKey] === 'number'
                ? (s as any)[fieldKey]
                : parseFloat(((s as any)[fieldKey] as string).replace(',', '.'))
        })) as ChartSample[];


        if (validSamples.length === 0) return null;

        const values = validSamples.map(s => s.parsedVal);
        const minVal = Math.min(...values);
        const maxVal = Math.max(...values);
        const globalAvg = values.reduce((a, b) => a + b, 0) / values.length;

        // Calcular desvio padrão
        const variance = values.reduce((acc, val) => acc + Math.pow(val - globalAvg, 2), 0) / values.length;
        const stdDev = Math.sqrt(variance);

        const margin = (maxVal - minVal) * 0.2 || (maxVal * 0.1) || 1;
        const yMin = Math.max(0, minVal - margin);
        const yMax = maxVal + margin;
        const yRange = yMax - yMin;

        // Dimensões
        const width = 1200;
        const height = 450;
        const padding = { left: 60, right: 40, top: 40, bottom: 60 };

        const chartWidth = width - padding.left - padding.right;
        const chartHeight = height - padding.top - padding.bottom;

        const totalPoints = validSamples.length;
        const stepX = chartWidth / (Math.max(totalPoints - 1, 1));

        // Agrupar dados por cor (Séries)
        const series = Object.keys(COLORS_MAP).map(color => {
            const groupSamples = validSamples
                .map((s, i) => ({ ...s, globalIndex: i }))
                .filter(s => s.cor === color);

            if (groupSamples.length === 0) return null;

            // Estatísticas do GRUPO
            const groupValues = groupSamples.map(s => s.parsedVal);
            const groupAvg = groupValues.reduce((a, b) => a + b, 0) / groupValues.length;
            const groupVariance = groupValues.reduce((acc, val) => acc + Math.pow(val - groupAvg, 2), 0) / groupValues.length;
            const groupStdDev = Math.sqrt(groupVariance);

            // Coordenadas baseadas no índice GLOBAL
            const points = groupSamples.map((s) => {
                const x = padding.left + (s.globalIndex * stepX);
                const y = padding.top + chartHeight - ((s.parsedVal - yMin) / yRange) * chartHeight;
                // Detectar outliers (>1.5σ DO GRUPO)
                const isOutlier = Math.abs(s.parsedVal - groupAvg) > 1.5 * groupStdDev;
                return { x, y, val: s.parsedVal, original: s, color, isOutlier };
            });

            // Path conectando APENAS estes pontos
            const path = points.length > 1
                ? `M ${points[0].x},${points[0].y} ` + points.slice(1).map(p => `L ${p.x},${p.y}`).join(" ")
                : null;

            return { color, points, path };
        }).filter(s => s !== null);

        // Linhas de grade baseadas nos valores reais
        const gridValues = [
            minVal,
            minVal + (maxVal - minVal) * 0.25,
            minVal + (maxVal - minVal) * 0.5,
            minVal + (maxVal - minVal) * 0.75,
            maxVal
        ];

        const gridLines = gridValues.map((val) => {
            const y = padding.top + chartHeight - ((val - yMin) / yRange) * chartHeight;
            return { y, val };
        });

        // Labels do eixo X
        // Labels do eixo X - Mostrar todos se tiver poucas amostras, senão pular alguns
        const labelInterval = totalPoints <= 30 ? 1 : Math.ceil(totalPoints / 15);
        const xLabels = validSamples
            .map((s, i) => ({ s, i }))
            .filter(({ i }) => i % labelInterval === 0)
            .map(({ s, i }) => ({
                x: padding.left + (i * stepX),
                label: s.amostra_id.length > 2 ? s.amostra_id : `#${s.amostra_id}`
            }));

        const globalAvgY = padding.top + chartHeight - ((globalAvg - yMin) / yRange) * chartHeight;

        // Banda de desvio padrão
        const stdDevUpperY = padding.top + chartHeight - ((globalAvg + stdDev - yMin) / yRange) * chartHeight;
        const stdDevLowerY = padding.top + chartHeight - ((globalAvg - stdDev - yMin) / yRange) * chartHeight;

        return {
            series,
            gridLines,
            xLabels,
            globalAvg,
            globalAvgY,
            width,
            height,
            yMin,
            yMax,
            padding,
            stdDev,
            stdDevUpperY,
            stdDevLowerY
        };

    }, [sortedSamples, selectedField, windowSize]);

    if (!chartData || chartData.series.length === 0) return (
        <div className="w-full h-64 flex flex-col items-center justify-center bg-neutral-50 rounded-none border border-neutral-200">
            <BarChart3 className="h-8 w-8 text-neutral-300 mb-2" />
            <span className="text-xs font-bold uppercase tracking-widest text-neutral-400">Aguardando Dados...</span>
        </div>
    );

    return (
        <div className="w-full bg-white border border-black p-8 animate-fade-in relative flex flex-col gap-8 shadow-[8px_8px_0px_rgba(0,0,0,1)]">

            {/* Cabeçalho Unificado */}
            <div className="space-y-6">
                {/* Linha 1: Título e Status */}
                <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 border-b border-black pb-4">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-black text-white">
                            <TrendingUp className="h-5 w-5" />
                        </div>
                        <div>
                            <h3 className="text-sm font-black text-black uppercase tracking-widest leading-none mb-1">
                                Análise de Tendência
                            </h3>
                            <p className="text-[10px] text-neutral-500 font-medium">
                                Visualização temporal de indicadores de qualidade
                            </p>
                        </div>
                    </div>

                    <div className="flex items-center gap-6 text-[10px] bg-neutral-50 px-4 py-2 rounded-lg border border-neutral-100">
                        <div className="flex flex-col items-end">
                            <span className="text-neutral-400 uppercase tracking-widest text-[9px]">Média Global</span>
                            <strong className="text-black text-sm font-mono">{formatDecimalBR(chartData.globalAvg, 2)}</strong>
                        </div>
                        <div className="w-px h-8 bg-neutral-200"></div>
                        <div className="flex flex-col items-end">
                            <span className="text-neutral-400 uppercase tracking-widest text-[9px]">Desvio Padrão</span>
                            <strong className="text-black text-sm font-mono">{formatDecimalBR(chartData.stdDev, 2)}</strong>
                        </div>
                    </div>
                </div>

                {/* Linha 2: Barra de Controle (Parâmetros + Tipo de Gráfico + Legenda) */}
                <div className="flex flex-col xl:flex-row items-center justify-between gap-4 bg-neutral-50 p-2 rounded-xl border border-neutral-200">

                    {/* Grupo Esquerda: Parâmetros */}
                    <div className="flex items-center gap-1 overflow-x-auto w-full xl:w-auto p-1">
                        {FIELDS.map(f => (
                            <button
                                key={f.key}
                                onClick={() => setSelectedField(f.key as any)}
                                className={cn(
                                    "px-4 py-2 text-[10px] font-bold uppercase tracking-widest transition-all rounded-lg whitespace-nowrap flex-1 md:flex-none text-center",
                                    selectedField === f.key
                                        ? "bg-black text-white shadow-md"
                                        : "text-neutral-500 hover:bg-white hover:text-black hover:shadow-sm"
                                )}
                            >
                                {f.label}
                            </button>
                        ))}
                    </div>

                    {/* Divisor Responsivo */}
                    <div className="hidden xl:block w-px h-8 bg-neutral-300"></div>

                    {/* Grupo Direita: Legenda e Tipos */}
                    <div className="flex flex-wrap items-center justify-center gap-4 w-full xl:w-auto">

                        {/* Legenda Compacta */}
                        <div className="flex items-center gap-2 pr-4 border-r border-neutral-300">
                            <div className="flex -space-x-1">
                                <div className="w-3 h-3 rounded-full bg-[#10b981] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#3b82f6] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#f59e0b] border border-white"></div>
                                <div className="w-3 h-3 rounded-full bg-[#ef4444] border border-white"></div>
                            </div>
                            <span className="text-[9px] font-bold uppercase text-neutral-400 tracking-wider">Grupos 1-4</span>
                        </div>

                        {/* Seletor de Tipo */}
                        <div className="flex items-center bg-white rounded-lg p-1 border border-neutral-200 shadow-sm">
                            {CHART_TYPES.map(type => {
                                const Icon = type.icon;
                                return (
                                    <button
                                        key={type.key}
                                        onClick={() => setChartType(type.key)}
                                        title={type.label}
                                        className={cn(
                                            "p-2 rounded-md transition-all",
                                            chartType === type.key
                                                ? "bg-neutral-100 text-black mx-1"
                                                : "text-neutral-400 hover:text-black"
                                        )}
                                    >
                                        <Icon className="h-4 w-4" />
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>


            <div className="flex flex-col lg:flex-row gap-8">
                {/* Área do Gráfico */}
                <div className="relative flex-1 aspect-[16/9] bg-neutral-50/30 border border-neutral-100 group">
                    <svg id="trend-chart-svg" viewBox={`0 0 ${chartData.width} ${chartData.height}`} className="w-full h-full overflow-visible">

                        {/* Banda de Desvio Padrão */}
                        <rect
                            x={chartData.padding.left}
                            y={chartData.stdDevUpperY}
                            width={chartData.width - chartData.padding.left - chartData.padding.right}
                            height={chartData.stdDevLowerY - chartData.stdDevUpperY}
                            fill="#f0f0f0"
                            opacity="0.5"
                        />

                        {/* Grade e Eixo Y */}
                        {chartData.gridLines.map((line, i) => (
                            <g key={i}>
                                <line
                                    x1={chartData.padding.left}
                                    y1={line.y}
                                    x2={chartData.width - chartData.padding.right}
                                    y2={line.y}
                                    stroke="#e5e5e5"
                                    strokeWidth="1"
                                    strokeDasharray="4 4"
                                />
                                <text
                                    x={chartData.padding.left - 12}
                                    y={line.y + 6}
                                    textAnchor="end"
                                    className="fill-neutral-900 font-mono font-black"
                                    style={{ fontSize: '16px' }}
                                >
                                    {formatDecimalBR(line.val, 1)}
                                </text>
                            </g>
                        ))}

                        {/* Linha de Média Global */}
                        <line
                            x1={chartData.padding.left}
                            y1={chartData.globalAvgY}
                            x2={chartData.width - chartData.padding.right}
                            y2={chartData.globalAvgY}
                            stroke="black"
                            strokeWidth="1"
                            strokeDasharray="2 2"
                            opacity="0.3"
                        />
                        <text x={chartData.width - chartData.padding.right + 5} y={chartData.globalAvgY + 4} className="text-[9px] fill-black font-mono font-bold opacity-50">MÉDIA</text>

                        {/* Paths e Pontos das Séries - RENDERIZAÇÃO CONDICIONAL */}
                        {chartData.series.map((s, i) => (
                            <g key={s.color}>

                                {/* GRÁFICO DE ÁREA */}
                                {chartType === 'area' && s.path && (
                                    <>
                                        <path
                                            d={`${s.path} L ${s.points[s.points.length - 1].x},${chartData.height - chartData.padding.bottom} L ${s.points[0].x},${chartData.height - chartData.padding.bottom} Z`}
                                            fill={s.color}
                                            opacity="0.2"
                                        />
                                        <path
                                            d={s.path}
                                            fill="none"
                                            stroke={s.color}
                                            strokeWidth="2"
                                            strokeLinecap="round"
                                            strokeLinejoin="round"
                                            opacity="0.8"
                                        />
                                    </>
                                )}

                                {/* GRÁFICO DE LINHAS */}
                                {chartType === 'line' && s.path && (
                                    <path
                                        d={s.path}
                                        fill="none"
                                        stroke={s.color}
                                        strokeWidth="2.5"
                                        strokeLinecap="round"
                                        strokeLinejoin="round"
                                        className="opacity-90"
                                    />
                                )}

                                {/* PONTOS DE DADOS - Comum a ambos */}
                                {s.points.map((p, idx) => (
                                    <g key={`${i}-${idx}`}>
                                        <circle
                                            cx={p.x}
                                            cy={p.y}
                                            r="8"
                                            fill="transparent"
                                            className="hover:cursor-pointer z-10"
                                            onMouseEnter={() => {
                                                setHoveredSample(p.original);
                                                if (onSampleHover) onSampleHover(p.original.id);
                                            }}
                                            onClick={() => {
                                                if (hoveredSample?.id === p.original.id) {
                                                    setHoveredSample(null);
                                                    if (onSampleHover) onSampleHover(null);
                                                } else {
                                                    setHoveredSample(p.original);
                                                    if (onSampleHover) onSampleHover(p.original.id);
                                                }
                                            }}
                                        />
                                        {/* Destaque de Outlier */}
                                        {p.isOutlier && (
                                            <circle
                                                cx={p.x}
                                                cy={p.y}
                                                r="10"
                                                fill="none"
                                                stroke="#ef4444"
                                                strokeWidth="2"
                                                strokeDasharray="2 2"
                                                className="animate-pulse"
                                            />
                                        )}
                                        <circle
                                            cx={p.x}
                                            cy={p.y}
                                            r="4"
                                            fill={p.isOutlier ? "#ef4444" : (chartType === 'area' ? s.color : "white")}
                                            stroke={chartType === 'area' ? "white" : s.color}
                                            strokeWidth="2.5"
                                            className="pointer-events-none transition-all"
                                        />
                                    </g>
                                ))}
                            </g>
                        ))}


                        {/* Anel de Destaque ao Hover - Estático e Discreto */}
                        {hoveredSample && (
                            <circle
                                cx={(chartData.series.flatMap(s => s.points).find(p => p.original.id === hoveredSample.id))?.x || 0}
                                cy={(chartData.series.flatMap(s => s.points).find(p => p.original.id === hoveredSample.id))?.y || 0}
                                r="6"
                                fill="white"
                                stroke="black"
                                strokeWidth="2"
                                className="z-20 shadow-sm"
                            />
                        )}


                        {/* Labels do Eixo X */}
                        {chartData.xLabels.map((lbl, i) => (
                            <text
                                key={i}
                                x={lbl.x}
                                y={chartData.height - 10}
                                textAnchor="middle"
                                className="fill-neutral-900 font-mono font-bold"
                                style={{ fontSize: '12px' }}
                            >
                                {lbl.label}
                            </text>
                        ))}
                    </svg>

                    {/* Legenda */}
                    <div className="absolute bottom-2 left-16 flex items-center gap-4 text-[9px]">
                        <div className="flex items-center gap-1">
                            <div className="w-3 h-3 bg-neutral-200 opacity-50"></div>
                            <span className="text-neutral-500">Banda ±1σ</span>
                        </div>
                        <div className="flex items-center gap-1">
                            <div className="w-3 h-3 rounded-full border-2 border-red-500 border-dashed"></div>
                            <span className="text-red-500">Outlier (&gt;2σ)</span>
                        </div>
                    </div>
                </div>

                {/* Painel de Detalhes */}
                <div className="w-full lg:w-64 min-h-[200px] border-l border-neutral-100 pl-0 lg:pl-10 flex flex-col gap-6">
                    <div className="flex items-center gap-2 border-b border-black pb-2 justify-between">
                        <div className="flex items-center gap-2">
                            <Activity className="h-4 w-4 text-black" />
                            <h4 className="text-xs font-bold uppercase tracking-widest">Inspetor</h4>
                        </div>
                        {hoveredSample && (
                            <button
                                onClick={() => setHoveredSample(null)}
                                className="text-[9px] font-bold text-neutral-400 hover:text-black uppercase tracking-tighter"
                            >
                                [ Desselecionar ]
                            </button>
                        )}
                    </div>

                    {hoveredSample ? (
                        <div className="space-y-6 animate-slide-up">
                            <div className="space-y-1">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block">Amostra Selecionada</span>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-4xl font-mono font-black tracking-tighter">#{hoveredSample.amostra_id}</span>
                                    <span className="text-[10px] uppercase font-bold text-neutral-400 max-w-[100px] truncate">{hoveredSample.mala || 'Sem Mala'}</span>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block">Métrica Principal ({selectedField.toUpperCase()})</span>
                                <div className="flex items-center gap-3">
                                    <span className="text-3xl font-mono font-bold border-b-2 border-black">
                                        {formatDecimalBR(hoveredSample.parsedVal || 0, 2)}
                                    </span>
                                    <div className={`px-2 py-1 rounded text-[10px] font-bold uppercase text-white`} style={{ backgroundColor: hoveredSample.cor || '#000' }}>
                                        {COLORS_MAP[hoveredSample.cor || ''] || 'S/COR'}
                                    </div>
                                </div>
                            </div>

                            <div className="p-4 bg-neutral-50 border border-neutral-200 space-y-3">
                                <span className="text-[9px] text-neutral-400 uppercase tracking-widest block border-b border-neutral-200 pb-1">Dados Contextuais</span>
                                <div className="grid grid-cols-2 gap-y-2 gap-x-4 text-[10px] font-mono">
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>MIC</span>
                                        <span className={selectedField === 'mic' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.mic || 0, 2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>LEN</span>
                                        <span className={selectedField === 'len' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.len || 0, 2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>UNF</span>
                                        <span className={selectedField === 'unf' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.unf || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>STR</span>
                                        <span className={selectedField === 'str' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.str || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>RD</span>
                                        <span className={selectedField === 'rd' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.rd || 0, 1)}</span>
                                    </div>
                                    <div className="flex justify-between items-center text-neutral-600">
                                        <span>+b</span>
                                        <span className={selectedField === 'b' ? 'font-bold text-black' : ''}>{formatDecimalBR(hoveredSample.b || 0, 1)}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center text-center opacity-40 space-y-4">
                            <div className="w-16 h-16 bg-neutral-100 rounded-full flex items-center justify-center">
                                <Activity className="h-6 w-6 text-neutral-400" />
                            </div>
                            <p className="text-[10px] uppercase font-bold text-neutral-500 max-w-[150px] leading-relaxed">
                                Passe o mouse sobre qualquer ponto para ver os dados HVI
                            </p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState } from "react";
import { createPortal } from "react-dom";
import { type Sample } from "@/entities/Sample";
import { X, Bot, Loader2, BarChart3, TrendingUp } from "lucide-react";
import { Button } from "@/components/ui/button";
import { DeepSeekService } from "@/services/DeepSeekService";

interface PatternAnalysisModalProps {
    isOpen: boolean;
    onClose: () => void;
    samples: Sample[];
    onApplyColors: (updates: Record<string, string>) => void;
}

interface Group {
    id: string;
    label?: string;
    micAvg: number;
    lenAvg: number;
    unfAvg: number;
    strAvg: number;
    rdAvg: number;
    bAvg: number;
    count: number;
    sampleIds: string[];
    color: string | null;
    patternFeatures?: string[];
}

export default function PatternAnalysisModal({ isOpen, onClose, samples, onApplyColors }: PatternAnalysisModalProps) {
    const [groups, setGroups] = useState<Group[]>([]);
    const [scanned, setScanned] = useState(false);

    // AI Report State
    const [aiAnalysis, setAiAnalysis] = useState("");
    const [isAiLoading, setIsAiLoading] = useState(false);
    const [isScanning, setIsScanning] = useState(false);

    // Análise de Padrões Estatísticos
    const runAnalysis = () => {
        setScanned(false);
        setIsScanning(true);

        setTimeout(() => {
            try {
                const result = DeepSeekService.classifySamplesSmart(samples);
                setGroups(result);
            } catch (error) {
                console.error("Erro na identificação de padrões:", error);
            }
            setScanned(true);
            setIsScanning(false);
        }, 1000);
    };

    const handleGenerateReport = async () => {
        setIsAiLoading(true);
        try {
            const analysis = await DeepSeekService.analyzeSamples(samples);
            setAiAnalysis(analysis);
        } catch (error) {
            setAiAnalysis("Erro ao gerar relatório descritivo.");
        } finally {
            setIsAiLoading(false);
        }
    };

    const handleApply = () => {
        const updates: Record<string, string> = {};

        // Aplicar cores de todos os grupos
        groups.forEach(group => {
            if (group.color) {
                group.sampleIds.forEach(id => {
                    updates[id] = group.color as string;
                });
            }
        });

        onApplyColors(updates);
        onClose();
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

            <div className="relative w-full max-w-5xl max-h-[90vh] bg-white text-black flex flex-col shadow-2xl animate-fade-in border border-black">
                {/* Header */}
                <div className="flex items-center justify-between p-8 border-b border-black">
                    <div className="space-y-1">
                        <h2 className="text-2xl font-serif leading-none flex items-center gap-3">
                            Analista Inteligente
                            <span className="text-sm bg-neutral-100 text-neutral-800 px-2 py-0.5 rounded font-mono font-bold">PADRÕES</span>
                        </h2>
                        <p className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">
                            Identificação Estatística de Padrões Laboratoriais HVI
                        </p>
                    </div>
                    <div className="flex items-center gap-2">
                        <button onClick={onClose} className="p-2 hover:bg-neutral-100 rounded-full" title="Fechar" aria-label="Fechar">
                            <X className="h-5 w-5" />
                        </button>
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-8 bg-neutral-50/50">

                    {!scanned ? (
                        <div className="h-full flex flex-col items-center justify-center space-y-6 py-12">
                            <div className={`w-20 h-20 bg-neutral-100 border border-neutral-200 flex items-center justify-center rounded-full ${isScanning ? 'animate-spin' : 'animate-pulse'}`}>
                                {isScanning ? (
                                    <Loader2 className="h-8 w-8 text-black" />
                                ) : (
                                    <BarChart3 className="h-8 w-8 text-black" />
                                )}
                            </div>
                            <div className="text-center space-y-2">
                                <h3 className="text-lg font-bold">Iniciar Identificação de Padrões</h3>
                                <p className="text-sm text-neutral-500 max-w-lg mx-auto">
                                    O Analista Inteligente identificará padrões estatísticos e agrupará
                                    <strong> todas as {samples.length} amostras</strong> por comportamento semelhante.
                                    <br /><br />
                                    <span className="text-xs text-neutral-400">
                                        Análise puramente descritiva — Sem aplicação de normas ou tolerâncias.
                                    </span>
                                </p>
                            </div>
                            <Button
                                onClick={runAnalysis}
                                disabled={isScanning}
                                className="px-8 h-12 bg-black text-white hover:bg-neutral-800 uppercase tracking-widest text-xs font-bold rounded-none shadow-lg"
                            >
                                {isScanning ? "Analisando..." : "Identificar Padrões"}
                            </Button>
                        </div>
                    ) : (
                        <div className="space-y-8">
                            {/* Header dos Resultados */}
                            <div className="flex items-center justify-between">
                                <h3 className="text-sm font-bold uppercase tracking-widest flex items-center gap-2">
                                    <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
                                    Agrupamentos Identificados
                                    <span className="text-neutral-400 font-normal ml-2">
                                        ({groups.reduce((acc, g) => acc + g.count, 0)} amostras = 100%)
                                    </span>
                                </h3>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={runAnalysis}
                                    className="h-8 text-[10px] uppercase font-bold border-black hover:bg-neutral-50 rounded-none bg-white"
                                >
                                    Reanalisar
                                </Button>
                            </div>

                            {groups.length === 0 ? (
                                <div className="text-center py-12 border-2 border-dashed border-neutral-300 bg-white">
                                    <p className="text-neutral-400 text-xs font-bold uppercase tracking-widest">
                                        Nenhum padrão estatístico identificado nos dados disponíveis
                                    </p>
                                </div>
                            ) : (
                                <div className="grid gap-4">
                                    {groups.map((group) => {
                                        const features = group.patternFeatures || [];

                                        return (
                                            <div key={group.id}
                                                className="bg-white border-l-4 p-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 shadow-sm hover:shadow-md transition-all"
                                                ref={(el) => {
                                                    if (el) {
                                                        const c = group.color || '#000';
                                                        el.style.borderLeftColor = c;
                                                        el.style.setProperty('--group-color', c);
                                                    }
                                                }}
                                            >
                                                {/* Estatísticas do Grupo */}
                                                <div className="flex items-center gap-6 flex-1">
                                                    <div
                                                        className="h-14 w-14 flex-shrink-0 text-white flex flex-col items-center justify-center font-mono font-bold leading-none rounded-lg shadow-sm bg-[var(--group-color)]"
                                                    >
                                                        <span className="text-xl">{group.count}</span>
                                                        <span className="text-[8px] opacity-80 uppercase">Obs.</span>
                                                    </div>
                                                    <div className="space-y-3 flex-1">
                                                        <div className="flex flex-col md:flex-row md:items-center gap-3">
                                                            <span className="text-xs uppercase font-bold tracking-widest text-black flex items-center gap-2 min-w-fit">
                                                                <TrendingUp className="h-3 w-3" />
                                                                {group.label || group.id}
                                                            </span>

                                                            {/* Tags de Características do Padrão */}
                                                            <div className="flex flex-wrap gap-2">
                                                                {features.map((feature, i) => (
                                                                    <span key={i} className="px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wider bg-neutral-100 text-neutral-700 ring-1 ring-neutral-200">
                                                                        {feature}
                                                                    </span>
                                                                ))}
                                                            </div>
                                                        </div>

                                                        {/* Grid de Estatísticas */}
                                                        <div className="grid grid-cols-6 gap-4 text-xs font-mono border-t border-neutral-100 pt-2 text-neutral-600">
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">MIC</span>
                                                                <b>{(group.micAvg || 0).toFixed(2)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">LEN</span>
                                                                <b>{(group.lenAvg || 0).toFixed(2)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">STR</span>
                                                                <b>{(group.strAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">RD</span>
                                                                <b>{(group.rdAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">+B</span>
                                                                <b>{(group.bAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                            <div className="text-center">
                                                                <span className="text-[8px] text-neutral-400 block mb-0.5">UNF</span>
                                                                <b>{(group.unfAvg || 0).toFixed(1)}</b>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                                {/* Badge de Identificação */}
                                                <div className="hidden md:flex flex-col items-end gap-1">
                                                    <span className="text-[9px] uppercase font-bold text-neutral-400 tracking-widest">Padrão</span>
                                                    <div
                                                        className="px-3 py-1 rounded bg-neutral-100 text-xs font-bold uppercase tracking-wider text-right shadow-sm border border-neutral-200"
                                                        ref={(el) => { if (el) el.style.color = group.color || '#000'; }}
                                                    >
                                                        {group.id}
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}

                            {/* Seção de Relatório Descritivo */}
                            <div className="pt-8 border-t border-neutral-200 mt-8">
                                <div className="flex items-center justify-between mb-6">
                                    <div>
                                        <h3 className="font-bold text-lg">Relatório Descritivo Completo</h3>
                                        <p className="text-[10px] uppercase tracking-widest text-neutral-400">
                                            Análise estatística detalhada — Sem critérios normativos
                                        </p>
                                    </div>
                                    {!aiAnalysis && (
                                        <Button
                                            onClick={handleGenerateReport}
                                            disabled={isAiLoading}
                                            variant="outline"
                                            className="h-10 px-6 uppercase text-xs font-bold tracking-widest border-black text-black hover:bg-black hover:text-white transition-colors"
                                        >
                                            {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Bot className="w-4 h-4 mr-2" />}
                                            {isAiLoading ? "Gerando..." : "Gerar Relatório"}
                                        </Button>
                                    )}
                                </div>
                                {aiAnalysis && (
                                    <div className="bg-white p-8 border border-neutral-200 shadow-sm font-mono text-xs leading-relaxed border-l-4 border-l-black animate-in fade-in slide-in-from-bottom-2 duration-500 max-h-96 overflow-y-auto">
                                        <pre className="whitespace-pre-wrap">{aiAnalysis}</pre>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </div>

                {/* Footer */}
                {scanned && (
                    <div className="p-8 border-t border-black bg-white flex justify-between items-center">
                        <p className="text-[10px] font-mono font-bold text-neutral-400 uppercase tracking-widest">
                            {groups.reduce((acc, g) => acc + g.count, 0)} Observações em {groups.length} Grupos
                        </p>
                        <div className="flex gap-4">
                            <Button
                                variant="ghost"
                                onClick={onClose}
                                className="h-12 px-6 rounded-none uppercase text-xs font-bold tracking-widest hover:bg-neutral-100"
                            >
                                Cancelar
                            </Button>
                            <Button
                                onClick={handleApply}
                                disabled={groups.length === 0}
                                className="h-12 px-8 bg-black text-white hover:bg-neutral-800 rounded-none uppercase text-xs font-bold tracking-widest disabled:opacity-50 shadow-xl"
                            >
                                Aprovar e Aplicar Cores
                            </Button>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
}

import { useEffect, useMemo, useState } from "react";
import * as Lucide from "lucide-react";
import { cn } from "@/lib/utils";
import { supabase } from "@/lib/supabase";
import { useAuth } from "@/contexts/AuthContext";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer, ReferenceLine } from 'recharts';

export const formatName = (name: string) => {
    return name.replace(/Linha\/Mq/gi, "MAQ").replace(/LINHA\/MQ/gi, "MAQ");
};

const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
        return (
            <div className="bg-white/95 backdrop-blur-sm border border-neutral-200 p-4 shadow-2xl rounded-xl animate-in fade-in zoom-in duration-200">
                <p className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 mb-2 border-b border-neutral-100 pb-1">{label}</p>
                <div className="space-y-1.5">
                    {payload.map((entry: any, index: number) => (
                        <div key={`${entry.name}-${index}`} className="flex items-center justify-between gap-8">
                            <div className="flex items-center gap-2">
                                <div className="h-2 w-2 rounded-full shadow-sm bg-dynamic" style={{ '--bg-color': entry.stroke || entry.color } as React.CSSProperties} />
                                <span className="text-[11px] font-medium text-neutral-600 uppercase pt-0.5">{entry.name}</span>
                            </div>
                            <span className="text-[11px] font-mono font-bold text-black">{Number(entry.value).toLocaleString('pt-BR')}</span>
                        </div>
                    ))}
                </div>
            </div>
        );
    }
    return null;
};

interface ProductionData {
    id?: string;
    data_producao: string;
    turno: string;
    peso: number;
    produto?: string;
    offset_peso?: number;
}

interface ProductionTrendChartProps {
    data: ProductionData[];
}

interface SHIFT_CONFIG {
    hex: string;
    bg: string;
    text: string;
}

const SHIFT_COLORS_CONFIG: Record<string, SHIFT_CONFIG> = {
    "TURNO 1": { hex: "#1d4ed8", bg: "bg-blue-700", text: "text-blue-700" },
    "TURNO 2": { hex: "#047857", bg: "bg-emerald-700", text: "text-emerald-700" },
    "TURNO 3": { hex: "#b45309", bg: "bg-amber-700", text: "text-amber-700" },
    "GERAL": { hex: "#4b5563", bg: "bg-gray-600", text: "text-gray-600" },
    "TOTAL DIA": { hex: "#000000", bg: "bg-black", text: "text-black" }
};

const MACHINE_COLORS_CONFIG: SHIFT_CONFIG[] = [
    { hex: "#dc2626", bg: "bg-red-600", text: "text-red-600" },
    { hex: "#ea580c", bg: "bg-orange-600", text: "text-orange-600" },
    { hex: "#ca8a04", bg: "bg-yellow-600", text: "text-yellow-600" },
    { hex: "#65a30d", bg: "bg-lime-600", text: "text-lime-600" },
    { hex: "#0d9488", bg: "bg-teal-600", text: "text-teal-600" },
    { hex: "#0891b2", bg: "bg-cyan-600", text: "text-cyan-600" },
    { hex: "#4f46e5", bg: "bg-indigo-600", text: "text-indigo-600" },
    { hex: "#c026d3", bg: "bg-fuchsia-600", text: "text-fuchsia-600" },
    { hex: "#e11d48", bg: "bg-rose-600", text: "text-rose-600" },
    { hex: "#7c3aed", bg: "bg-violet-600", text: "text-violet-600" }
];

interface ChartPoint {
    date: string;
    val: number;
    id: string;
    type: string;
}

export default function ProductionTrendChart({ data }: ProductionTrendChartProps) {
    const { currentLab, user } = useAuth();
    const labId = currentLab?.id || user?.lab_id;

    type ViewMode = 'general' | 'detailed' | 'machine_comparison' | 'compare_machines_total';
    const [viewMode, setViewMode] = useState<ViewMode>('general');
    const [selectedShift, setSelectedShift] = useState<string>("TURNO 1");
    const [selectedMachine, setSelectedMachine] = useState<string>("");

    const [dateStart, setDateStart] = useState<string>('');
    const [dateEnd, setDateEnd] = useState<string>('');

    const [targetValue, setTargetValue] = useState<number | null>(null);
    const [isSavingTarget, setIsSavingTarget] = useState(false);
    const [showTargetLine, setShowTargetLine] = useState(false);
    const [showMovingAverage, setShowMovingAverage] = useState(false);
    const [granularity, setGranularity] = useState<'day' | 'week' | 'month'>('day');

    useEffect(() => {
        const loadTarget = async () => {
            if (!labId) return;
            const { data: config } = await supabase
                .from('operacao_producao_config')
                .select('meta_producao')
                .eq('lab_id', labId)
                .maybeSingle();

            if (config?.meta_producao) {
                setTargetValue(config.meta_producao);
                setShowTargetLine(true);
            }
        };
        loadTarget();
    }, [labId]);

    const saveTargetToDB = async (val: number) => {
        if (!labId) return;
        setIsSavingTarget(true);
        try {
            await supabase
                .from('operacao_producao_config')
                .upsert({
                    lab_id: labId,
                    meta_producao: val,
                    updated_at: new Date().toISOString()
                }, { onConflict: 'lab_id' });
        } catch (e) {
            console.error("Erro ao salvar meta:", e);
        } finally {
            setIsSavingTarget(false);
        }
    };



    const availableShifts = useMemo(() => Array.from(new Set(data.map(d => d.turno))).sort(), [data]);
    const availableMachines = useMemo(() => {
        const productSums: Record<string, number> = {};
        data.forEach(d => {
            const name = d.produto || "Desconhecido";
            productSums[name] = (productSums[name] || 0) + (d.peso || 0);
        });
        return Array.from(new Set(data.map(d => d.produto || "Desconhecido")))
            .filter(m => productSums[m] > 0)
            .sort();
    }, [data]);

    useEffect(() => {
        if (!selectedMachine && availableMachines.length > 0) {
            setSelectedMachine(availableMachines[0]);
        }
    }, [availableMachines, selectedMachine]);

    const filteredData = useMemo(() => {
        if (data.length === 0) return [];
        if (!dateStart || !dateEnd) return data;

        const start = new Date(dateStart).setHours(0, 0, 0, 0);
        const end = new Date(dateEnd).setHours(23, 59, 59, 999);

        return data.filter(d => {
            const dTime = new Date(d.data_producao).getTime();
            return dTime >= start && dTime <= end;
        }).sort((a, b) => new Date(a.data_producao).getTime() - new Date(b.data_producao).getTime());
    }, [data, dateStart, dateEnd]);

    const kpis = useMemo(() => {
        if (filteredData.length === 0) return { total: 0, avg: 0, peak: 0, peakDate: '-' };
        const dayMap = new Map<string, number>();
        filteredData.forEach(d => {
            const current = dayMap.get(d.data_producao) || 0;
            dayMap.set(d.data_producao, current + d.peso);
        });
        const dailyValues = Array.from(dayMap.values());
        const total = dailyValues.reduce((a, b) => a + b, 0);
        const avg = total / (dailyValues.length || 1);
        const peak = Math.max(...dailyValues);
        const peakEntry = Array.from(dayMap.entries()).find(([, val]) => val === peak);
        const peakDate = peakEntry ? peakEntry[0].split('-').reverse().slice(0, 2).join('/') : '-';
        return { total, avg, peak, peakDate };
    }, [filteredData]);

    const sortedDataResult = useMemo(() => {
        const seriesMap = new Map<string, ChartPoint[]>();
        if (viewMode === 'general') {
            availableShifts.forEach(t => seriesMap.set(t, []));
            seriesMap.set("TOTAL DIA", []);
            const aggregatedMap = new Map<string, Record<string, number>>();
            filteredData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                periodData[d.turno] = (periodData[d.turno] || 0) + d.peso;
                periodData['TOTAL DIA'] = (periodData['TOTAL DIA'] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableShifts.forEach(turno => {
                    if (values[turno] > 0) {
                        seriesMap.get(turno)?.push({ date: dateKey, val: values[turno], id: `${dateKey}-${turno}`, type: turno });
                    }
                });
                if (values['TOTAL DIA'] > 0) {
                    seriesMap.get("TOTAL DIA")?.push({ date: dateKey, val: values['TOTAL DIA'], id: `${dateKey}-TOTAL`, type: "TOTAL DIA" });
                }
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else if (viewMode === 'detailed') {
            const shiftData = filteredData.filter(d => d.turno === selectedShift);
            availableMachines.forEach(m => seriesMap.set(m, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            shiftData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                if (d.produto) periodData[d.produto] = (periodData[d.produto] || 0) + (d.offset_peso ?? d.peso);
                else periodData['???'] = (periodData['???'] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableMachines.forEach(mq => {
                    if (values[mq] > 0) seriesMap.get(mq)?.push({ date: dateKey, val: values[mq], id: `${dateKey}-${mq}`, type: mq });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else if (viewMode === 'machine_comparison') {
            const machineData = filteredData.filter(d => d.produto === selectedMachine);
            availableShifts.forEach(t => seriesMap.set(t, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            machineData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                periodData[d.turno] = (periodData[d.turno] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableShifts.forEach(turno => {
                    const val = values[turno] || 0;
                    if (val > 0) seriesMap.get(turno)?.push({ date: dateKey, val, id: `${dateKey}-${turno}-${selectedMachine}`, type: turno });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        } else {
            availableMachines.forEach(m => seriesMap.set(m, []));
            const aggregatedMap = new Map<string, Record<string, number>>();
            filteredData.forEach(d => {
                const date = new Date(d.data_producao);
                let key = d.data_producao;
                if (granularity === 'week') {
                    const day = date.getDay() || 7;
                    if (day !== 1) date.setHours(-24 * (day - 1));
                    key = date.toISOString().split('T')[0];
                } else if (granularity === 'month') {
                    key = d.data_producao.substring(0, 7) + '-01';
                }
                if (!aggregatedMap.has(key)) aggregatedMap.set(key, {});
                const periodData = aggregatedMap.get(key)!;
                if (d.produto) periodData[d.produto] = (periodData[d.produto] || 0) + d.peso;
            });
            const sortedKeys = Array.from(aggregatedMap.keys()).sort();
            sortedKeys.forEach(dateKey => {
                const values = aggregatedMap.get(dateKey)!;
                availableMachines.forEach(mq => {
                    if (values[mq] > 0) seriesMap.get(mq)?.push({ date: dateKey, val: values[mq], id: `${dateKey}-${mq}-TOTAL`, type: mq });
                });
            });
            return { uniqueDates: sortedKeys, series: seriesMap };
        }
    }, [filteredData, viewMode, selectedShift, selectedMachine, availableShifts, availableMachines, granularity]);

    const rechartsData = useMemo(() => {
        if (!sortedDataResult || sortedDataResult.uniqueDates.length === 0) return [];
        return sortedDataResult.uniqueDates.map(date => {
            const point: any = { date, displayDate: date.split('-').reverse().slice(0, 2).join('/') };
            Array.from(sortedDataResult.series.entries()).forEach(([name, points]) => {
                const found = points.find(p => p.date === date);
                if (found) point[name] = found.val;
            });
            return point;
        });
    }, [sortedDataResult]);

    const seriesConfig = useMemo(() => {
        if (!sortedDataResult) return [];
        return Array.from(sortedDataResult.series.keys()).map(name => {
            let color = "#000000";
            if (name === "TOTAL DIA") {
                color = SHIFT_COLORS_CONFIG["TOTAL DIA"].hex;
            } else if (SHIFT_COLORS_CONFIG[name]) {
                color = SHIFT_COLORS_CONFIG[name].hex;
            } else {
                const machIndex = availableMachines.indexOf(name);
                if (machIndex !== -1) {
                    color = MACHINE_COLORS_CONFIG[machIndex % MACHINE_COLORS_CONFIG.length].hex;
                } else {
                    let hash = 0;
                    for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
                    const c = (hash & 0x00FFFFFF).toString(16).toUpperCase();
                    color = "#" + "00000".substring(0, 6 - c.length) + c;
                }
            }
            return { name, color, isTotal: name === "TOTAL DIA" };
        });
    }, [sortedDataResult, availableMachines]);

    if (!rechartsData || rechartsData.length === 0) return (
        <div className="w-full h-64 flex flex-col items-center justify-center bg-neutral-50 border border-neutral-200 rounded-xl">
            <Lucide.BarChart3 className="h-8 w-8 text-neutral-300 mb-2" />
            <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">Dados insuficiente para o período</span>
        </div>
    );

    return (
        <div className="w-full bg-white border border-black p-6 animate-fade-in relative flex flex-col gap-6 shadow-[8px_8px_0px_rgba(0,0,0,1)] rounded-xl">
            <div className="flex flex-col md:flex-row items-start md:items-end justify-between gap-6 border-b border-black pb-6">
                <div className="flex items-center gap-4"><div className="p-3 bg-black text-white rounded shrink-0 shadow-lg"><Lucide.TrendingUp className="h-6 w-6" /></div><div><h3 className="text-xl font-serif text-black leading-none mb-1">Análise de Produção</h3><p className="text-[10px] text-neutral-500 font-bold uppercase tracking-widest">{viewMode === 'general' ? 'Visão Geral da Fábrica' : viewMode === 'detailed' ? 'Performance por Máquina' : 'Detalhamento'}</p></div></div>
                <div className="flex items-center gap-2 overflow-x-auto pb-1 md:pb-0 w-full md:w-auto">
                    <div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">Total</span><span className="text-lg font-mono font-black text-black leading-none">{kpis.total.toLocaleString('pt-BR')}</span></div>
                    <div className="w-px h-8 bg-neutral-200 hidden md:block" /><div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">Média</span><span className="text-lg font-mono font-black text-emerald-600 leading-none">{Math.round(kpis.avg).toLocaleString('pt-BR')}</span></div>
                    <div className="w-px h-8 bg-neutral-200 hidden md:block" /><div className="px-4 py-2 bg-neutral-50 border border-neutral-100 rounded-lg text-center min-w-[100px]"><span className="text-[9px] font-bold text-neutral-400 uppercase block">Pico ({kpis.peakDate})</span><span className="text-lg font-mono font-black text-blue-600 leading-none">{kpis.peak.toLocaleString('pt-BR')}</span></div>
                </div>
            </div>
            <div className="bg-neutral-50/50 p-2 rounded-lg border border-neutral-100 flex flex-col lg:flex-row items-center justify-between gap-4">
                <div className="flex flex-col sm:flex-row items-center gap-4 w-full lg:w-auto overflow-x-auto">
                    <div className="flex items-center gap-2 bg-white border border-neutral-200 rounded p-1.5 shadow-sm"><span className="text-[10px] font-bold text-neutral-500 uppercase">De:</span><input type="date" aria-label="Início" value={dateStart} onChange={(e) => setDateStart(e.target.value)} className="bg-transparent border-none p-0 text-[10px] font-bold uppercase" /><span className="text-neutral-300 mx-1">|</span><span className="text-[10px] font-bold text-neutral-500 uppercase">Até:</span><input type="date" aria-label="Fim" value={dateEnd} onChange={(e) => setDateEnd(e.target.value)} className="bg-transparent border-none p-0 text-[10px] font-bold uppercase" /></div>
                    <div className="h-6 w-px bg-neutral-300 hidden sm:block" />
                    <div className="flex items-center bg-white border border-neutral-200 rounded p-1 shadow-sm">{(['day', 'week', 'month'] as const).map(opt => (<button key={opt} onClick={() => setGranularity(opt)} className={cn("px-3 py-1.5 text-[10px] font-bold uppercase rounded transition-all", granularity === opt ? "bg-neutral-800 text-white shadow" : "text-neutral-400 hover:text-black hover:bg-neutral-50")}>{opt === 'day' ? 'Dia' : opt === 'week' ? 'Sem' : 'Mês'}</button>))}</div>
                </div>
                <div className="flex flex-wrap items-center gap-3 justify-end w-full lg:w-auto">
                    <button onClick={() => setShowMovingAverage(!showMovingAverage)} className={cn("flex items-center gap-2 px-3 h-9 rounded border transition-all text-[10px] font-bold uppercase tracking-wide", showMovingAverage ? "bg-orange-50 border-orange-200 text-orange-600 shadow-sm" : "bg-white border-neutral-200 text-neutral-400 hover:border-neutral-300 hover:text-neutral-600")}><Lucide.Activity className="h-3.5 w-3.5" /><span className="hidden sm:inline">Tendência</span></button>
                    <div className={cn("flex items-center gap-2 px-3 h-9 bg-white border rounded transition-all focus-within:ring-1 focus-within:ring-red-500", showTargetLine ? "border-red-200 shadow-sm" : "border-neutral-200")}><Lucide.Target className={cn("h-3.5 w-3.5", showTargetLine ? "text-red-500" : "text-neutral-300")} /><input type="number" placeholder="Meta" className="w-20 text-[10px] border-none p-0 font-mono focus:ring-0" value={targetValue || ''} onChange={(e) => { const v = Number(e.target.value); setTargetValue(v); setShowTargetLine(true); }} onBlur={() => targetValue && saveTargetToDB(targetValue)} />{isSavingTarget && <span className="text-[10px]">...</span>}</div>
                    <select title="Modo de Exibição" value={viewMode} onChange={(e) => setViewMode(e.target.value as ViewMode)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm focus:outline-none focus:ring-1 focus:ring-black cursor-pointer"><option value="general">Geral</option><option value="detailed">Por Máquina (Turno)</option><option value="compare_machines_total">Máquinas (Total)</option><option value="machine_comparison">Detalhamento</option></select>
                    {viewMode === 'detailed' && <select title="Turno" value={selectedShift} onChange={(e) => setSelectedShift(e.target.value)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm">{availableShifts.map(s => <option key={s} value={s}>{s}</option>)}</select>}
                    {viewMode === 'machine_comparison' && <select title="Máquina" value={selectedMachine} onChange={(e) => setSelectedMachine(e.target.value)} className="h-9 px-3 text-[10px] font-bold uppercase bg-white border border-neutral-200 rounded shadow-sm">{availableMachines.map(m => <option key={m} value={m}>{formatName(m)}</option>)}</select>}
                </div>
            </div>

            <div className="bg-neutral-50/50 border border-neutral-100 rounded-[1.5rem] p-4 h-[420px] w-full mt-2 shadow-inner">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={rechartsData} margin={{ top: 20, right: 30, left: 10, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e5e5" />
                        <XAxis dataKey="displayDate" axisLine={false} tickLine={false} tick={{ fill: '#9ca3af', fontSize: 10, fontWeight: 700 }} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#9ca3af', fontSize: 10, fontWeight: 700 }} tickFormatter={(val) => Math.round(val).toLocaleString('pt-BR')} />
                        <RechartsTooltip content={<CustomTooltip />} cursor={{ stroke: '#e5e5e5', strokeWidth: 2 }} />
                        {showTargetLine && targetValue && (
                            <ReferenceLine y={targetValue} stroke="#ef4444" strokeWidth={2} strokeDasharray="6 4" label={{ position: 'insideTopLeft', value: 'META', fill: '#ef4444', fontSize: 10, fontWeight: 900 }} />
                        )}
                        {seriesConfig.map((s) => (
                            <Line key={s.name} type="monotone" dataKey={s.name} name={formatName(s.name)} stroke={s.color} strokeWidth={s.isTotal ? 4 : 2.5} dot={{ r: s.isTotal ? 6 : 4, stroke: s.color, strokeWidth: 2, fill: '#fff' }} activeDot={{ r: s.isTotal ? 8 : 6, stroke: '#fff', strokeWidth: 2, fill: s.color }} />
                        ))}
                    </LineChart>
                </ResponsiveContainer>
            </div>

            <div className="flex flex-wrap items-center justify-center gap-x-6 gap-y-3 pt-6 pb-2 border-t border-neutral-100">
                {seriesConfig.map((s) => (
                    <div key={s.name} className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full shadow-sm bg-dynamic" style={{ '--bg-color': s.color } as React.CSSProperties} />
                        <span className="text-[10px] font-bold text-neutral-500 uppercase tracking-widest">{formatName(s.name)}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

import { Card, CardContent } from "@/components/ui/card";
import type { Sample } from "@/entities/Sample";
import { calculateStatistics } from "@/lib/stats";
import { AlertTriangle, Zap, Info, Pencil, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { formatDecimalBR } from "@/services/ocrExtraction";
import { useState } from "react";

interface StatisticsPanelProps {
    samples: Sample[];
    selectedColor?: string | null;
}

const COLORS: Record<string, string> = {
    "#ef4444": "VERMELHO",
    "#3b82f6": "AZUL",
    "#10b981": "VERDE",
    "#f59e0b": "AMARELO",
};

const CUSTOM_AVERAGES_KEY = 'custom_color_averages';

export default function StatisticsPanel({ samples, selectedColor }: StatisticsPanelProps) {
    const [editingField, setEditingField] = useState<{ color: string; field: string } | null>(null);
    const [editValue, setEditValue] = useState<string>('');

    const [customAverages, setCustomAverages] = useState<Record<string, Record<string, number>>>(() => {
        try {
            const stored = localStorage.getItem(CUSTOM_AVERAGES_KEY);
            return stored ? JSON.parse(stored) : {};
        } catch {
            return {};
        }
    });

    const fields = [
        { key: 'mic', label: 'MIC', decimals: 2 },
        { key: 'len', label: 'LEN', decimals: 2 },
        { key: 'str', label: 'STR', decimals: 1 },
        { key: 'rd', label: 'RD', decimals: 1 },
        { key: 'b', label: '+b', decimals: 1 },
    ] as const;

    const groups = samples.reduce((acc, s) => {
        if (s.cor) {
            if (!acc[s.cor]) acc[s.cor] = [];
            acc[s.cor].push(s);
        }
        return acc;
    }, {} as Record<string, Sample[]>);

    const colorsToShow = selectedColor ? [selectedColor] : Object.keys(groups);

    const generateAutomatedInsight = (groupSamples: Sample[]) => {
        const micStats = calculateStatistics(groupSamples.map(s => ({ id: s.id, val: s.mic || 0 })));
        if (micStats.stdDev > 0.4) return { message: "Alta Variabilidade", type: "warning" };
        if (micStats.mean < 3.5 || micStats.mean > 5.0) return { message: "Atenção: Média Atípica", type: "warning" };
        return { message: "Métricas Estáveis", type: "success" };
    };

    const getValue = (color: string, field: string, calculatedValue: number) => {
        return customAverages[color]?.[field] ?? calculatedValue;
    };

    const isCustomValue = (color: string, field: string) => {
        return customAverages[color]?.[field] !== undefined;
    };

    const startEditing = (color: string, field: string, currentValue: number, decimals: number) => {
        setEditingField({ color, field });
        // Format value to remove floating point artifacts
        setEditValue(currentValue.toFixed(decimals));
    };

    const saveEdit = () => {
        if (!editingField) return;
        const numValue = parseFloat(editValue);
        if (isNaN(numValue)) {
            cancelEdit();
            return;
        }

        const newCustomAverages = {
            ...customAverages,
            [editingField.color]: {
                ...customAverages[editingField.color],
                [editingField.field]: numValue
            }
        };

        setCustomAverages(newCustomAverages);
        localStorage.setItem(CUSTOM_AVERAGES_KEY, JSON.stringify(newCustomAverages));
        setEditingField(null);
        setEditValue('');
    };

    const cancelEdit = () => {
        setEditingField(null);
        setEditValue('');
    };

    const resetToCalculated = (color: string, field: string) => {
        const newCustomAverages = { ...customAverages };
        if (newCustomAverages[color]) {
            delete newCustomAverages[color][field];
            if (Object.keys(newCustomAverages[color]).length === 0) {
                delete newCustomAverages[color];
            }
        }
        setCustomAverages(newCustomAverages);
        localStorage.setItem(CUSTOM_AVERAGES_KEY, JSON.stringify(newCustomAverages));
    };

    if (colorsToShow.length === 0) {
        return (
            <div className="bg-neutral-50 rounded-xl p-12 text-center border border-neutral-200 border-dashed">
                <div className="bg-white h-12 w-12 rounded-full border border-neutral-100 flex items-center justify-center mx-auto mb-3 shadow-sm">
                    <Info className="h-5 w-5 text-neutral-400" />
                </div>
                <p className="text-neutral-900 font-bold uppercase tracking-widest text-xs">Sem Dados Classificados</p>
                <p className="text-[10px] text-neutral-500 mt-1 max-w-xs mx-auto">Classifique as amostras para visualizar as estatísticas por grupo.</p>
            </div>
        );
    }

    return (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
            {colorsToShow.map(color => {
                const groupSamples = groups[color] || [];
                if (groupSamples.length === 0) return null;

                const colorName = COLORS[color] || "GRUPO";
                const insight = generateAutomatedInsight(groupSamples);

                return (
                    <Card key={color} className="overflow-hidden border border-neutral-200 bg-white shadow-sm hover:shadow-lg transition-all duration-200">
                        {/* Thin color indicator */}
                        <div className="h-0.5 w-full" style={{ backgroundColor: color }} />

                        <CardContent className="p-6">
                            {/* Header */}
                            <div className="flex justify-between items-center mb-6">
                                <h4 className="text-sm font-bold uppercase tracking-wider text-neutral-700">
                                    {colorName}
                                </h4>
                                <span className="text-[10px] font-semibold text-neutral-400 bg-neutral-50 px-2 py-1 rounded">
                                    {groupSamples.length} amostras
                                </span>
                            </div>

                            {/* Metrics */}
                            <div className="space-y-4">
                                {fields.map(field => {
                                    const values = groupSamples.map(s => ({ id: s.id, val: (s as any)[field.key] })).filter(v => typeof v.val === 'number');
                                    const stats = calculateStatistics(values);
                                    const displayValue = getValue(color, field.key, stats.mean);
                                    const isCustom = isCustomValue(color, field.key);
                                    const isEditing = editingField?.color === color && editingField?.field === field.key;

                                    return (
                                        <div key={field.key}>
                                            {isEditing ? (
                                                <div className="flex items-center gap-2">
                                                    <span className="text-xs font-semibold text-neutral-400 uppercase w-12 shrink-0">
                                                        {field.label}
                                                    </span>
                                                    <input
                                                        type="number"
                                                        step={field.decimals === 2 ? "0.01" : "0.1"}
                                                        value={editValue}
                                                        onChange={(e) => setEditValue(e.target.value)}
                                                        onKeyDown={(e) => {
                                                            if (e.key === 'Enter') saveEdit();
                                                            if (e.key === 'Escape') cancelEdit();
                                                        }}
                                                        onBlur={saveEdit}
                                                        className="flex-1 min-w-0 px-3 py-2 text-xl font-mono font-bold border-2 border-blue-500 rounded-lg text-center focus:outline-none focus:ring-2 focus:ring-blue-300 bg-blue-50"
                                                        autoFocus
                                                    />
                                                </div>
                                            ) : (
                                                <div
                                                    className="flex items-center justify-between group/metric cursor-pointer py-2 px-3 -mx-3 rounded-lg hover:bg-neutral-50 transition-colors"
                                                    onClick={() => startEditing(color, field.key, displayValue, field.decimals)}
                                                >
                                                    <span className="text-xs font-semibold text-neutral-400 uppercase">
                                                        {field.label}
                                                    </span>
                                                    <div className="flex items-center gap-2">
                                                        <span
                                                            className={cn(
                                                                "text-2xl font-mono font-bold tabular-nums transition-colors",
                                                                isCustom ? "text-blue-600" : "text-neutral-900"
                                                            )}
                                                        >
                                                            {formatDecimalBR(displayValue, field.decimals)}
                                                        </span>
                                                        {isCustom ? (
                                                            <button
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    resetToCalculated(color, field.key);
                                                                }}
                                                                className="h-6 w-6 flex items-center justify-center rounded-md hover:bg-orange-100 text-orange-600 transition-colors shrink-0"
                                                                title="Restaurar valor calculado"
                                                            >
                                                                <X className="h-4 w-4" />
                                                            </button>
                                                        ) : (
                                                            <Pencil className="h-4 w-4 text-neutral-300 opacity-0 group-hover/metric:opacity-100 transition-opacity" />
                                                        )}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    )
                                })}
                            </div>

                            {/* Footer insight */}
                            <div className={cn(
                                "mt-6 pt-4 border-t flex items-center justify-center gap-2 text-[10px] font-bold uppercase tracking-wider",
                                insight.type === 'success' ? "border-emerald-100 text-emerald-600" : "border-amber-100 text-amber-600"
                            )}>
                                {insight.type === 'success' ? <Zap className="h-3.5 w-3.5" /> : <AlertTriangle className="h-3.5 w-3.5" />}
                                {insight.message}
                            </div>
                        </CardContent>
                    </Card>
                )
            })}
        </div>
    );
}

import { useMemo } from "react";
import type { Sample } from "@/entities/Sample";
import { Card, CardContent } from "@/components/ui/card";

interface ExportPreviewProps {
    samples: Sample[];
    separator: string;
    hasHeader: boolean;
    decimalSeparator: "." | ",";
    mode: "all" | "by_color";
    selectedColor?: string;
}

export default function ExportPreview({ samples, separator, hasHeader, decimalSeparator, mode, selectedColor }: ExportPreviewProps) {
    const previewContent = useMemo(() => {
        let filtered = samples;
        if (mode === "by_color" && selectedColor) {
            filtered = samples.filter(s => s.cor === selectedColor);
        }

        const headers = ["MIC", "LEN", "UNF", "STR", "RD", "+b"];
        const sep = separator === "tab" ? "\t" : separator;

        let lines: string[] = [];
        if (hasHeader) {
            lines.push(headers.join(sep));
        }

        filtered.forEach(s => {
            // MIC e LEN: 2 decimais, UNF/RD/+b: 1 decimal, STR: inteiro
            const row = [
                s.mic?.toFixed(2),
                s.len?.toFixed(2),
                s.unf?.toFixed(1),
                s.str?.toFixed(1),
                s.rd?.toFixed(1),
                s.b?.toFixed(1)
            ].map(val => {
                if (val === undefined || val === null) return "";
                let str = val.toString();
                if (decimalSeparator === ",") str = str.replace(".", ",");
                return str;
            });
            lines.push(row.join(sep));
        });

        return lines.join("\n");
    }, [samples, separator, hasHeader, decimalSeparator, mode, selectedColor]);

    return (
        <Card className="border-none shadow-2xl rounded-3xl overflow-hidden ring-1 ring-slate-800">
            <CardContent className="p-8 bg-slate-950 text-emerald-400 font-mono text-xs overflow-auto max-h-[500px] whitespace-pre-wrap leading-relaxed">
                <div className="flex items-center gap-2 mb-4 text-slate-500 border-b border-white/5 pb-2">
                    <div className="w-2 h-2 rounded-full bg-red-500"></div>
                    <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                    <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                    <span className="ml-2 text-[10px] font-black uppercase tracking-widest italic opacity-50">data_output_terminal</span>
                </div>
                {previewContent || "// Aguardando dados para exportação..."}
            </CardContent>
        </Card>
    );
}

