            };

            let error;
            if (isNew) {
                const result = await supabase.from('auditoria_categorias').insert([payload]);
                error = result.error;
            } else {
                const result = await supabase.from('auditoria_categorias').update(payload).eq('id', id);
                error = result.error;
            }

            if (error) {
                console.error("Supabase Error saving category:", error);
                throw error;
            }
            return;
        }

        const cats = await this.listCategories();
        const existingIndex = cats.findIndex(c => c.id === cat.id);
        if (existingIndex >= 0) {
            cats[existingIndex] = cat;
        } else {
            cats.push({ ...cat, id: cat.id || crypto.randomUUID() });
        }
        localStorage.setItem(CATS_KEY, JSON.stringify(cats));
    },

    async deleteCategory(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('auditoria_categorias').delete().eq('id', id);
            if (error) throw error;
            return;
        }
        const cats = await this.listCategories();
        const filtered = cats.filter(c => c.id !== id);
        localStorage.setItem(CATS_KEY, JSON.stringify(filtered));
    },

    // --- DOCUMENTS ---
    async list(): Promise<AuditDocument[]> {
        if (isSupabaseEnabled()) {
            try {
                console.log("DEBUG: Fetching audit_docs...");
                const { data, error } = await supabase
                    .from('auditoria_documentos')
                    .select('*');

                if (error) throw error;

                if (data && data.length > 0) {
                    detectedDbColumns = Object.keys(data[0]);
                    console.log("DEBUG: Columns found:", detectedDbColumns);
                }

                const docs = (data || []).map((d: any) => {
                    try {
                        return {
                            id: d.id,
                            name: d.name || 'Sem Nome',
                            fileName: d.fileName || d.filename || d.file_name || d.name || 'unknown',
                            fileSize: d.fileSize || d.filesize || d.file_size || 0,
                            fileType: d.fileType || d.filetype || d.file_type || 'application/octet-stream',
                            uploadDate: d.uploadDate || d.uploaddate || d.upload_date || d.created_at || new Date().toISOString(),
                            category: d.category || 'Geral',
                            analystName: d.analystName || d.analystname || d.analyst_name || 'Desconhecido',
                            status: d.status || 'verified',
                            labId: d.labId || d.labid || d.lab_id,
                            data: d.data
                        };
                    } catch (err) {
                        console.error("Mapping error for doc:", d, err);
                        return null;
                    }
                }).filter((d: any) => d !== null) as AuditDocument[];

                // Post-process: Generate Signed URLs for Storage Paths
                const pathsToSign: string[] = [];
                const docIndices: number[] = [];

                docs.forEach((doc, index) => {
                    if (doc.data && !doc.data.startsWith('data:') && !doc.data.startsWith('http')) {
                        pathsToSign.push(doc.data);
                        docIndices.push(index);
                    }
                });

                if (pathsToSign.length > 0) {
                    try {
                        const { data: signedData, error: _signError } = await supabase.storage
                            .from('audit-docs')
                            .createSignedUrls(pathsToSign, 3600); // Valid for 1 hour

                        if (signedData) {
                            signedData.forEach((item, i) => {
                                if (item.signedUrl) {
                                    docs[docIndices[i]].data = item.signedUrl;
                                }
                            });
                        }
                    } catch (signErr) {
                        console.warn("Failed to sign URLs, proceeding with raw paths:", signErr);
                    }
                }

                return docs.sort((a, b) => new Date(b.uploadDate).getTime() - new Date(a.uploadDate).getTime());

            } catch (authError) {
                console.warn("Supabase (Audit Docs) unavailable, falling back to local storage:", authError);
                // Fallback proceed to local storage code below
            }
        }
        const data = localStorage.getItem(DOCS_KEY);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return parsed.map((d: AuditDocument) => {
            const { data, ...rest } = d;
            return rest;
        });
    },

    async getContent(id: string): Promise<string | null> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase
                .from('auditoria_documentos')
                .select('*')
                .eq('id', id)
                .single();

            if (error || !data) return null;

            const rawData = data.data; // This might be base64, http url, or storage path

            if (rawData && !rawData.startsWith('data:') && !rawData.startsWith('http')) {
                // It's a storage path, get signed URL
                const { data: signed } = await supabase.storage
                    .from('audit-docs')
                    .createSignedUrl(rawData, 3600);
                return signed?.signedUrl || null;
            }

            return rawData || null;
        }
        const raw = localStorage.getItem(DOCS_KEY);
        if (!raw) return null;
        const parsed = JSON.parse(raw);
        const doc = parsed.find((d: AuditDocument) => d.id === id);
        return doc ? doc.data : null;
    },

    async listByLab(labId: string): Promise<AuditDocument[]> {
        const allDocs = await this.list();
        return allDocs.filter(d => d.labId === labId);
    },

    async upload(doc: Omit<AuditDocument, 'id' | 'uploadDate' | 'status'>, file?: File): Promise<AuditDocument> {
        if (isSupabaseEnabled()) {
            let finalData = doc.data;

            // 1. Upload to Supabase Storage if file is provided
            if (file) {
                try {
                    console.log("DEBUG: Starting Storage Upload...", file.name);
                    const cleanName = file.name.replace(/[^a-zA-Z0-9.-]/g, '_');
                    const uniquePath = `${Date.now()}_${cleanName}`;

                    const { error: uploadError } = await supabase.storage
                        .from('audit-docs')
                        .upload(uniquePath, file, {
                            cacheControl: '3600',
                            upsert: false
                        });

                    if (uploadError) {
                        console.error("Storage Upload Failed:", uploadError);
                        throw uploadError;
                    }

                    // 2. Store RELATIVE PATH (for secure access)
                    finalData = uniquePath;
                    console.log("DEBUG: File stored at path:", finalData);
                } catch (err) {
                    console.error("Critical Storage Error:", err);
                    throw err;
                }
            }

            // Define possible schemas to retry automatically
            const strategies = [
                {
                    name: 'lowercase',
                    map: {
                        name: 'name', fileName: 'filename', fileSize: 'filesize', fileType: 'filetype',
                        category: 'category', analystName: 'analystname', labId: 'labid',
                        status: 'status', data: 'data', uploadDate: 'uploaddate'
                    }
                },
                {
                    name: 'snake_case',
                    map: {
                        name: 'name', fileName: 'file_name', fileSize: 'file_size', fileType: 'file_type',
                        category: 'category', analystName: 'analyst_name', labId: 'lab_id',
                        status: 'status', data: 'data', uploadDate: 'created_at'
                    }
                },
                {
                    name: 'camelCase',
                    map: {
                        name: 'name', fileName: 'fileName', fileSize: 'fileSize', fileType: 'fileType',
                        category: 'category', analystName: 'analystName', labId: 'labId',
                        status: 'status', data: 'data', uploadDate: 'uploadDate'
                    }
                }
            ];

            let lastError;

            for (const strategy of strategies) {
                console.log(`DEBUG: Trying DB insert strategy: ${strategy.name}`);
                try {
                    const payload: any = {};
                    payload[strategy.map.name] = doc.name;
                    payload[strategy.map.fileName] = doc.fileName;
                    payload[strategy.map.fileSize] = doc.fileSize;
                    payload[strategy.map.fileType] = doc.fileType;
                    payload[strategy.map.category] = doc.category;
                    payload[strategy.map.analystName] = doc.analystName;
                    payload[strategy.map.labId] = doc.labId; // Allow null/undefined
                    payload[strategy.map.status] = 'verified';
                    payload[strategy.map.data] = finalData;
                    payload[strategy.map.uploadDate] = new Date().toISOString();

                    Object.keys(payload).forEach(key => payload[key] === undefined && delete payload[key]);

                    const { data, error } = await supabase
                        .from('auditoria_documentos')
                        .insert([payload])
                        .select()
                        .single();

                    if (error) {
                        if (error.code === 'PGRST204' || error.code === '42703' || error.message?.includes('column')) {
                            console.warn(`Strategy ${strategy.name} failed with column error. Retrying...`);
                            lastError = error;
                            continue;
                        }
                        throw error;
                    }

                    console.log(`DEBUG: Strategy ${strategy.name} SUCCEEDED!`);

                    const d = data;
                    return {
                        id: d.id,
                        name: d.name,
                        fileName: d.fileName || d.filename || d.file_name,
                        fileSize: d.fileSize || d.filesize || d.file_size,
                        fileType: d.fileType || d.filetype || d.file_type,
                        uploadDate: d.uploadDate || d.uploaddate || d.upload_date || d.created_at,
                        category: d.category,
                        analystName: d.analystName || d.analystname || d.analyst_name,
                        status: d.status,
                        labId: d.labId || d.labid || d.lab_id,
                        data: d.data
                    };

                } catch (err: any) {
                    lastError = err;
                    if (err.code === 'PGRST204' || err.code === '42703' || err.message?.includes('column')) {
                        continue;
                    }
                    throw err;
                }
            }
            throw lastError;
        }

        const raw = localStorage.getItem(DOCS_KEY);
        const allDocs = raw ? JSON.parse(raw) : [];

        const newDoc: AuditDocument = {
            ...doc,
            id: crypto.randomUUID(),
            uploadDate: new Date().toISOString(),
            status: 'verified'
        };

        allDocs.push(newDoc);
        localStorage.setItem(DOCS_KEY, JSON.stringify(allDocs));
        return newDoc;
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('auditoria_documentos').delete().eq('id', id);
            if (error) throw error;
            return;
        }
        const raw = localStorage.getItem(DOCS_KEY);
        if (!raw) return;
        const docs = JSON.parse(raw);
        const filtered = docs.filter((d: AuditDocument) => d.id !== id);
        localStorage.setItem(DOCS_KEY, JSON.stringify(filtered));
    }
};

import { supabase } from "@/lib/supabase";

export interface Machine {
    id: string;
    machineId: string; // "ID da Máquina" e.g. "HVI 01"
    serialNumber: string; // "Número de Série"
    model: 'USTER' | 'PREMIER';
    labId: string; // Vínculo com Laboratório
    created_at?: string;
}

const STORAGE_KEY = 'fibertech_machines';

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

const getStoredMachines = (): Machine[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        return JSON.parse(data);
    } catch {
        return [];
    }
};

const saveStoredMachines = (machines: Machine[]) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(machines));
};

export const MachineService = {
    async list(): Promise<Machine[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('maquinas').select('*');
            if (error) throw error;

            if (data && data.length > 0) {
                return data.map((m: any) => ({
                    id: m.id,
                    machineId: m.identificacao,
                    serialNumber: m.numero_serie,
                    model: m.modelo,
                    labId: m.lab_id,
                    created_at: m.created_at
                }));
            }

            // CRITICAL SAFETY NET: If Supabase empty, fall back to avoid hiding data
            const localData = getStoredMachines();
            if (localData.length > 0) {
                console.warn("Supabase (Machines) empty. Using LOCAL STORAGE fallback.");
                return localData;
            }

            return []; // Nothing anywhere
        }
        return getStoredMachines();
    },

    async listByLab(labId: string): Promise<Machine[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase
                .from('maquinas')
                .select('*')
                .eq('lab_id', labId);

            if (error) throw error;

            return data.map((m: any) => ({
                id: m.id,
                machineId: m.identificacao,
                serialNumber: m.numero_serie,
                model: m.modelo,
                labId: m.lab_id,
                created_at: m.created_at
            }));
        }
        return getStoredMachines().filter(m => m.labId === labId);
    },

    async create(data: Omit<Machine, 'id' | 'created_at'>): Promise<Machine> {
        if (isSupabaseEnabled()) {
            const dbData = {
                identificacao: data.machineId,
                numero_serie: data.serialNumber,
                modelo: data.model,
                lab_id: data.labId
            };

            const { data: newMachine, error } = await supabase
                .from('maquinas')
                .insert([dbData])
                .select()
                .single();

            if (error) throw error;

            return {
                id: newMachine.id,
                machineId: newMachine.identificacao,
                serialNumber: newMachine.numero_serie,
                model: newMachine.modelo,
                labId: newMachine.lab_id,
                created_at: newMachine.created_at
            };
        }

        const machines = getStoredMachines();
        const newMachine: Machine = {
            ...data,
            id: crypto.randomUUID(),
            created_at: new Date().toISOString()
        };
        machines.push(newMachine);
        saveStoredMachines(machines);
        return newMachine;
    },

    async update(id: string, data: Partial<Machine>): Promise<Machine> {
        if (isSupabaseEnabled()) {
            const dbUpdates: any = {};
            if (data.machineId) dbUpdates.identificacao = data.machineId;
            if (data.serialNumber) dbUpdates.numero_serie = data.serialNumber;
            if (data.model) dbUpdates.modelo = data.model;
            if (data.labId) dbUpdates.lab_id = data.labId;

            const { data: updated, error } = await supabase
                .from('maquinas')
                .update(dbUpdates)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;

            return {
                id: updated.id,
                machineId: updated.identificacao,
                serialNumber: updated.numero_serie,
                model: updated.modelo,
                labId: updated.lab_id,
                created_at: updated.created_at
            };
        }

        const machines = getStoredMachines();
        const index = machines.findIndex(m => m.id === id);
        if (index === -1) throw new Error("Machine not found");

        machines[index] = { ...machines[index], ...data };
        saveStoredMachines(machines);
        return machines[index];
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('maquinas').delete().eq('id', id);
            if (error) throw error;
            return;
        }

        const machines = getStoredMachines();
        const filtered = machines.filter(m => m.id !== id);
        saveStoredMachines(filtered);
    },

    subscribe(callback: () => void): () => void {
        if (!isSupabaseEnabled()) return () => { };

        const channel = supabase
            .channel('maquinas-changes')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'maquinas' },
                () => callback()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }
};

import { supabase } from "@/lib/supabase";

export interface Sample {
    id: string;
    lote_id: string;
    amostra_id: string; // "01", "02", etc.
    hvi?: string; // Número da máquina HVI (ex: "2")
    mic?: number;
    len?: number;
    unf?: number;
    str?: number;
    rd?: number;
    b?: number;
    mala?: string;
    etiqueta?: string;
    data_analise?: string;
    hora_analise?: string;
    cor?: string; // Hex color code
    locked?: boolean;
    historico_modificacoes: Array<{
        timestamp: string;
        usuario: string;
        campo: string;
        valor_anterior: any;
        valor_novo: any;
        tipo_modificacao: 'criacao' | 'edicao' | 'cor_alterada';
    }>;
}

const STORAGE_KEY = 'fibertech_samples';

const isSupabaseEnabled = () => !!import.meta.env.VITE_SUPABASE_URL && !!import.meta.env.VITE_SUPABASE_ANON_KEY;

const getStoredSamples = (): Sample[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return [];
        const parsed = JSON.parse(data);
        return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
        console.error("Error reading samples from storage", error);
        return [];
    }
};

const saveStoredSamples = (samples: Sample[]) => {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(samples));
    } catch (error) {
        console.error("Error saving samples to storage", error);
        throw error;
    }
};

export const SampleService = {
    async list(): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').select('*');
            if (error) throw error;
            if (data && data.length > 0) return data;

            // CRITICAL SAFETY NET
            const local = getStoredSamples();
            if (local.length > 0) {
                console.warn("Supabase (Samples) empty. Using Local Storage Fallback.");
                return local;
            }
            return [];
        }
        return getStoredSamples();
    },

    async listByLote(loteId: string): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').select('*').eq('lote_id', loteId).order('amostra_id');
            if (error) throw error;
            return data || [];
        }
        return getStoredSamples()
            .filter(s => s.lote_id === loteId)
            .sort((a, b) => a.amostra_id.localeCompare(b.amostra_id));
    },

    async create(data: Omit<Sample, 'id'>): Promise<Sample> {
        if (isSupabaseEnabled()) {
            const { data: newSample, error } = await supabase.from('amostras').insert([data]).select().single();
            if (error) throw error;
            return newSample;
        }

        const samples = getStoredSamples();
        const newSample: Sample = {
            ...data,
            id: Math.random().toString(36).substr(2, 9),
        };
        samples.push(newSample);
        saveStoredSamples(samples);
        return newSample;
    },

    async bulkCreate(dataList: Omit<Sample, 'id'>[]): Promise<Sample[]> {
        if (isSupabaseEnabled()) {
            const { data, error } = await supabase.from('amostras').insert(dataList).select();
            if (error) throw error;
            return data;
        }

        const samples = getStoredSamples();
        const newSamples = dataList.map(data => ({
            ...data,
            id: Math.random().toString(36).substr(2, 9),
        }));
        samples.push(...newSamples);
        saveStoredSamples(samples);
        return newSamples;
    },

    async update(id: string, data: Partial<Sample>): Promise<Sample> {
        if (isSupabaseEnabled()) {
            const { data: updated, error } = await supabase.from('amostras').update(data).eq('id', id).select().single();
            if (error) throw error;
            return updated;
        }

        const samples = getStoredSamples();
        const index = samples.findIndex(s => s.id === id);
        if (index === -1) throw new Error("Sample not found");

        samples[index] = { ...samples[index], ...data };
        saveStoredSamples(samples);
        return samples[index];
    },

    async bulkUpdate(updates: Record<string, Partial<Sample>>): Promise<void> {
        if (isSupabaseEnabled()) {
            // Supabase doesn't have a direct "bulk update different rows with different data" in one call easily like this
            // But we can use an RPC or multiple calls. For simplicity here, we'll do promise.all
            const promises = Object.entries(updates).map(([id, data]) =>
                supabase.from('amostras').update(data).eq('id', id)
            );
            await Promise.all(promises);
            return;
        }

        const samples = getStoredSamples();
        let changed = false;
        Object.entries(updates).forEach(([id, data]) => {
            const index = samples.findIndex(s => s.id === id);
            if (index !== -1) {
                samples[index] = { ...samples[index], ...data };
                changed = true;
            }
        });
        if (changed) saveStoredSamples(samples);
    },

    async delete(id: string): Promise<void> {
        if (isSupabaseEnabled()) {
            const { error } = await supabase.from('amostras').delete().eq('id', id);
            if (error) throw error;
            return;
        }

        const samples = getStoredSamples();
        const filtered = samples.filter(s => s.id !== id);
        saveStoredSamples(filtered);
    },

    subscribe(callback: () => void): () => void {
        if (!isSupabaseEnabled()) return () => { };

        const channel = supabase
            .channel(`amostras-changes-${Math.random().toString(36).substr(2, 9)}`)
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'amostras' },
                () => callback()
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }
};

import * as XLSX from 'xlsx';

export interface ProducaoParsed {
    lab_id: string;
    identificador_unico: string;
    data_producao: string;
    turno: string;
    produto: string;
    peso: number;
    metadata: any;
}

const parseDate = (cell: any): string | null => {
    if (!cell) return null;
    if (typeof cell === 'number' && cell > 40000) {
        const date = XLSX.SSF.parse_date_code(cell);
        return `${date.y}-${String(date.m).padStart(2, '0')}-${String(date.d).padStart(2, '0')}`;
    }
    if (typeof cell === 'string') {
        const match = cell.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
        if (match) return `${match[3]}-${match[2].padStart(2, '0')}-${match[1].padStart(2, '0')}`;
    }
    return null;
};

export const parseProducaoFileInChunks = async (
    file: File,
    labId: string,
    onBatch: (batch: ProducaoParsed[]) => Promise<void>,
    batchSize: number = 2000
): Promise<number> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();

        reader.onload = async (e) => {
            try {
                const data = e.target?.result;
                const workbook = XLSX.read(data, { type: 'binary', dense: true });
                const sheetName = workbook.SheetNames[0];
                const worksheet = workbook.Sheets[sheetName];

                const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: "" });

                // 1. Detect Header Row for Machine Mapping
                let machineMap: Record<number, number> = {};
                let headerRowIndex = -1;

                for (let i = 0; i < Math.min(rows.length, 50); i++) {
                    const row = rows[i];
                    let foundNumbers = 0;
                    let tempMap: Record<number, number> = {};

                    row.forEach((cell, colIdx) => {
                        const val = parseInt(String(cell));
                        if (!isNaN(val) && val > 0 && val < 1000) {
                            tempMap[colIdx] = val;
                            foundNumbers++;
                        }
                    });

                    if (foundNumbers > 5) {
                        machineMap = tempMap;
                        headerRowIndex = i;
                        break;
                    }
                }

                if (headerRowIndex === -1) {
                    throw new Error("Não foi possível detectar o cabeçalho das máquinas (1, 2, 3...) nas primeiras 50 linhas.");
                }

                console.log(`Detected machines at row ${headerRowIndex}:`, machineMap);

                let currentBlockDate: string | null = null;
                let currentTurnoLabel: string = "";
                let currentBatch: ProducaoParsed[] = [];
                let totalProcessed = 0;
                let rowsWithData = 0;

                for (let i = 0; i < rows.length; i++) {
                    if (i === headerRowIndex) continue;

                    const row = rows[i];
                    if (!row || row.length === 0) {
                        // Reset turno on empty row to avoid importing trailing summary/total rows
                        currentTurnoLabel = "";
                        continue;
                    }

                    // Check for valid content in row (not just nulls/empty strings)
                    const hasContent = row.some(cell => cell !== null && cell !== "" && cell !== undefined);
                    if (!hasContent) {
                        currentTurnoLabel = "";
                        continue;
                    }

                    // 1. Check for date in columns 0 or 1
                    const potentialDate = parseDate(row[0]) || parseDate(row[1]);
                    if (potentialDate) {
                        currentBlockDate = potentialDate;
                        // Important: if this is JUST a date row (no turno or data yet), 
                        // we might reset turno or wait for the next row to tell us.
                    }

                    // 2. Check for turno label in columns 0 or 1
                    const firstCell = String(row[0] || "").toUpperCase().trim();
                    const secondCell = String(row[1] || "").toUpperCase().trim();

                    if (firstCell.includes("TURNO")) currentTurnoLabel = firstCell;
                    else if (secondCell.includes("TURNO")) currentTurnoLabel = secondCell;

                    // 3. If we have date + turno, process data columns
                    if (currentBlockDate && currentTurnoLabel) {
                        let foundInRow = 0;

                        // Iterate through ALL columns that might have data
                        // We use the machineMap as reference indices
                        const machineIndices = Object.keys(machineMap).map(Number);

                        // We also check columns immediately to the LEFT of machine labels (offset handling)
                        const colsToCheck = new Set<number>();
                        machineIndices.forEach(idx => {
                            colsToCheck.add(idx);
                            if (idx > 0) colsToCheck.add(idx - 1);
                        });

                        const sortedCols = Array.from(colsToCheck).sort((a, b) => a - b);

                        for (const colIdx of sortedCols) {
                            const cell = row[colIdx];
                            if (cell === null || cell === "" || cell === undefined) continue;

                            let val = NaN;
                            if (typeof cell === 'number') val = cell;
                            else if (typeof cell === 'string' && cell.trim() !== "") {
                                const clean = cell.replace(/\./g, "").replace(",", ".");
                                // Verify it's not a date string mistakenly being parsed as value
                                if (!clean.includes("/") && !isNaN(parseFloat(clean))) {
                                    val = parseFloat(clean);
                                }
                            }

                            if (isNaN(val) || val < 0) continue;

                            // Find which machine this column belongs to
                            // Rule: Exact match first, then offset +1
                            let machineNumber: number | undefined = machineMap[colIdx];
                            if (machineNumber === undefined && machineMap[colIdx + 1] !== undefined) {
                                machineNumber = machineMap[colIdx + 1];
                            }

                            if (machineNumber !== undefined) {
                                currentBatch.push({
                                    lab_id: labId,
                                    identificador_unico: `${currentBlockDate}-${currentTurnoLabel.replace(/[^A-Z0-9]/g, "")}-MQ${machineNumber}`,
                                    data_producao: currentBlockDate,
                                    turno: currentTurnoLabel.replace(":", "").trim(),
                                    produto: `Linha/Mq ${machineNumber}`,
                                    peso: val,
                                    metadata: { source: 'excel_upload_streaming_robust' }
                                });
                                foundInRow++;
                            }
                        }

                        if (foundInRow > 0) {
                            rowsWithData++;
                        }

                        if (currentBatch.length >= batchSize) {
                            await onBatch(currentBatch);
                            totalProcessed += currentBatch.length;
                            currentBatch = [];
                        }
                    }
                }

                console.log(`Finished parsing. Total rows with data: ${rowsWithData}, Total records: ${totalProcessed + currentBatch.length}`);

                if (currentBatch.length > 0) {
                    await onBatch(currentBatch);
                    totalProcessed += currentBatch.length;
                }

                resolve(totalProcessed);
            } catch (error) {
                reject(error);
            }
        };

        reader.onerror = reject;
        reader.readAsBinaryString(file);
    });
};

