import { useState, useEffect } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { Download, ArrowLeft, Settings2, FileStack, Terminal, ChevronDown, Zap } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import type { Sample } from "@/entities/Sample";
import type { Lote } from "@/entities/Lote";
import { SampleService } from "@/entities/Sample";
import { LoteService } from "@/entities/Lote";
import ExportPreview from "@/components/export/ExportPreview";

export default function Export() {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const loteId = searchParams.get("loteId");

    const [lote, setLote] = useState<Lote | null>(null);
    const [samples, setSamples] = useState<Sample[]>([]);

    const [mode, setMode] = useState<"all" | "by_color">("all");
    const [separator, setSeparator] = useState<string>("tab");
    const hasHeader = true;
    const [decimalSeparator, setDecimalSeparator] = useState<"." | ",">(".");
    const [selectedColor, setSelectedColor] = useState<string>("#ef4444");

    useEffect(() => {
        if (loteId) {
            loadData();
        }
    }, [loteId]);

    const loadData = async () => {
        if (!loteId) return;
        const l = await LoteService.get(loteId);
        if (l) setLote(l);
        const s = await SampleService.listByLote(loteId);
        setSamples(s);
    };

    const handleDownload = () => {
        let filtered = samples;
        if (mode === "by_color" && selectedColor) {
            filtered = samples.filter(s => s.cor === selectedColor);
        }

        const headers = ["ID", "MIC", "LEN", "UNF", "STR", "RD", "+b"];
        const sep = separator === "tab" ? "\t" : separator;

        let content = "";
        if (hasHeader) {
            content += headers.join(sep) + "\n";
        }

        filtered.forEach(s => {
            const row = [
                s.amostra_id,
                s.mic?.toFixed(2),
                s.len?.toFixed(2),
                s.unf?.toFixed(1),
                s.str?.toFixed(1),
                s.rd?.toFixed(1),
                s.b?.toFixed(1)
            ].map(val => {
                if (val === undefined || val === null) return "";
                let str = val.toString();
                if (decimalSeparator === ",") str = str.replace(".", ",");
                return str;
            });
            content += row.join(sep) + "\n";
        });

        const blob = new Blob([content], { type: "text/plain;charset=utf-8" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        const timestamp = new Date().toISOString().split('T')[0];
        link.download = `HVI_${lote?.nome || "Export"}_${mode}_${timestamp}.txt`;
        link.click();
        URL.revokeObjectURL(url);
    };

    if (!loteId) return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-fade-in">
            <div className="bg-white p-16 rounded-[2.5rem] text-center space-y-8 max-w-xl border border-slate-200 shadow-xl">
                <div className="bg-slate-50 w-20 h-20 rounded-[1.5rem] border border-slate-100 flex items-center justify-center mx-auto shadow-sm">
                    <FileStack className="h-10 w-10 text-slate-300" />
                </div>
                <div className="space-y-4">
                    <h3 className="text-xl font-black text-slate-900 italic uppercase tracking-widest leading-none">Lote Indefinido</h3>
                    <p className="text-[10px] font-black text-slate-400 max-w-xs mx-auto uppercase tracking-widest leading-relaxed pt-2">É necessário uma sessão ativa de lote para iniciar o protocolo.</p>
                </div>
                <Button onClick={() => navigate("/")} className="h-14 px-12 bg-slate-950 text-white font-black text-[10px] uppercase tracking-[0.4em] transition-all hover:scale-105 rounded-xl shadow-lg">RETORNAR</Button>
            </div>
        </div>
    );

    return (
        <div className="max-w-7xl mx-auto space-y-12 animate-fade-in relative pb-10 text-slate-900">
            {/* Header - Compact */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 border-b border-slate-200 pb-10">
                <div className="space-y-4">
                    <div className="flex items-center gap-4">
                        <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => navigate(-1)}
                            className="rounded-xl bg-white hover:bg-slate-50 text-slate-400 h-10 w-10 border border-slate-200 shadow-sm"
                        >
                            <ArrowLeft className="h-4 w-4" />
                        </Button>
                        <h1 className="text-3xl lg:text-4xl font-black text-slate-900 italic uppercase tracking-tighter leading-none shadow-sm">Exportação de Dados</h1>
                        <div className="px-3 py-1 bg-slate-100 rounded-lg border border-slate-200 text-[9px] font-black text-slate-500 uppercase tracking-widest italic">
                            industrial_txt_v2
                        </div>
                    </div>
                    <div className="flex items-center gap-10 text-[10px] font-bold uppercase tracking-[0.4em] text-slate-400 italic leading-none pt-2">
                        <span className="flex items-center gap-2">
                            <Terminal className="h-3.5 w-3.5 text-blue-500" />
                            Node: <span className="text-blue-600 font-bold">{lote?.nome}</span>
                        </span>
                        <span className="flex items-center gap-2">
                            <Zap className="h-3.5 w-3.5 text-emerald-500 shadow-sm" />
                            Status: Validado
                        </span>
                    </div>
                </div>
            </div>

            <div className="grid gap-10 lg:grid-cols-12 animate-slide-up">
                <div className="lg:col-span-12 xl:col-span-4 space-y-8">
                    <div className="bg-white rounded-[2rem] border border-slate-200 overflow-hidden shadow-2xl shadow-slate-200/50">
                        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
                            <h3 className="text-[10px] font-black text-slate-900 italic uppercase tracking-[0.3em] flex items-center gap-3">
                                <Settings2 className="h-4 w-4 text-slate-400" />
                                Configurações de Saída
                            </h3>
                        </div>
                        <div className="p-10 space-y-10">
                            <div className="space-y-4">
                                <Label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] ml-1">Escopo</Label>
                                <div className="grid grid-cols-2 gap-2 p-1.5 bg-slate-50 rounded-xl border border-slate-100 shadow-inner">
                                    <button
                                        onClick={() => setMode("all")}
                                        className={`py-3 rounded-lg text-[9px] font-black transition-all tracking-widest uppercase ${mode === "all" ? "bg-white text-slate-900 shadow-sm border border-slate-200" : "text-slate-400 hover:text-slate-600"}`}
                                    >
                                        TODOS
                                    </button>
                                    <button
                                        onClick={() => setMode("by_color")}
                                        className={`py-3 rounded-lg text-[9px] font-black transition-all tracking-widest uppercase ${mode === "by_color" ? "bg-white text-slate-900 shadow-sm border border-slate-200" : "text-slate-400 hover:text-slate-600"}`}
                                    >
                                        POR_TAG
                                    </button>
                                </div>
                            </div>

                            {mode === "by_color" && (
                                <div className="space-y-4 animate-slide-up">
                                    <Label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] ml-1 italic">Selecionar Tag</Label>
                                    <div className="flex gap-3 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
                                        {["#ef4444", "#f59e0b", "#10b981", "#3b82f6"].map(c => (
                                            <button
                                                key={c}
                                                onClick={() => setSelectedColor(c)}
                                                className={`w-9 h-9 rounded-xl border-2 transition-all ${selectedColor === c ? 'border-slate-900 scale-110 shadow-lg' : 'border-transparent opacity-20 hover:opacity-100'}`}
                                                style={{ backgroundColor: c }}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="grid grid-cols-2 gap-6">
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] ml-1">Delim</Label>
                                    <div className="relative">
                                        <select
                                            className="w-full h-12 rounded-xl border border-slate-200 bg-white px-5 text-[10px] font-black text-slate-900 italic tracking-widest focus:ring-1 focus:ring-blue-500/10 outline-none appearance-none transition-all shadow-sm"
                                            value={separator}
                                            onChange={(e) => setSeparator(e.target.value)}
                                        >
                                            <option value="tab">TABULAÇÃO</option>
                                            <option value=";">PONTO_VÍRGULA</option>
                                            <option value=",">VÍRGULA</option>
                                            <option value="|">PIPE_LINE</option>
                                        </select>
                                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-300 pointer-events-none" />
                                    </div>
                                </div>
                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black uppercase text-slate-400 tracking-[0.2em] ml-1">Ponto</Label>
                                    <div className="relative">
                                        <select
                                            className="w-full h-12 rounded-xl border border-slate-200 bg-white px-5 text-[10px] font-black text-slate-900 italic tracking-widest focus:ring-1 focus:ring-blue-500/10 outline-none appearance-none transition-all shadow-sm"
                                            value={decimalSeparator}
                                            onChange={(e) => setDecimalSeparator(e.target.value as "." | ",")}
                                        >
                                            <option value=".">DOTPT (.)</option>
                                            <option value=",">VIRGPT (,)</option>
                                        </select>
                                        <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-slate-300 pointer-events-none" />
                                    </div>
                                </div>
                            </div>

                            <Button
                                className="w-full h-18 rounded-2xl bg-slate-950 text-white hover:bg-black shadow-[0_0_40px_rgba(0,0,0,0.1)] font-black text-[10px] uppercase tracking-[0.4em] transition-all hover:scale-[1.02] mt-4"
                                onClick={handleDownload}
                            >
                                <Download className="mr-3 h-5 w-5" /> EXECUTAR DUMP
                            </Button>
                        </div>
                    </div>
                </div>

                <div className="lg:col-span-12 xl:col-span-8 bg-white rounded-[2.5rem] overflow-hidden flex flex-col shadow-2xl shadow-slate-200/50 border border-slate-200 min-h-[600px]">
                    <div className="p-10 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                        <div className="space-y-1">
                            <h3 className="text-[11px] font-black text-slate-900 italic uppercase tracking-[0.4em] leading-none">Pré-visualização do Buffer</h3>
                            <p className="text-[9px] text-slate-400 uppercase font-black tracking-widest pt-1 italic opacity-60">Validação da sequência industrial de saída</p>
                        </div>
                    </div>
                    <div className="flex-1 bg-slate-50/10 overflow-auto">
                        <ExportPreview
                            samples={samples}
                            separator={separator}
                            hasHeader={hasHeader}
                            decimalSeparator={decimalSeparator}
                            mode={mode}
                            selectedColor={selectedColor}
                        />
                    </div>
                    <div className="p-10 border-t border-slate-100 bg-white flex flex-col items-center justify-center text-center space-y-3">
                        <p className="text-[9px] text-slate-300 font-bold uppercase tracking-widest italic leading-relaxed opacity-60">O conteúdo acima reflete o arquivo final salvo localmente pelo sistema.</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import {
    Plus as PlusIcon,
    Search as SearchIcon,
    Trash2 as Trash2Icon,
    PencilLine as PencilLineIcon,
    Lock as LockIcon,
    LockOpen as LockOpenIcon,
    ArrowRight
} from "lucide-react";
import { useNavigate } from "react-router-dom";
// import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { type Lote, LoteService } from "@/entities/Lote";
import { SampleService } from "@/entities/Sample";
import { type Lab, LabService } from "@/entities/Lab";
import { useToast } from "@/contexts/ToastContext";
import { useAuth } from "@/contexts/AuthContext";
import { useLanguage } from "@/contexts/LanguageContext";
import { Modal } from "@/components/shared/Modal";
import { AnalistaService } from "@/entities/Analista";

export default function Home() {
    const [lotes, setLotes] = useState<Lote[]>([]);
    const [sampleCounts, setSampleCounts] = useState<Record<string, number>>({});
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    const [isByLoteModalOpen, setIsByLoteModalOpen] = useState(false);
    const [newLoteName, setNewLoteName] = useState("");
    const [newLoteCidade, setNewLoteCidade] = useState("");
    const [isCreating, setIsCreating] = useState(false);

    // Edit/Delete states
    const [loteToEdit, setLoteToEdit] = useState<Lote | null>(null);
    const [editName, setEditName] = useState("");
    const [editCidade, setEditCidade] = useState("");
    const [loteToDelete, setLoteToDelete] = useState<Lote | null>(null);

    const navigate = useNavigate();

    const { addToast } = useToast();
    const { user, currentLab } = useAuth();
    const { t } = useLanguage();

    useEffect(() => {
        loadLotes();

        // Subscribe to real-time changes
        const unsubLotes = LoteService.subscribe(() => {
            loadLotes();
        });
        const unsubSamples = SampleService.subscribe(() => {
            loadLotes();
        });

        return () => {
            unsubLotes();
            unsubSamples();
        };
    }, [user, currentLab]);

    // Auto-fill city from user's lab or selected lab
    useEffect(() => {
        const fetchLabCity = async () => {
            const targetLabId = currentLab?.id || user?.lab_id;

            if (targetLabId) {
                try {
                    const lab = await LabService.get(targetLabId);
                    if (lab && lab.cidade) {
                        const cityState = lab.estado ? `${lab.cidade}/${lab.estado}` : lab.cidade;
                        setNewLoteCidade(cityState);
                    } else {
                        const lastCity = localStorage.getItem("last_lote_city");
                        if (lastCity) setNewLoteCidade(lastCity);
                    }
                } catch (error) {
                    console.error("Failed to fetch lab details", error);
                    // Fallback on error too
                    const lastCity = localStorage.getItem("last_lote_city");
                    if (lastCity) setNewLoteCidade(lastCity);
                }
            } else {
                // Fallback if no lab text
                const lastCity = localStorage.getItem("last_lote_city");
                if (lastCity) setNewLoteCidade(lastCity);
            }
        };
        fetchLabCity();
    }, [user, currentLab, isByLoteModalOpen]);

    const [labs, setLabs] = useState<Lab[]>([]);

    useEffect(() => {
        // Load labs for name resolution
        LabService.list().then(setLabs).catch(console.error);
    }, []);

    const [activeAnalysts, setActiveAnalysts] = useState<any[]>([]);

    useEffect(() => {
        const loadAnalysts = async () => {
            const data = await AnalistaService.list();
            const now = new Date().getTime();
            const active = data.filter(a =>
                a.last_active && (now - new Date(a.last_active).getTime() < 15000)
            );
            setActiveAnalysts(active);
        };

        loadAnalysts();
        const interval = setInterval(loadAnalysts, 3000);
        return () => clearInterval(interval);
    }, []);

    const loadLotes = async () => {
        setIsLoading(true);
        try {
            let data = await LoteService.list();

            // Filter logic (CORRECTED):
            // 1. If currentLab is selected → Show ONLY batches from that lab
            // 2. If NO currentLab AND admin_global → Show ALL batches
            // 3. If admin_lab → Always show only their assigned lab

            if (currentLab) {
                // Lab context is selected → filter by that lab
                data = data.filter(l => l.lab_id === currentLab.id);
            } else if (user?.acesso === 'admin_lab' && user.lab_id) {
                // Lab admin without selection → their assigned lab only
                data = data.filter(l => l.lab_id === user.lab_id);
            }
            // If admin_global with NO currentLab → show ALL (no filter)

            setLotes(data);

            const counts: Record<string, number> = {};
            for (const lote of data) {
                const samples = await SampleService.listByLote(lote.id);
                counts[lote.id] = samples.length;
            }
            setSampleCounts(counts);
        } catch (error) {
            console.error(error);
        } finally {
            setIsLoading(false);
        }
    };

    // ... [existing getLabName] ...

    // Helper to get initials
    const getInitials = (name: string) => {
        if (!name) return "??";
        return name.split(" ").map(n => n[0]).join("").substring(0, 2).toUpperCase();
    };

    const getLabName = (labId?: string) => {
        if (!labId) return "N/A";
        const lab = labs.find(l => l.id === labId);
        return lab ? `${lab.nome} - ${lab.cidade}` : "Unknown Lab";
    };

    const handleCreateLote = async () => {
        if (!newLoteName.trim() || !user) return;

        const targetLabId = currentLab?.id || user.lab_id;
        if (!targetLabId && user.acesso !== 'admin_global') {
            addToast({ title: "Error: No Lab Context", type: "error" });
            return;
        }

        setIsCreating(true);
        try {
            const newLote = await LoteService.create({
                nome: newLoteName,
                cidade: newLoteCidade,
                analista_responsavel: user.nome,
                lab_id: targetLabId, // Bind Lote to current context
                status: 'aberto'
            });
            addToast({
                title: "Created",
                description: `Batch ${newLoteName} initialized.`,
                type: "success"
            });
            setNewLoteName("");
            localStorage.setItem("last_lote_city", newLoteCidade);
            setNewLoteName("");
            // Keep city for next time or rely on useEffect to reload it
            // setNewLoteCidade(""); // Don't clear it, or rely on useEffect. 
            // Better to clear and let useEffect/init restore it on next open.
            setNewLoteCidade("");
            setIsByLoteModalOpen(false);
            navigate(`/registro?loteId=${newLote.id}`);
        } catch (error) {
            addToast({ title: "Creation Error", type: "error" });
        } finally {
            setIsCreating(false);
        }
    };

    const handleUpdateLote = async () => {
        if (!loteToEdit || !editName.trim()) return;
        try {
            await LoteService.update(loteToEdit.id, { nome: editName, cidade: editCidade });
            addToast({ title: "Updated", type: "success" });
            setLoteToEdit(null);
            loadLotes();
        } catch (error) {
            addToast({ title: "Update Error", type: "error" });
        }
    };

    const handleToggleStatus = async (lote: Lote) => {
        try {
            const newStatus = lote.status === 'aberto' ? 'finalizado' : 'aberto';
            await LoteService.update(lote.id, { status: newStatus });
            addToast({
                title: "Status Updated",
                description: `Batch ${lote.nome} is now ${newStatus === 'aberto' ? 'Open' : 'Locked'}.`,
                type: "success"
            });
            loadLotes();
        } catch (error) {
            addToast({ title: "Status Update Error", type: "error" });
        }
    };

    const handleDeleteLote = async () => {
        if (!loteToDelete) return;
        try {
            await LoteService.delete(loteToDelete.id);
            addToast({
                title: "Items Removed",
                type: "info"
            });
            setLoteToDelete(null);
            loadLotes();
        } catch (error) {
            addToast({ title: "Delete Error", type: "error" });
        }
    };

    const filteredLotes = lotes.filter(l =>
        l.nome.toLowerCase().includes(searchTerm.toLowerCase())
    ).sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());

    return (
        <div className="space-y-16 animate-fade-in text-black pb-24">

            {/* Header Section */}
            <div className="flex flex-col md:flex-row items-end justify-between border-b border-black pb-8 gap-8">
                <div className="space-y-2">
                    <span className="text-[10px] uppercase tracking-[0.25em] text-neutral-500 font-mono">{t('home.subtitle')}</span>
                    <h1 className="text-4xl lg:text-5xl font-serif text-black leading-none">
                        {t('home.title')}
                    </h1>
                </div>

                <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
                    <div className="relative w-full md:w-80">
                        <SearchIcon className="absolute left-0 top-1/2 -translate-y-1/2 h-4 w-4 text-neutral-400" />
                        <Input
                            placeholder={t('home.search_placeholder')}
                            className="h-12 pl-8 border-b border-neutral-300 rounded-none bg-transparent focus:border-black focus:ring-0 text-xs font-mono placeholder:text-neutral-300 px-0"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Button
                        onClick={() => setIsByLoteModalOpen(true)}
                        className="h-12 px-8 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] uppercase tracking-[0.2em] font-bold"
                    >
                        <PlusIcon className="mr-2 h-4 w-4" />
                        {t('home.init_batch')}
                    </Button>
                </div>
            </div>

            {/* Grid */}
            <div>
                {isLoading ? (
                    <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
                        {[1, 2, 3].map(i => <div key={i} className="h-64 border border-neutral-100 bg-neutral-50 animate-pulse" />)}
                    </div>
                ) : filteredLotes.length === 0 ? (
                    <div className="py-24 text-center border border-dashed border-neutral-300">
                        <p className="text-neutral-400 font-mono uppercase tracking-widest text-xs">{t('home.no_batches')}</p>
                    </div>
                ) : (
                    <div className="grid gap-x-8 gap-y-12 md:grid-cols-2 lg:grid-cols-3">
                        {filteredLotes.map((lote) => (
                            <div key={lote.id} className="group flex flex-col justify-between border border-neutral-200 hover:border-black transition-colors duration-300 min-h-[320px] bg-white relative z-10">
                                <div className="p-8 space-y-8">
                                    <div className="flex justify-between items-start">
                                        <div className="space-y-2">
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${lote.status === 'aberto' ? 'bg-emerald-500' : 'bg-red-500'}`}></span>
                                                <span className={`text-[10px] uppercase tracking-widest font-mono ${lote.status === 'aberto' ? 'text-emerald-600' : 'text-red-500'}`}>
                                                    {lote.status === 'aberto' ? t('home.active') : t('home.locked')}
                                                </span>

                                                {/* Active Users Indicator */}
                                                {activeAnalysts.filter(a => a.current_lote_id === lote.id && a.id !== user?.id).length > 0 && (
                                                    <div className="flex -space-x-2 ml-2">
                                                        {activeAnalysts.filter(a => a.current_lote_id === lote.id && a.id !== user?.id).map((analyst, idx) => (
                                                            <div key={idx} className="w-6 h-6 rounded-full border border-white bg-neutral-200 flex items-center justify-center text-[8px] font-bold overflow-hidden relative z-10" title={`${analyst.nome} is editing`}>
                                                                {analyst.foto ? (
                                                                    <img src={analyst.foto} className="w-full h-full object-cover" />
                                                                ) : (
                                                                    getInitials(analyst.nome)
                                                                )}
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                            <h3 className="text-xl font-serif text-black leading-tight">
                                                {lote.nome}
                                            </h3>
                                        </div>

                                        <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button
                                                onClick={(e) => { e.stopPropagation(); handleToggleStatus(lote); }}
                                                className="p-2 hover:bg-neutral-100 transition-colors"
                                                title={lote.status === 'aberto' ? t('home.lock_batch') : t('home.unlock_batch')}
                                            >
                                                {lote.status === 'aberto' ? (
                                                    <LockIcon className="h-4 w-4 text-neutral-400 hover:text-black" />
                                                ) : (
                                                    <LockOpenIcon className="h-4 w-4 text-red-500 hover:text-red-700" />
                                                )}
                                            </button>
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    setLoteToEdit(lote);
                                                    setEditName(lote.nome);
                                                    setEditCidade(lote.cidade || "");
                                                }}
                                                className="p-2 hover:bg-neutral-100 transition-colors"
                                                title={t('home.rename_batch')}
                                            >
                                                <PencilLineIcon className="h-4 w-4 text-black" />
                                            </button>
                                            <button
                                                onClick={(e) => { e.stopPropagation(); setLoteToDelete(lote); }}
                                                className="p-2 hover:bg-neutral-100 transition-colors"
                                                title={t('home.destroy_batch')}
                                            >
                                                <Trash2Icon className="h-4 w-4 text-black" />
                                            </button>
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-2 gap-8 border-t border-neutral-100 pt-6">
                                        <div>
                                            <span className="text-[9px] uppercase tracking-widest text-neutral-400 block mb-1">{t('home.created')}</span>
                                            <span className="font-mono text-xs">{new Date(lote.created_at).toLocaleDateString()}</span>
                                        </div>
                                        <div>
                                            <span className="text-[9px] uppercase tracking-widest text-neutral-400 block mb-1">{t('home.analyst')}</span>
                                            <span className="font-mono text-xs flex items-center gap-1">
                                                {lote.analista_responsavel}
                                            </span>
                                        </div>
                                        <div>
                                            <span className="text-[9px] uppercase tracking-widest text-neutral-400 block mb-1">{t('home.origin')}</span>
                                            <span className="font-mono text-xs uppercase text-neutral-600 truncate block">
                                                {lote.cidade || "N/A"}
                                            </span>
                                        </div>
                                        <div>
                                            <span className="text-[9px] uppercase tracking-widest text-neutral-400 block mb-1">{t('home.unit')}</span>
                                            <span className="font-mono text-xs uppercase text-black font-bold truncate block" title={getLabName(lote.lab_id)}>
                                                {getLabName(lote.lab_id).split(' - ')[0]}
                                            </span>
                                        </div>
                                    </div>

                                    <div>
                                        <span className="text-[9px] uppercase tracking-widest text-neutral-400 block mb-2">{t('home.data_points')}</span>
                                        <div className="text-3xl font-mono">
                                            {(sampleCounts[lote.id] || 0).toString().padStart(2, '0')}
                                        </div>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 border-t border-neutral-200 divide-x divide-neutral-200">
                                    <button
                                        onClick={() => navigate(`/registro?loteId=${lote.id}`)}
                                        className="h-12 flex items-center justify-center gap-2 hover:bg-black hover:text-white transition-colors text-[10px] uppercase tracking-widest font-bold"
                                    >
                                        {t('home.digitize')}
                                    </button>
                                    <button
                                        onClick={() => navigate(`/analysis?loteId=${lote.id}`)}
                                        className="h-12 flex items-center justify-center gap-2 hover:bg-black hover:text-white transition-colors text-[10px] uppercase tracking-widest font-bold"
                                    >
                                        {t('home.analyze')}
                                        <ArrowRight className="h-3 w-3" />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <Modal
                isOpen={isByLoteModalOpen}
                onClose={() => setIsByLoteModalOpen(false)}
                title={t('home.initialize_batch_title')}
                description={t('home.enter_params')}
            >
                <div className="space-y-8 pt-4">
                    <div className="space-y-4">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-neutral-500">{t('home.batch_identifier')}</label>
                        <Input
                            autoFocus
                            placeholder="e.g. YEAR-2025-A"
                            value={newLoteName}
                            onChange={(e) => setNewLoteName(e.target.value)}
                            className="h-12 border-b border-black rounded-none text-xl font-mono text-black placeholder:text-neutral-200 px-0 bg-transparent focus:ring-0 border-t-0 border-x-0"
                        />
                    </div>
                    <div className="space-y-4">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-neutral-500">{t('home.origin_city')}</label>
                        <Input
                            placeholder="e.g. Primavera do Leste/MT"
                            value={newLoteCidade}
                            onChange={(e) => setNewLoteCidade(e.target.value)}
                            className="h-12 border-b border-black rounded-none text-sm font-mono text-black placeholder:text-neutral-200 px-0 bg-transparent focus:ring-0 border-t-0 border-x-0"
                        />
                    </div>
                    <Button
                        onClick={handleCreateLote}
                        disabled={!newLoteName.trim() || isCreating}
                        className="w-full h-14 rounded-none bg-black text-white hover:bg-neutral-800 font-bold uppercase text-[11px] tracking-[0.3em]"
                    >
                        {isCreating ? t('home.initializing') : t('home.confirm_initialization')}
                    </Button>
                </div>
            </Modal>

            {/* Edit Modal */}
            <Modal
                isOpen={!!loteToEdit}
                onClose={() => setLoteToEdit(null)}
                title={t('home.rename_batch')}
            >
                <div className="space-y-6 pt-4">
                    <div className="space-y-4">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-neutral-500">{t('home.new_identifier')}</label>
                        <Input
                            autoFocus
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            className="h-12 border-b border-black rounded-none text-xl font-mono text-black placeholder:text-neutral-200 px-0 bg-transparent focus:ring-0 border-t-0 border-x-0"
                        />
                    </div>
                    <div className="space-y-4">
                        <label className="text-[10px] font-bold uppercase tracking-widest text-neutral-500">{t('home.origin_city')}</label>
                        <Input
                            value={editCidade}
                            onChange={(e) => setEditCidade(e.target.value)}
                            className="h-12 border-b border-black rounded-none text-sm font-mono text-black placeholder:text-neutral-200 px-0 bg-transparent focus:ring-0 border-t-0 border-x-0"
                        />
                    </div>
                    <Button
                        onClick={handleUpdateLote}
                        disabled={!editName.trim()}
                        className="w-full h-14 rounded-none bg-black text-white hover:bg-neutral-800 font-bold uppercase text-[11px] tracking-[0.3em]"
                    >
                        {t('home.save_changes')}
                    </Button>
                </div>
            </Modal>

            {/* Delete Modal */}
            <Modal
                isOpen={!!loteToDelete}
                onClose={() => setLoteToDelete(null)}
                title={t('home.destroy_batch')}
            >
                <div className="space-y-8 pt-4 text-center">
                    <p className="text-sm text-neutral-600">
                        {t('home.permanently_delete')} <span className="font-bold text-black border-b border-black">{loteToDelete?.nome}</span>?
                        <br /><span className="text-[10px] uppercase text-red-600 font-bold mt-2 block">{t('home.data_loss_warning')}</span>
                    </p>
                    <div className="grid grid-cols-2 gap-4">
                        <Button
                            onClick={() => setLoteToDelete(null)}
                            variant="ghost"
                            className="h-12 font-bold uppercase text-[10px] tracking-widest"
                        >
                            {t('common.cancel')}
                        </Button>
                        <Button
                            onClick={handleDeleteLote}
                            className="h-12 rounded-none bg-red-600 text-white hover:bg-red-700 font-bold uppercase text-[10px] tracking-widest"
                        >
                            {t('home.confirm_deletion')}
                        </Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

import { useState, Component } from "react";
import type { ErrorInfo, ReactNode } from "react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { AlertTriangle } from "lucide-react";

// --- ERROR BOUNDARY ---
class IcacErrorBoundary extends Component<{ children: ReactNode }, { hasError: boolean, error: Error | null }> {
    constructor(props: { children: ReactNode }) {
        super(props);
        this.state = { hasError: false, error: null };
    }

    static getDerivedStateFromError(error: Error) {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, errorInfo: ErrorInfo) {
        console.error("ICAC Critical Error:", error, errorInfo);
    }

    render() {
        if (this.state.hasError) {
            return (
                <div className="p-8 bg-red-50 border border-red-200 rounded-xl text-center">
                    <AlertTriangle className="h-12 w-12 text-red-500 mx-auto mb-4" />
                    <h2 className="text-xl font-bold text-red-700 mb-2">Algo deu errado neste componente</h2>
                    <p className="text-red-600 mb-4">{this.state.error?.message}</p>
                    <Button
                        onClick={() => this.setState({ hasError: false })}
                        variant="outline"
                        className="bg-white"
                    >
                        Tentar Novamente
                    </Button>
                </div>
            );
        }

        return this.props.children;
    }
}

// --- TYPES ---
interface PropertyConfig {
    target: string;
    deviation: string;
}

interface HviConfig {
    mic: PropertyConfig;
    str: PropertyConfig;
    uhml: PropertyConfig;
    ui: PropertyConfig;
    rd: PropertyConfig;
    b: PropertyConfig;
}

interface SampleResult {
    id: number;
    mic: number;
    str: number;
    uhml: number;
    ui: number;
    rd: number;
    b: number;
}

const DEFAULT_CONFIG: HviConfig = {
    mic: { target: "4.55", deviation: "0.05" },
    str: { target: "25.6", deviation: "0.7" },
    uhml: { target: "25.6", deviation: "0.3" },
    ui: { target: "79.3", deviation: "0.5" },
    rd: { target: "75.2", deviation: "0.5" },
    b: { target: "15.5", deviation: "0.3" },
};

// --- SAFE UTILS ---
const safeFormatValue = (val: any, decimals: number = 2): string => {
    if (typeof val !== 'number' || isNaN(val)) return "0,00";
    try {
        return val.toFixed(decimals).replace('.', ',');
    } catch {
        return "0,00";
    }
};

const safeFloat = (str: string): number => {
    if (!str) return 0;
    const clean = str.toString().replace(',', '.');
    const parsed = parseFloat(clean);
    return isNaN(parsed) ? 0 : parsed;
};

// --- MAIN COMPONENT ---
function IcacContent() {
    const [sampleCount, setSampleCount] = useState("12");
    const [config, setConfig] = useState<HviConfig>(DEFAULT_CONFIG);
    const [results, setResults] = useState<{ days: SampleResult[][] } | null>(null);
    const [copiedDay, setCopiedDay] = useState<number | null>(null);
    const [lockedDays, setLockedDays] = useState<Set<number>>(new Set());
    const [history, setHistory] = useState<Array<{
        timestamp: string;
        config: HviConfig;
    }>>([]);


    const handleConfigChange = (field: keyof HviConfig, type: 'target' | 'deviation', value: string) => {
        setConfig(prev => ({
            ...prev,
            [field]: {
                ...prev[field],
                [type]: value
            }
        }));
    };

    const calculateRange = (targetStr: string, devStr: string) => {
        const target = safeFloat(targetStr);
        const dev = safeFloat(devStr);
        if (target === 0 && dev === 0) return "-- — --";
        return `${(target - dev).toFixed(2)} — ${(target + dev).toFixed(2)}`;
    };

    const generateRandomValue = (targetStr: string, devStr: string, decimals: number) => {
        const target = safeFloat(targetStr);
        const dev = safeFloat(devStr);

        const min = target - dev;
        const max = target + dev;
        const val = min + Math.random() * (max - min);

        let final = parseFloat(val.toFixed(decimals));
        const minAllowed = parseFloat(min.toFixed(decimals));
        const maxAllowed = parseFloat(max.toFixed(decimals));

        if (final < minAllowed) final = minAllowed;
        if (final > maxAllowed) final = maxAllowed;

        return final;
    };

    const handleGenerate = () => {
        const count = parseInt(sampleCount);
        if (isNaN(count) || count <= 0) return;

        const allSamples: SampleResult[] = [];
        for (let i = 1; i <= count; i++) {
            allSamples.push({
                id: i,
                mic: generateRandomValue(config.mic.target, config.mic.deviation, 2),
                str: generateRandomValue(config.str.target, config.str.deviation, 1),
                uhml: generateRandomValue(config.uhml.target, config.uhml.deviation, 2),
                ui: generateRandomValue(config.ui.target, config.ui.deviation, 1),
                rd: generateRandomValue(config.rd.target, config.rd.deviation, 1),
                b: generateRandomValue(config.b.target, config.b.deviation, 1),
            });
        }

        const days: SampleResult[][] = [];
        for (let i = 0; i < allSamples.length; i += 6) {
            days.push(allSamples.slice(i, i + 6));
        }

        setResults({ days });
        setLockedDays(new Set()); // Reset locks on new generation
        setHistory(prev => [{
            timestamp: new Date().toLocaleString('pt-BR'),
            config: { ...config }
        }, ...prev]);
    };

    // --- ROBUST COPY FUNCTION ---
    const handleCopy = async (dayIndex: number, data: SampleResult[]) => {
        if (lockedDays.has(dayIndex)) return;

        try {
            // Gera apenas os valores (MIC, STR, UHML, UI, RD, +b) separados por TAB
            const rows = data.map(row =>
                `${safeFormatValue(row.mic, 2)}\t${safeFormatValue(row.str, 1)}\t${safeFormatValue(row.uhml, 2)}\t${safeFormatValue(row.ui, 1)}\t${safeFormatValue(row.rd, 1)}\t${safeFormatValue(row.b, 1)}`
            );

            const fullText = rows.join('\n');

            let copied = false;

            // 1. Try Modern API
            if (navigator.clipboard && navigator.clipboard.writeText) {
                try {
                    await navigator.clipboard.writeText(fullText);
                    copied = true;
                } catch (e) {
                    console.warn("API Copy failed, trying fallback");
                }
            }

            // 2. Fallback using temporary element (no ref conflicts)
            if (!copied) {
                try {
                    const tempTextArea = document.createElement("textarea");
                    tempTextArea.value = fullText;
                    tempTextArea.style.position = "fixed";
                    tempTextArea.style.left = "-9999px";
                    tempTextArea.style.top = "0";
                    document.body.appendChild(tempTextArea);

                    tempTextArea.focus();
                    tempTextArea.select();

                    copied = document.execCommand('copy');
                    document.body.removeChild(tempTextArea);
                } catch (e) {
                    console.error("Fallback failed", e);
                }
            }

            if (copied) {
                setCopiedDay(dayIndex);
                setTimeout(() => {
                    setLockedDays(prev => {
                        const next = new Set(prev);
                        next.add(dayIndex);
                        return next;
                    });
                    setCopiedDay(null);
                }, 1000);
            } else {
                alert("Erro ao copiar. Tente selecionar e copiar manualmente.");
            }

        } catch (error) {
            console.error("Copy Fatal Error:", error);
            alert("Erro crítico na cópia.");
        }
    };

    const renderTable = (dayTitle: string, dayIndex: number, data: SampleResult[]) => {
        if (!data || data.length === 0) return null;

        const calculateAverage = (field: keyof SampleResult) => {
            const sum = data.reduce((acc, curr) => acc + (curr[field] as number), 0);
            return sum / data.length;
        };

        const avgs = {
            mic: calculateAverage('mic'),
            str: calculateAverage('str'),
            uhml: calculateAverage('uhml'),
            ui: calculateAverage('ui'),
            rd: calculateAverage('rd'),
            b: calculateAverage('b'),
        };

        const isCopied = copiedDay === dayIndex;
        const isLocked = lockedDays.has(dayIndex);

        return (
            <div key={dayIndex} className="mb-16 animate-fade-in">
                <div className="flex items-center justify-between mb-6 border-b border-black pb-4">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase tracking-[0.2em] text-neutral-500 font-sans mb-1">DATA SET {String(dayIndex + 1).padStart(2, '0')}</span>
                        <h3 className="font-serif text-3xl text-black leading-none">{dayTitle}</h3>
                    </div>

                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleCopy(dayIndex, data)}
                        disabled={isLocked || isCopied}
                        className={`h-10 px-6 rounded-none border border-black uppercase text-[10px] tracking-widest font-bold transition-all hover:bg-black hover:text-white ${isLocked
                            ? 'opacity-40 cursor-not-allowed bg-neutral-100 border-neutral-300'
                            : isCopied
                                ? 'bg-black text-white'
                                : 'bg-transparent text-black'
                            }`}
                    >
                        {isLocked ? "LOCKED" : isCopied ? "COPIED" : "COPY DATA"}
                    </Button>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-center border-collapse">
                        <thead>
                            <tr className="border-b border-neutral-200">
                                <th className="py-4 px-4 text-left text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">Index</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">MIC</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">STR</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">UHML</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">UI</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">RD</th>
                                <th className="py-4 px-4 text-[10px] uppercase tracking-widest font-normal text-neutral-500 font-sans">+b</th>
                            </tr>
                        </thead>
                        <tbody className="font-mono text-xs">
                            {data.map((row) => (
                                <tr key={row.id} className="border-b border-neutral-100 hover:bg-neutral-50 transition-colors">
                                    <td className="py-3 px-4 text-left text-neutral-400">#{String(row.id).padStart(2, '0')}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.mic, 2)}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.str, 1)}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.uhml, 2)}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.ui, 1)}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.rd, 1)}</td>
                                    <td className="py-3 px-4 text-black">{safeFormatValue(row.b, 1)}</td>
                                </tr>
                            ))}
                            {/* LINHA DE MÉDIA - MINIMALISTA */}
                            <tr className="bg-neutral-50 border-t-2 border-black">
                                <td className="py-4 px-4 text-left font-sans text-[10px] uppercase tracking-widest text-black font-bold">AVERAGE</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.mic, 2)}</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.str, 1)}</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.uhml, 2)}</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.ui, 1)}</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.rd, 1)}</td>
                                <td className="py-4 px-4 font-bold">{safeFormatValue(avgs.b, 1)}</td>
                            </tr>
                            {/* LINHA DE META - MINIMALISTA */}
                            <tr className="border-t border-neutral-200 text-neutral-400">
                                <td className="py-3 px-4 text-left font-sans text-[10px] uppercase tracking-widest">TARGET</td>
                                <td className="py-3 px-4">{config.mic.target}</td>
                                <td className="py-3 px-4">{config.str.target}</td>
                                <td className="py-3 px-4">{config.uhml.target}</td>
                                <td className="py-3 px-4">{config.ui.target}</td>
                                <td className="py-3 px-4">{config.rd.target}</td>
                                <td className="py-3 px-4">{config.b.target}</td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
        );
    };

    const renderInputGroup = (key: keyof HviConfig, label: string) => {
        const { target, deviation } = config[key];
        return (
            <div className="flex flex-col gap-2">
                <div className="flex items-baseline justify-between border-b border-neutral-200 pb-1">
                    <label className="text-sm font-bold uppercase tracking-widest text-black font-sans">{label}</label>
                    <span className="font-mono text-xs text-neutral-400">{calculateRange(target, deviation)}</span>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                        <span className="text-[10px] uppercase tracking-widest text-neutral-400 block">Target</span>
                        <Input
                            value={target}
                            onChange={(e) => handleConfigChange(key, 'target', e.target.value)}
                            className="bg-transparent border border-neutral-200 rounded-none h-10 font-mono text-sm text-center focus:border-black focus:ring-0 transition-colors placeholder:text-neutral-200"
                        />
                    </div>
                    <div className="space-y-1">
                        <span className="text-[10px] uppercase tracking-widest text-neutral-400 block flex justify-between">
                            <span>Dev</span>
                            <span>±</span>
                        </span>
                        <Input
                            value={deviation}
                            onChange={(e) => handleConfigChange(key, 'deviation', e.target.value)}
                            className="bg-transparent border border-neutral-200 rounded-none h-10 font-mono text-sm text-center focus:border-black focus:ring-0 transition-colors placeholder:text-neutral-200"
                        />
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className="min-h-screen bg-white text-black font-sans selection:bg-black selection:text-white pb-24">
            {/* HERDER ORIGO */}
            <div className="max-w-7xl mx-auto pt-16 pb-20 px-6 md:px-12 flex flex-col items-center justify-center space-y-8">
                <div className="flex flex-col items-center gap-6">
                    {/* SVG LOGO ORIGO */}
                    <svg width="64" height="64" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="50" cy="50" r="48" stroke="black" strokeWidth="2" />
                        <circle cx="50" cy="50" r="4" fill="black" />
                    </svg>
                    <h1 className="text-4xl font-serif tracking-[0.2em] font-normal text-black pl-2">ORIGO</h1>
                </div>
            </div>

            <div className="max-w-6xl mx-auto px-6 md:px-12 space-y-24 animate-fade-in">

                {/* CONTROLS SECTION */}
                <div className="space-y-12">
                    <div className="flex items-center justify-between border-b border-black pb-4">
                        <h2 className="font-serif text-2xl">Module Configuration</h2>
                        <div className="flex items-center gap-6">
                            <span className="text-xs uppercase tracking-widest text-neutral-500">Sample Count</span>
                            <Input
                                value={sampleCount}
                                onChange={(e) => setSampleCount(e.target.value)}
                                className="w-20 h-10 rounded-none border-b border-neutral-300 focus:border-black text-center font-mono focus:ring-0 px-0 bg-transparent text-base"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-x-12 gap-y-12">
                        {renderInputGroup('mic', 'MIC')}
                        {renderInputGroup('str', 'STR')}
                        {renderInputGroup('uhml', 'UHML')}
                        {renderInputGroup('ui', 'UI')}
                        {renderInputGroup('rd', 'RD')}
                        {renderInputGroup('b', '+b')}
                    </div>

                    <div className="flex justify-center pt-8">
                        <button
                            onClick={handleGenerate}
                            className="group relative px-16 py-5 bg-black text-white text-xs uppercase tracking-[0.25em] font-bold hover:bg-neutral-800 transition-all duration-300 border border-transparent hover:border-black hover:bg-white hover:text-black"
                        >
                            Execute Analysis
                        </button>
                    </div>
                </div>

                {/* RESULTS SECTION */}
                {results && (
                    <div className="space-y-16 animate-fade-in">
                        <div className="flex items-center justify-between border-b border-black pb-4">
                            <div className="flex items-baseline gap-4">
                                <h2 className="font-serif text-2xl">Output Data</h2>
                                <span className="text-xs font-mono text-neutral-400">SESSION ID: {Date.now().toString().slice(-6)}</span>
                            </div>
                            <button onClick={() => setResults(null)} className="text-[10px] uppercase tracking-widest text-neutral-400 hover:text-black transition-colors">
                                Clear Workspace
                            </button>
                        </div>

                        <div className="space-y-20">
                            {results.days.map((dayData, index) =>
                                renderTable(`Day ${index + 1}`, index, dayData)
                            )}
                        </div>
                    </div>
                )}

                {/* HISTORY SECTION */}
                {history.length > 0 && (
                    <div className="pt-24 border-t border-neutral-100">
                        <h2 className="font-serif text-2xl mb-12">Session Log</h2>
                        <div className="space-y-0 text-sm">
                            {history.map((entry, entryIndex) => (
                                <div key={entryIndex} className="group flex flex-col md:flex-row md:items-center justify-between py-6 border-b border-neutral-100 hover:bg-neutral-50 transition-colors px-4">
                                    <div className="flex items-center gap-8 mb-4 md:mb-0">
                                        <span className="font-mono text-neutral-400 text-xs">{(entryIndex + 1).toString().padStart(3, '0')}</span>
                                        <span className="text-xs uppercase tracking-widest text-neutral-900">{entry.timestamp}</span>
                                    </div>
                                    <div className="flex gap-8 font-mono text-xs text-neutral-500 overflow-x-auto pb-2 md:pb-0">
                                        {Object.entries(entry.config).map(([k, v]) => (
                                            <span key={k} className="whitespace-nowrap">
                                                <span className="uppercase text-neutral-300 mr-2">{k}:</span>
                                                <span className="text-black">{v.target}</span>
                                            </span>
                                        ))}
                                    </div>
                                    <button
                                        className="hidden group-hover:block ml-4 text-[9px] uppercase tracking-widest font-bold text-black border border-black px-4 py-2 hover:bg-black hover:text-white transition-colors"
                                        onClick={() => {
                                            setConfig(entry.config);
                                            window.scrollTo({ top: 0, behavior: 'smooth' });
                                        }}
                                    >
                                        Restore
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );

}

// Export Wrapped Component
export default function Icac() {
    return (
        <IcacErrorBoundary>
            <IcacContent />
        </IcacErrorBoundary>
    );
}

