            {activeTab === 'geral' && analysisMetrics && (
                <div ref={analiticoSectionRef} className="space-y-6 mb-12 animate-fade-in transition-all duration-700 bg-white/50 p-6 rounded-[3rem] border border-neutral-100 mt-8">
