                                    <div className={cn(
                                        "px-2 py-1 rounded-full text-[9px] font-bold flex items-center gap-1",
                                        analysisMetrics.revisionRate >= 0.85 ? "bg-emerald-50 text-emerald-600" : "bg-amber-50 text-amber-600"
