                                        <span>{(analysisMetrics.revisionRate * 100).toFixed(1)}%</span>
                                    </div>
                                </div>
                                <div className="text-2xl font-serif text-black">{analysisMetrics.currentReceived.toLocaleString('pt-BR')}</div>
