                            <div className="flex flex-col gap-6 mb-8">
                                <div>
                                    <h3 className="text-2xl font-serif text-black leading-tight tracking-tight flex items-center gap-2">
                                        <LayoutGrid className="h-6 w-6 text-neutral-400" />
