import React, { useState, useEffect } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { useToast } from "@/contexts/ToastContext";
import { Upload, BarChart3, Loader2, X, Sun, Moon, Sunset, ArrowRight, Save, Calendar, Copy, FileSpreadsheet } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import Tesseract from 'tesseract.js';

import { LabService } from "@/entities/Lab";
import ProductionTrendChart from "@/components/analysis/ProductionTrendChart";
import { producaoService } from "@/services/producao.service";
import type { ProducaoData } from "@/services/producao.service";
import { parseProducaoFileInChunks } from "@/lib/producaoParser";
import { Skeleton } from "@/components/ui/skeleton";

interface IOperacaoItem {
    id?: string;
    data_producao: string;
    turno: string;
    identificador_unico: string;
    peso: number;
    produto?: string;
    metadata?: any;
}

interface OCRBox {
    text: string;
    x0: number;
    y0: number;
    x1: number;
    y1: number;
    confidence: number;
}

interface OCRBlock {
    id: string;
    data: string;
    turnos: {
        nome: string;
        valores: {
            val: string;
            bbox?: OCRBox;
        }[];
        totalOriginal?: number;
        totalBbox?: OCRBox;
    }[];
}

interface OCRResult {
    blocks: OCRBlock[];
    allBoxes: OCRBox[];
}

export default function Operacao() {
    const { user, currentLab, selectLab } = useAuth();
    const labId = currentLab?.id || user?.lab_id || (user?.acesso === 'admin_global' ? 'all' : undefined);
    const { addToast } = useToast();
    const [isUploading, setIsUploading] = useState(false);
    const [isProcessingOCR, setIsProcessingOCR] = useState(false);
    const [ocrDebugText, setOcrDebugText] = useState<string>("");
    const [isLoading, setIsLoading] = useState(false);
    const [pastedImage, setPastedImage] = useState<string | null>(null);
    const [ocrData, setOcrData] = useState<OCRResult | null>(null);
    const [chartData, setChartData] = useState<IOperacaoItem[]>([]);
    const [totalProduzido, setTotalProduzido] = useState(0);

    const turno1Total = chartData.filter((d: IOperacaoItem) => d.turno === 'TURNO 1').reduce((acc: number, curr: IOperacaoItem) => acc + curr.peso, 0);
    const turno2Total = chartData.filter((d: IOperacaoItem) => d.turno === 'TURNO 2').reduce((acc: number, curr: IOperacaoItem) => acc + curr.peso, 0);
    const turno3Total = chartData.filter((d: IOperacaoItem) => d.turno === 'TURNO 3').reduce((acc: number, curr: IOperacaoItem) => acc + curr.peso, 0);

    useEffect(() => {
        loadStats();
    }, [currentLab]);

    useEffect(() => {
        const handlePaste = (e: ClipboardEvent) => {
            const items = e.clipboardData?.items;
            if (!items) return;
            for (let i = 0; i < items.length; i++) {
                if (items[i].type.indexOf('image') !== -1) {
                    const blob = items[i].getAsFile();
                    if (blob) {
                        const reader = new FileReader();
                        reader.onload = (event) => {
                            if (event.target?.result) {
                                setPastedImage(event.target.result as string);
                                processImageOCR(blob);
                            }
                        };
                        reader.readAsDataURL(blob);
                    }
                    e.preventDefault();
                    break;
                }
            }
        };
        window.addEventListener('paste', handlePaste);
        return () => window.removeEventListener('paste', handlePaste);
    }, [currentLab]);

    const loadStats = async () => {
        const targetLabId = currentLab?.id || user?.lab_id;
        if (!targetLabId) return;
        setIsLoading(true);
        try {
            const data = await producaoService.list(targetLabId);
            if (data) {
                const validData: IOperacaoItem[] = data.map((d: ProducaoData) => ({ ...d, peso: d.peso || 0 }));
                setChartData(validData);
                setTotalProduzido(validData.reduce((acc: number, curr: IOperacaoItem) => acc + curr.peso, 0));
            }
        } catch (error) {
            console.error("Failed load:", error);
            addToast({ title: "Erro de Carregamento", type: "error" });
        } finally {
            setIsLoading(false);
        }
    };

    const preprocessImage = async (imageBlob: Blob): Promise<string> => {
        return new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                const img = new Image();
                img.onload = () => {
                    const canvas = document.createElement("canvas");
                    const ctx = canvas.getContext("2d");
                    if (!ctx) { resolve(e.target?.result as string); return; }
                    const scale = 2;
                    canvas.width = img.width * scale;
                    canvas.height = img.height * scale;
                    ctx.imageSmoothingEnabled = false;
                    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
                    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
                    const data = imageData.data;
                    for (let i = 0; i < data.length; i += 4) {
                        const gray = data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114;
                        data[i] = gray; data[i + 1] = gray; data[i + 2] = gray;
                    }
                    ctx.putImageData(imageData, 0, 0);
                    resolve(canvas.toDataURL("image/png", 1.0));
                };
                img.src = e.target?.result as string;
            };
            reader.readAsDataURL(imageBlob);
        });
    };

    const fixOCRCharacters = (text: string): string => {
        return text.replace(/O/g, '0').replace(/I/g, '1').replace(/l/g, '1').replace(/B/g, '8').replace(/S/g, '5').replace(/Z/g, '7').replace(/G/g, '6');
    };

    const extractNumbersFromLine = (words: any[]) => {
        const values: { val: string; bbox: OCRBox }[] = [];
        words.forEach(w => {
            const rawText = w.text.trim();
            if (!rawText) return;
            const letterCount = (rawText.match(/[a-zA-Z]/g) || []).length;
            const digitCount = (rawText.match(/[0-9]/g) || []).length;
            if (letterCount >= 2 || (letterCount > 0 && digitCount === 0)) return;
            const clean = fixOCRCharacters(rawText).replace(/\./g, '');
            const numStr = clean.replace(/[^\d]/g, '');
            if (numStr.length > 0) {
                const val = parseInt(numStr);
                if (!isNaN(val) && val < 1000000) {
                    values.push({ val: String(val), bbox: { text: w.text, x0: w.bbox.x0, y0: w.bbox.y0, x1: w.bbox.x1, y1: w.bbox.y1, confidence: w.confidence } });
                }
            }
        });
        return values;
    };

    const processImageOCR = async (imageFile: File) => {
        setIsProcessingOCR(true);
        setOcrData(null);
        setOcrDebugText("Iniciando processamento...");
        try {
            const processedImageUrl = await preprocessImage(imageFile);
            const worker = await Tesseract.createWorker('eng');
            await worker.setParameters({ tessedit_pageseg_mode: Tesseract.PSM.SINGLE_BLOCK });
            const result = (await worker.recognize(processedImageUrl)) as any;
            await worker.terminate();
            const rawText = result.data.text || "";
            let debugLog = `--- LEITURA BRUTA ---\n${rawText}\n-------------------\n\n`;
            let lines = result.data.lines || [];
            if (lines.length === 0 && rawText.trim().length > 0) {
                lines = rawText.split('\n').map((txt: string) => ({ text: txt, words: txt.split(/\s+/).filter(Boolean).map(w => ({ text: w, bbox: { x0: 0, x1: 0, y0: 0, y1: 0 }, confidence: 100 })) }));
            }
            const blocks: OCRBlock[] = [];
            let currentBlock: OCRBlock | null = null;
            let lastDate = '';
            const globalDateRegex = /(\d{1,2})\/(\d{1,2})\/(\d{2,4})/;
            const ensureBlock = (date: string) => {
                if (currentBlock && !currentBlock.data && date) { currentBlock.data = date; return; }
                if (currentBlock && currentBlock.data === date && date !== '') return;
                if (currentBlock && currentBlock.turnos.length === 0) { currentBlock.data = date; return; }
                currentBlock = { id: Math.random().toString(36).substr(2, 9), data: date, turnos: [] };
                blocks.push(currentBlock);
            };
            ensureBlock(lastDate);
            let sequentialNumericLineCount = 0;
            lines.forEach((line: any) => {
                const text = line.text.trim();
                const upper = text.toUpperCase();
                if (text.length < 3) return;
                const isDataRow = upper.includes("TURNO") || upper.includes("TOTAL");
                if (!isDataRow) {
                    const dateMatch = text.match(globalDateRegex);
                    if (dateMatch) {
                        let day = dateMatch[1], month = dateMatch[2], year = dateMatch[3];
                        if (year.length === 2) year = `20${year}`;
                        if (parseInt(month) <= 12 && parseInt(day) <= 31 && parseInt(year) >= 2020) {
                            const newDate = `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
                            if (newDate !== lastDate && lastDate !== '') sequentialNumericLineCount = 0;
                            lastDate = newDate;
                            ensureBlock(newDate);
                        }
                    }
                }
                const nums = extractNumbersFromLine(line.words || []);
                const isFuzzyTurno = /[T\[].{2,5}\s+[123]\b/.test(text) || upper.includes("TURNO");
                const isFuzzyTotal = upper.includes("TOTAL") || /TOT.{0,2}L/i.test(text) || upper.includes("AL GERAL");
                const hasLabel = isFuzzyTurno || isFuzzyTotal || upper.includes("T1") || upper.includes("T2");
                const visualNumbersCount = (text.replace(/[^0-9]/g, "").length);
                const isDataLine = hasLabel || nums.length >= 2 || (visualNumbersCount > 8 && nums.length >= 1);
                if (hasLabel && nums.length > 1) { while (nums.length > 0 && parseInt(nums[0].val) <= 3) nums.shift(); }
                if (isDataLine) {
                    let label = "TURNO INDEFINIDO";
                    const t1 = upper.includes("TURNO 1") || upper.includes("T1") || /[T\[].{2,5}\s*1\b/.test(text);
                    const t2 = upper.includes("TURNO 2") || upper.includes("T2") || /[T\[].{2,5}\s*2\b/.test(text);
                    const t3 = upper.includes("TURNO 3") || upper.includes("T3") || /[T\[].{2,5}\s*3\b/.test(text);
                    if (t1) { if (currentBlock && currentBlock.turnos.some(t => t.nome === "TURNO 1")) { ensureBlock(''); sequentialNumericLineCount = 0; } label = "TURNO 1"; sequentialNumericLineCount = 1; }
                    else if (t2) { label = "TURNO 2"; sequentialNumericLineCount = 2; }
                    else if (t3) { label = "TURNO 3"; sequentialNumericLineCount = 3; }
                    else if (isFuzzyTotal) { label = "TOTAL GERAL"; }
                    else {
                        let isSumRow = false;
                        if (currentBlock && currentBlock.turnos.length > 0 && nums.length > 2) {
                            const realTurnos = currentBlock.turnos.filter(t => !t.nome.includes('TOTAL') && !t.nome.includes('GERAL'));
                            if (realTurnos.length >= 1) {
                                const tMv = realTurnos.map(t => { const v = [...t.valores]; if (v.length > 3) v.pop(); return v; });
                                const maxCols = Math.min(nums.length > 3 ? nums.length - 1 : nums.length, ...tMv.map(v => v.length), 5);
                                const comps = Math.max(maxCols, Math.min(nums.length, 3));
                                let matches = 0;
                                for (let c = 0; c < comps; c++) {
                                    let colSum = 0; tMv.forEach(v => { if (v[c]) colSum += parseFloat(v[c].val.replace(/\./g, "").replace(",", ".")); });
                                    const currVal = parseFloat(nums[c].val.replace(/\./g, "").replace(",", "."));
                                    if (!isNaN(currVal) && colSum > 0 && Math.abs(colSum - currVal) <= Math.max(colSum * 0.20, 10)) matches++;
                                }
                                if (matches >= Math.max(1, Math.ceil(comps / 3))) isSumRow = true;
                                if (!isSumRow && realTurnos.length >= 1) isSumRow = true;
                            }
                        }
                        if (isSumRow) label = "TOTAL GERAL";
                        else if (nums.length >= 3) { sequentialNumericLineCount++; if (sequentialNumericLineCount === 1) label = "TURNO 1"; else if (sequentialNumericLineCount === 2) label = "TURNO 2"; else label = "TOTAL GERAL"; }
                        else return;
                    }
                    if (nums.length > 5) { const fv = parseInt(nums[0].val); if (fv === sequentialNumericLineCount && fv <= 3) nums.shift(); }
                    let tOrig = 0; if (nums.length > 4) { const li = nums.pop(); if (li) tOrig = parseInt(li.val.replace(/\./g, '')); }
                    if (nums.length > 0 && currentBlock) {
                        if (!currentBlock.turnos.some(t => t.nome === label && JSON.stringify(t.valores.map(v => v.val)) === JSON.stringify(nums.map(n => n.val)))) {
                            if (label === "TOTAL GERAL") {
                                const rt = currentBlock.turnos.filter(t => !t.nome.includes('TOTAL') && !t.nome.includes('GERAL'));
                                if (rt.length > 0) {
                                    const mc = Math.max(...rt.map(t => t.valores.length));
                                    const cv: { val: string; bbox: OCRBox }[] = [];
                                    for (let c = 0; c < mc; c++) {
                                        let cs = 0; rt.forEach(t => { if (t.valores[c]) cs += parseFloat(t.valores[c].val.replace(/\./g, "").replace(",", ".")); });
                                        cv.push({ val: String(cs), bbox: nums[c]?.bbox || { text: '', x0: 0, y0: 0, x1: 0, y1: 0, confidence: 100 } });
                                    }
                                    currentBlock.turnos.push({ nome: label, valores: cv, totalOriginal: tOrig });
                                } else currentBlock.turnos.push({ nome: label, valores: nums, totalOriginal: tOrig });
                            } else currentBlock.turnos.push({ nome: label, valores: nums, totalOriginal: tOrig });
                        }
                    }
                }
            });
            const validBlocks = blocks.filter(b => b.turnos.length > 0);
            setOcrDebugText(debugLog + `\nBlocos Válidos Finais: ${validBlocks.length}`);
            if (validBlocks.length === 0) {
                setOcrData({ blocks: [{ id: 'error_fallback', data: lastDate, turnos: [{ nome: "NENHUM DADO IDENTIFICADO", valores: [] }] }], allBoxes: [] });
                addToast({ title: "Atenção", description: "O texto foi lido mas não conseguimos identificar as colunas.", type: "warning" });
            } else {
                setOcrData({ blocks: validBlocks, allBoxes: result.data.words?.map((w: any) => ({ text: w.text, x0: w.bbox.x0, y0: w.bbox.y0, x1: w.bbox.x1, y1: w.bbox.y1, confidence: w.confidence })) || [] });
                addToast({ title: "Sucesso", description: `${validBlocks.length} dias identificados.`, type: "success" });
            }
        } catch (error: any) {
            console.error(error); setOcrDebugText(`ERRO FATAL: ${error.message}`);
            addToast({ title: "Erro", description: "Falha ao processar imagem.", type: "error" });
        } finally { setIsProcessingOCR(false); }
    };

    const confirmOCRUpload = async () => {
        if (!currentLab?.id || !ocrData) return;
        const recordsToInsert: any[] = [];
        ocrData.blocks.forEach((block: OCRBlock) => {
            if (!block.data) return;
            block.turnos.forEach((turno: any) => {
                if (turno.nome.includes("TOTAL") || turno.nome.includes("GERAL")) return;
                turno.valores.forEach((item: any, index: number) => {
                    const cleaned = item.val.replace(/\./g, '').replace(',', '.');
                    const val = parseFloat(cleaned);
                    if (!isNaN(val) && val > 0) {
                        recordsToInsert.push({ lab_id: currentLab.id, identificador_unico: `${block.data}-${turno.nome.replace(" ", "")}-COL${index + 1}`, data_producao: block.data, turno: turno.nome, produto: `Linha/Mq ${index + 1}`, peso: val, metadata: { source: 'ocr_multi_day' } });
                    }
                });
            });
        });
        if (recordsToInsert.length === 0) { addToast({ title: "Sem dados", type: "warning" }); return; }
        setIsLoading(true);
        try {
            await producaoService.uploadData(recordsToInsert);
            addToast({ title: "Salvo com sucesso!", description: `${recordsToInsert.length} registros salvos.`, type: "success" });
            setOcrData(null); setPastedImage(null); loadStats();
        } catch (error) { addToast({ title: "Erro ao salvar", type: "error" }); } finally { setIsLoading(false); }
    };

    const handleClearAllData = async () => {
        const targetLabId = currentLab?.id || user?.lab_id;
        if (!confirm("LIMPAR TUDO?") || !targetLabId) return;
        try { await producaoService.deleteAll(targetLabId); loadStats(); addToast({ title: "Histórico Limpo", type: "success" }); } catch (error) { addToast({ title: "Erro ao limpar", type: "error" }); }
    };

    const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        const targetLabId = currentLab?.id || user?.lab_id;

        if (!targetLabId) {
            addToast({ title: "Erro de Laboratório", description: "O seu usuário não está vinculado a nenhum laboratório.", type: "error" });
            event.target.value = "";
            return;
        }
        setIsUploading(true);
        try {
            let total = 0; await parseProducaoFileInChunks(file, targetLabId, async (batch: any[]) => { await producaoService.uploadData(batch); total += batch.length; }, 2000);
            addToast({ title: "Upload concluído", description: `${total} registros.`, type: "success" }); loadStats();
        } catch (error) {
            console.error("Upload producao error:", error);
            addToast({ title: "Erro no processamento", type: "error" });
        } finally {
            setIsUploading(false); event.target.value = "";
        }
    };

    const [labs, setLabs] = useState<any[]>([]);
    useEffect(() => { if (user?.acesso === 'admin_global') { const fn = async () => { const l = await LabService.list(); setLabs(l); }; fn(); } }, [user]);

    if (user?.acesso === 'admin_global' && !currentLab) {
        return (
            <div className="flex flex-col items-center justify-center p-8 space-y-12 animate-fade-in text-black">
                <div className="inline-flex p-4 bg-black rounded-2xl shadow-2xl"><FileSpreadsheet className="h-12 w-12 text-white" /></div>
                <h1 className="text-5xl font-serif">Selecione o Laboratório</h1>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-7xl">
                    {labs.map((lab: any) => (
                        <button key={lab.id} onClick={() => selectLab(lab.id)} className="group relative flex flex-col p-8 bg-white border-2 border-neutral-200 hover:border-black rounded-2xl transition-all duration-300 text-left hover:shadow-xl hover:-translate-y-1">
                            <div className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 transition-opacity"><ArrowRight className="h-6 w-6 text-black" /></div>
                            <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 mb-2">Laboratório</span>
                            <h3 className="text-xl font-bold text-black group-hover:underline">{lab.nome}</h3>
                        </button>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="w-full py-8 text-black pb-24">
            <div className="flex items-center justify-between mb-8 pb-8 border-b border-black">
                <div className="flex items-center gap-4">
                    <div className="h-12 w-12 bg-black text-white flex items-center justify-center rounded-lg"><FileSpreadsheet className="h-6 w-6" /></div>
                    <div><span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400">Operação</span><h1 className="text-3xl font-serif">Diária</h1></div>
                </div>
                <div className="flex gap-3">
                    {user?.acesso === 'admin_global' && (
                        <select
                            title="Selecione o Laboratório"
                            aria-label="Selecione o Laboratório"
                            className="bg-white border-2 border-neutral-200 text-black text-[10px] font-bold uppercase tracking-widest rounded-xl px-4 py-2 hover:border-black transition-all cursor-pointer outline-none"
                            value={labId || ""}
                            onChange={(e) => {
                                if (e.target.value) selectLab(e.target.value);
                            }}
                        >
                            <option value="" disabled>SELECIONE O LABORATÓRIO</option>
                            {labs.map(l => <option key={l.id} value={l.id}>{l.nome}</option>)}
                        </select>
                    )}
                    <Button variant="outline" onClick={handleClearAllData} className="text-red-600 border-red-100 hover:bg-red-50">Limpar Histórico</Button>
                    <div className="relative">
                        <input type="file" accept=".xlsx,.xls" onChange={handleFileUpload} disabled={isUploading} className="absolute inset-0 opacity-0 cursor-pointer" title="Importar Excel" aria-label="Importar Excel" />
                        <Button className="bg-emerald-600 text-white">{isUploading ? <Loader2 className="animate-spin h-4 w-4 mr-2" /> : <Upload className="h-4 w-4 mr-2" />} Importar Excel</Button>
                    </div>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 mb-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
                {isLoading ? (
                    <>
                        <Skeleton className="h-[180px] rounded-[2rem]" />
                        <Skeleton className="h-[180px] rounded-[2rem]" />
                        <Skeleton className="h-[180px] rounded-[2rem]" />
                        <Skeleton className="h-[180px] rounded-[2rem]" />
                    </>
                ) : (
                    <>
                        <div className="group bg-white border border-neutral-200 p-8 rounded-[2rem] shadow-[0_10px_30px_rgba(0,0,0,0.02)] hover:shadow-[0_20px_50px_rgba(0,0,0,0.05)] transition-all duration-500 hover:-translate-y-1">
                            <div className="flex items-center justify-between mb-6">
                                <span className="text-[10px] font-black uppercase tracking-widest text-neutral-400 group-hover:text-amber-500 transition-colors">Turno 1</span>
                                <div className="h-8 w-8 rounded-full bg-amber-50 flex items-center justify-center group-hover:scale-110 transition-transform"><Sun className="h-4 w-4 text-amber-500" /></div>
                            </div>
                            <div className="text-4xl font-serif text-black mb-1 tabular-nums">{turno1Total.toLocaleString()}</div>
                            <div className="text-[10px] font-bold text-neutral-400 uppercase tracking-tight">Carga de Amostras</div>
                        </div>

                        <div className="group bg-white border border-neutral-200 p-8 rounded-[2rem] shadow-[0_10px_30px_rgba(0,0,0,0.02)] hover:shadow-[0_20px_50px_rgba(0,0,0,0.05)] transition-all duration-500 hover:-translate-y-1">
                            <div className="flex items-center justify-between mb-6">
                                <span className="text-[10px] font-black uppercase tracking-widest text-neutral-400 group-hover:text-orange-500 transition-colors">Turno 2</span>
                                <div className="h-8 w-8 rounded-full bg-orange-50 flex items-center justify-center group-hover:scale-110 transition-transform"><Sunset className="h-4 w-4 text-orange-500" /></div>
                            </div>
                            <div className="text-4xl font-serif text-black mb-1 tabular-nums">{turno2Total.toLocaleString()}</div>
                            <div className="text-[10px] font-bold text-neutral-400 uppercase tracking-tight">Carga de Amostras</div>
                        </div>

                        <div className="group bg-white border border-neutral-200 p-8 rounded-[2rem] shadow-[0_10px_30px_rgba(0,0,0,0.02)] hover:shadow-[0_20px_50px_rgba(0,0,0,0.05)] transition-all duration-500 hover:-translate-y-1">
                            <div className="flex items-center justify-between mb-6">
                                <span className="text-[10px] font-black uppercase tracking-widest text-neutral-400 group-hover:text-indigo-500 transition-colors">Turno 3</span>
                                <div className="h-8 w-8 rounded-full bg-indigo-50 flex items-center justify-center group-hover:scale-110 transition-transform"><Moon className="h-4 w-4 text-indigo-500" /></div>
                            </div>
                            <div className="text-4xl font-serif text-black mb-1 tabular-nums">{turno3Total.toLocaleString()}</div>
                            <div className="text-[10px] font-bold text-neutral-400 uppercase tracking-tight">Carga de Amostras</div>
                        </div>

                        <div className="group bg-black p-8 rounded-[2rem] shadow-[0_10px_30px_rgba(0,0,0,0.15)] relative overflow-hidden transition-all duration-500 hover:-translate-y-2">
                            <div className="absolute -right-8 -bottom-8 opacity-10 group-hover:opacity-20 transition-opacity rotate-12 group-hover:rotate-0 duration-700">
                                <BarChart3 className="h-40 w-40 text-white" />
                            </div>
                            <div className="flex items-center justify-between mb-6 relative z-10">
                                <span className="text-[10px] font-black uppercase tracking-widest text-neutral-400">Produção Total</span>
                                <div className="h-8 w-8 rounded-full bg-white/10 flex items-center justify-center group-hover:bg-white/20 transition-colors"><BarChart3 className="h-4 w-4 text-white" /></div>
                            </div>
                            <div className="text-4xl font-serif text-white mb-1 relative z-10 tabular-nums">{totalProduzido.toLocaleString()}</div>
                            <div className="text-[10px] font-bold text-neutral-500 uppercase tracking-tight relative z-10">Total de Amostras Processadas</div>
                        </div>
                    </>
                )}
            </div>
            <ProductionTrendChart data={chartData} />
            {pastedImage && (
                <div className="fixed inset-0 bg-white/95 z-50 p-8 overflow-y-auto animate-fade-in">
                    <div className="max-w-6xl mx-auto">
                        <div className="flex items-center justify-between mb-8">
                            <div className="flex items-center gap-4"><div className="h-10 w-10 bg-black text-white flex items-center justify-center rounded-lg"><Copy className="h-5 w-5" /></div><h2 className="text-2xl font-serif">Revisão de Dados OCR</h2></div>
                            <div className="flex gap-4">
                                <Button onClick={confirmOCRUpload} disabled={isLoading} className="bg-black text-white px-8"><Save className="h-4 w-4 mr-2" /> Salvar Tudo</Button>
                                <Button variant="ghost" onClick={() => { setOcrData(null); setPastedImage(null); }}><X className="h-6 w-6" /></Button>
                            </div>
                        </div>
                        {isProcessingOCR ? (
                            <div className="flex flex-col items-center justify-center p-20 space-y-4">
                                <Loader2 className="h-12 w-12 animate-spin text-black" />
                                <div className="text-center"><p className="font-bold text-lg">Processando Imagem com OCR...</p><p className="text-sm text-neutral-500">Estamos identificando datas, turnos e máquinas automaticamente.</p></div>
                            </div>
                        ) : ocrData && (
                            <div className="space-y-8 animate-fade-in">
                                {ocrData.blocks.map((block: OCRBlock, bIdx: number) => (
                                    <div key={block.id} className="bg-white border-2 border-neutral-200 rounded-xl overflow-hidden shadow-sm">
                                        <div className="bg-neutral-50 p-4 border-b border-neutral-200 flex items-center justify-between">
                                            <div className="flex items-center gap-4">
                                                <div className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-neutral-200 shadow-sm">
                                                    <Calendar className="h-4 w-4 text-neutral-400" />
                                                    <input type="date" value={block.data} onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                                                        const n = { ...ocrData };
                                                        n.blocks[bIdx].data = e.target.value;
                                                        setOcrData(n);
                                                    }} className="text-sm font-bold bg-transparent border-none focus:ring-0 p-0" title="Data do Bloco" />
                                                </div>
                                                <span className="text-xs font-bold uppercase text-neutral-400 tracking-widest">Dia {bIdx + 1}</span>
                                            </div>
                                            {!block.data && <div className="flex items-center gap-2 text-red-500 font-bold text-[10px] animate-pulse"><X className="h-3 w-3" /> DATA OBRIGATÓRIA</div>}
                                        </div>
                                        <div className="p-6 grid grid-cols-1 md:grid-cols-4 gap-6">
                                            {block.turnos.map((turno: any) => (
                                                <div key={turno.nome} className={cn("p-4 rounded-xl border", turno.nome.includes("TOTAL") ? "bg-black text-white border-black" : "bg-neutral-50 border-neutral-100")}>
                                                    <div className="flex items-center gap-2 mb-4">
                                                        {turno.nome.includes("TURNO 1") && <Sun className="h-4 w-4 text-amber-500" />}
                                                        {turno.nome.includes("TURNO 2") && <Sunset className="h-4 w-4 text-orange-500" />}
                                                        {turno.nome.includes("TURNO 3") && <Moon className="h-4 w-4 text-indigo-500" />}
                                                        <h4 className="font-bold text-xs uppercase tracking-widest">{turno.nome}</h4>
                                                    </div>
                                                    <div className="space-y-2">
                                                        {turno.valores.map((item: any, vIdx: number) => (
                                                            <div key={vIdx} className="flex items-center justify-between gap-3 bg-white p-2 rounded-lg border border-neutral-200 shadow-sm text-black">
                                                                <span className="text-[9px] font-bold text-neutral-400 uppercase">M{vIdx + 1}</span>
                                                                <input type="text" value={item.val} onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                                                                    const n = { ...ocrData };
                                                                    const t = n.blocks[bIdx].turnos.find((t: any) => t.nome === turno.nome);
                                                                    if (t) t.valores[vIdx].val = e.target.value;
                                                                    setOcrData(n);
                                                                }} className="w-full text-right text-sm font-mono font-bold bg-transparent border-none focus:ring-0 p-0" title={`Máquina ${vIdx + 1}`} />
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                        <div className="mt-12 p-6 bg-neutral-900 rounded-xl text-white">
                            <div className="flex items-center gap-2 mb-4"><div className="h-2 w-2 rounded-full bg-emerald-500 animate-pulse" /> <span className="font-bold text-xs uppercase tracking-widest">Logs do Motor de Inteligência</span></div>
                            <pre className="text-[10px] font-mono leading-relaxed opacity-50 overflow-x-auto whitespace-pre-wrap">{ocrDebugText}</pre>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect, useRef } from "react";
import { createPortal } from "react-dom";
import { ShieldCheck, FileText, Download, Trash2, CheckSquare, Eye, X as CloseIcon, ArrowLeft, Plus, Settings, Edit3, ArrowRight } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { Navigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useToast } from "@/contexts/ToastContext";
import { AuditService, type AuditDocument, type AuditCategory } from "@/entities/Audit";
import { LabService } from "@/entities/Lab";
import { cn } from "@/lib/utils";

export default function Quality() {
    const { user, currentLab, selectLab, deselectLab } = useAuth();
    const { addToast } = useToast();

    // Role check: Only admins or quality_admin
    if (user && !['admin_global', 'admin_lab', 'quality_admin'].includes(user.acesso)) {
        return <Navigate to="/" replace />;
    }



    // Audit State
    const [categories, setCategories] = useState<AuditCategory[]>([]);
    const [documents, setDocuments] = useState<AuditDocument[]>([]);
    const [isUploading, setIsUploading] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
    const [previewDoc, setPreviewDoc] = useState<AuditDocument | null>(null);

    // Category Management State
    const [isConfigMode, setIsConfigMode] = useState(false);
    const [editingCategory, setEditingCategory] = useState<Partial<AuditCategory> | null>(null);
    const [labs, setLabs] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        loadInitialData();
    }, [user, currentLab]);

    const loadInitialData = async () => {
        setIsLoading(true);

        // Safety timeout: If data takes too long (12s), force stop loading so user can at least try to interact
        const safetyTimer = setTimeout(() => {
            console.warn("Forcing load stop due to timeout");
            setIsLoading(false);
            addToast({ title: "Conexão lenta", description: "O carregamento demorou mais que o esperado.", type: "warning" });
        }, 12000);

        try {
            // 1. Load Labs (Critical for navigation)
            const labsData = await LabService.list().catch(e => {
                console.error("Failed to load labs:", e);
                addToast({ title: "Aviso: Falha ao carregar laboratórios", description: "Tente recarregar a página.", type: "warning" });
                return [];
            });
            setLabs(labsData);

            // 2. Load Audit Data (Can fail without blocking navigation)
            try {
                const targetLabId = currentLab?.id || user?.lab_id;
                const [docs, cats] = await Promise.all([
                    targetLabId ? AuditService.listByLab(targetLabId) : AuditService.list(),
                    AuditService.listCategories()
                ]);

                setDocuments(docs);
                setCategories(cats);
            } catch (auditError: any) {
                console.error("Audit data load error:", auditError);
                // Alert the user more specifically
                const msg = auditError.message || JSON.stringify(auditError);
                addToast({
                    title: "Erro ao carregar auditoria",
                    description: msg.substring(0, 100),
                    type: "error"
                });
            }

        } catch (error: any) {
            console.error("Critical error in Quality load:", error);
            addToast({
                title: "Erro de Carregamento",
                description: "Falha crítica ao inicializar módulo.",
                type: "error"
            });
        } finally {
            clearTimeout(safetyTimer);
            setIsLoading(false);
        }
    };



    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        const category = categories.find(c => c.id === selectedCategoryId);
        if (!file || !user || !category) return;

        const targetLabId = currentLab?.id || user?.lab_id;
        if (!targetLabId && user.acesso !== 'admin_global') {
            addToast({ title: "Erro: Laboratório não identificado", type: "error" });
            return;
        }

        setIsUploading(true);
        try {
            const reader = new FileReader();
            reader.onload = async (event) => {
                try {
                    const base64 = event.target?.result as string;

                    await AuditService.upload({
                        name: file.name.split('.')[0],
                        fileName: file.name,
                        fileSize: file.size,
                        fileType: file.type,
                        data: base64,
                        category: category.name,
                        analystName: user.nome,
                        labId: targetLabId || undefined
                    }, file);

                    addToast({ title: "Documento Anexado", type: "success" });
                    loadInitialData();
                } catch (err: any) {
                    console.error("Upload errored:", err);
                    addToast({ title: "Erro ao anexar: " + (err.message || 'Desconhecido'), type: "error" });
                } finally {
                    setIsUploading(false);
                }
            };
            reader.readAsDataURL(file);
        } catch (error) {
            addToast({ title: "Erro no Upload", type: "error" });
            setIsUploading(false);
        }
    };

    const handleDownload = async (doc: AuditDocument) => {
        try {
            let data = doc.data;
            // Se não tem dados ou parece ser um caminho relativo (storage path), busca URL assinada nova
            if (!data || (!data.startsWith('http') && !data.startsWith('data:'))) {
                console.log("DEBUG: Buscando URL assinada para download...", doc.fileName);
                const refreshed = await AuditService.getContent(doc.id);
                if (refreshed) data = refreshed;
            }

            if (!data) {
                addToast({ title: "Arquivo indisponível", description: "Não foi possível gerar o link de download.", type: "error" });
                return;
            }

            // Cria link temporário para download forçado
            const link = document.createElement('a');
            link.href = data;
            link.download = doc.fileName || 'documento';

            // Se for URL externa (Storage), abre em nova aba para garantir
            if (data.startsWith('http')) {
                link.target = '_blank';
                link.rel = 'noopener noreferrer';
            }

            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } catch (error) {
            console.error("Erro no download:", error);
            addToast({ title: "Erro ao baixar", type: "error" });
        }
    };

    const handlePreview = async (doc: AuditDocument) => {
        try {
            let data = doc.data;
            if (!data || (!data.startsWith('http') && !data.startsWith('data:'))) {
                const content = await AuditService.getContent(doc.id);
                if (content) data = content;
            }

            if (!data) {
                addToast({ title: "Erro ao carregar visualização", type: "error" });
                return;
            }

            setPreviewDoc({ ...doc, data: data });
        } catch (e) {
            console.error("Erro preview:", e);
            addToast({ title: "Erro ao abrir visualização", type: "error" });
        }
    };

    const handleDeleteDoc = async (id: string) => {
        if (confirm("Deseja remover este documento do checklist?")) {
            await AuditService.delete(id);
            addToast({ title: "Documento Removido", type: "info" });
            loadInitialData();
        }
    };

    // Category Methods
    const handleSaveCategory = async () => {
        if (!editingCategory?.name) {
            addToast({ title: "Nome da categoria obrigatório", type: "error" });
            return;
        }
        try {
            const targetLabId = currentLab?.id || user?.lab_id;
            const categoryToSave = {
                ...editingCategory,
                labId: targetLabId
            } as AuditCategory;

            await AuditService.saveCategory(categoryToSave);
            addToast({ title: "Categoria Salva", type: "success" });
            setEditingCategory(null);
            loadInitialData();
        } catch (error: any) {
            console.error("Failed to save category:", error);
            const errorMsg = error.message || "Erro desconhecido";
            // Alert in case toast is missed
            alert(`Erro ao salvar categoria: ${errorMsg}`);
            addToast({
                title: "Erro ao salvar categoria",
                description: errorMsg,
                type: "error"
            });
        }
    };

    const handleDeleteCategory = async (id: string) => {
        if (confirm("Remover esta categoria? Isso não excluirá os documentos já enviados, mas eles ficarão órfãos.")) {
            await AuditService.deleteCategory(id);
            addToast({ title: "Categoria Removida", type: "info" });
            loadInitialData();
        }
    };

    const getLabInfo = (labId?: string) => {
        if (!labId) return null;
        const lab = labs.find(l => l.id === labId);
        if (!lab) return null;
        return { name: lab.nome, city: lab.cidade };
    };

    // Lab Selection Screen for Global Admin (similar to Inicio.tsx)
    if (user?.acesso === 'admin_global' && !currentLab) {
        return (
            <div className="min-h-full flex flex-col items-center justify-center p-8 space-y-12 animate-fade-in">
                <div className="text-center space-y-6 max-w-2xl">
                    <div className="inline-flex items-center justify-center p-4 bg-black rounded-2xl mb-6 shadow-2xl">
                        <ShieldCheck className="h-12 w-12 text-white" />
                    </div>
                    <h1 className="text-5xl lg:text-6xl font-serif text-black leading-tight">
                        Selecione o Laboratório
                    </h1>
                    <p className="text-xl text-neutral-600 font-light">
                        Escolha um laboratório para visualizar e gerenciar seus documentos de qualidade e conformidade.
                    </p>
                </div>

                {isLoading ? (
                    <div className="animate-pulse flex gap-4">
                        <div className="h-48 w-64 bg-neutral-200 rounded-2xl"></div>
                        <div className="h-48 w-64 bg-neutral-200 rounded-2xl"></div>
                    </div>
                ) : labs.length === 0 ? (
                    <div className="text-center p-8 border-2 border-dashed border-neutral-300 rounded-2xl flex flex-col items-center">
                        <ShieldCheck className="h-12 w-12 text-neutral-300 mb-4" />
                        <p className="text-neutral-500 font-mono mb-6">Nenhum laboratório encontrado.</p>

                        <div className="flex gap-4">
                            <Button
                                onClick={() => loadInitialData()}
                                variant="outline"
                                className="border-black hover:bg-neutral-50"
                            >
                                <ArrowRight className="mr-2 h-4 w-4" />
                                Tentar Novamente
                            </Button>

                            <Button
                                onClick={() => window.location.href = '#/admin'}
                                variant="destructive"
                                className="bg-black hover:bg-neutral-800 text-white"
                            >
                                <Settings className="mr-2 h-4 w-4" />
                                Gerenciar Labs
                            </Button>
                        </div>

                        <div className="mt-8 p-4 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200 max-w-md">
                            Verifique se existem laboratórios cadastrados no módulo Admin e se sua conexão com o banco de dados está ativa.
                        </div>
                    </div>
                ) : (
                    <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 w-full max-w-5xl">
                        {labs.map((lab) => {
                            const labDocs = documents.filter(d => d.labId === lab.id);
                            const docCount = labDocs.length;

                            return (
                                <button
                                    key={lab.id}
                                    onClick={() => selectLab(lab.id)}
                                    className="group relative flex flex-col p-8 bg-white border-2 border-neutral-200 hover:border-black rounded-2xl transition-all duration-300 text-left hover:shadow-xl hover:-translate-y-1"
                                >
                                    <div className="absolute top-6 right-6 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <ArrowRight className="h-6 w-6 text-black" />
                                    </div>
                                    <div className="h-12 w-12 bg-neutral-100 rounded-xl flex items-center justify-center mb-6 group-hover:bg-black group-hover:text-white transition-colors">
                                        <ShieldCheck className="h-6 w-6" />
                                    </div>
                                    <h3 className="text-2xl font-serif text-black mb-2">{lab.nome}</h3>
                                    <p className="text-sm font-mono text-neutral-500 uppercase tracking-wider mb-4">
                                        {lab.cidade || 'N/A'} - {lab.estado || 'N/A'}
                                    </p>
                                    <div className="mt-auto pt-6 border-t border-neutral-100 w-full flex justify-between items-center">
                                        <span className="text-xs font-bold uppercase tracking-widest text-neutral-400 group-hover:text-black">
                                            {docCount} Documento{docCount !== 1 ? 's' : ''}
                                        </span>
                                        <span className="text-xs font-mono text-neutral-300 group-hover:text-black">
                                            {lab.codigo}
                                        </span>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                )}
            </div>
        );
    }

    const currentCategory = categories.find(c => c.id === selectedCategoryId);
    const categoryDocs = documents.filter(d => d.category === currentCategory?.name);

    return (
        <div className="space-y-12 animate-fade-in text-black pb-24">
            {/* Header Section */}
            <div className="border-b border-black pb-8">
                <div className="flex flex-col md:flex-row items-end justify-between gap-8">
                    <div className="space-y-2">
                        <div className="flex items-center gap-4">
                            {(selectedCategoryId || isConfigMode) && (
                                <button
                                    onClick={() => { setSelectedCategoryId(null); setIsConfigMode(false); }}
                                    className="h-10 w-10 border border-neutral-200 flex items-center justify-center hover:border-black transition-colors"
                                >
                                    <ArrowLeft className="h-4 w-4" />
                                </button>
                            )}
                            <div>
                                <span className="text-[10px] uppercase tracking-[0.25em] text-neutral-500 font-mono block">
                                    {isConfigMode ? "Configurações do Checklist" : selectedCategoryId ? "Categoria Detalhada" : "Quality Assurance & Compliance"}
                                </span>
                                {currentLab && <span className="text-[9px] font-bold text-black uppercase tracking-widest bg-neutral-100 px-2 py-0.5 rounded-sm">{currentLab.nome}</span>}
                            </div>
                        </div>
                        <h1 className="text-4xl font-serif text-black leading-none mt-1">
                            {isConfigMode ? "Gerenciar Categorias" : selectedCategoryId ? currentCategory?.name : "Checklist de Auditoria"}
                        </h1>
                    </div >

                    <div className="flex items-center gap-4">
                        {/* Exit Lab Button for Global Admin */}
                        {user?.acesso === 'admin_global' && currentLab && (
                            <Button
                                onClick={() => deselectLab()}
                                variant="outline"
                                className="h-12 px-6 font-bold text-[10px] uppercase tracking-widest rounded-none border-black hover:bg-black hover:text-white transition-colors"
                            >
                                <ArrowLeft className="mr-2 h-4 w-4" />
                                Trocar Laboratório
                            </Button>
                        )}

                        {!selectedCategoryId && !isConfigMode && (
                            <Button
                                onClick={() => setIsConfigMode(true)}
                                variant="outline"
                                className="h-12 border-black rounded-none text-[10px] font-bold uppercase tracking-widest px-8"
                            >
                                <Settings className="mr-2 h-4 w-4" />
                                Configurar
                            </Button>
                        )}

                        {selectedCategoryId && (
                            <div className="flex flex-col gap-4">
                                <Button
                                    onClick={() => fileInputRef.current?.click()}
                                    disabled={isUploading}
                                    className="h-12 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] font-bold uppercase tracking-widest px-8"
                                >
                                    <Plus className="mr-2 h-4 w-4" />
                                    {isUploading ? "ANEXANDO..." : "ADICIONAR DOCUMENTO"}
                                </Button>
                                <input
                                    type="file"
                                    ref={fileInputRef}
                                    onChange={handleFileUpload}
                                    className="hidden"
                                    accept=".pdf,.doc,.docx,.jpg,.png,.xlsx,.xls,.pptx,.csv"
                                />
                            </div>
                        )}

                        {isConfigMode && (
                            <Button
                                onClick={() => setEditingCategory({ id: '', name: '', description: '' })}
                                className="h-12 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] font-bold uppercase tracking-widest px-8"
                            >
                                <Plus className="mr-2 h-4 w-4" />
                                Nova Categoria
                            </Button>
                        )}
                    </div>
                </div >
            </div >

            {/* Content Area */}
            {
                isConfigMode ? (
                    /* CONFIG MODE: List categories for editing */
                    <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                        {categories.map((cat) => (
                            <div key={cat.id} className="p-8 border border-neutral-200 bg-white flex flex-col justify-between h-64">
                                <div>
                                    <div className="flex justify-between items-start mb-4">
                                        <h3 className="text-xl font-serif">{cat.name}</h3>
                                        <div className="flex gap-2">
                                            <button
                                                onClick={() => setEditingCategory(cat)}
                                                className="h-8 w-8 border border-neutral-100 flex items-center justify-center hover:border-black transition-colors"
                                            >
                                                <Edit3 className="h-4 w-4" />
                                            </button>
                                            <button
                                                onClick={() => handleDeleteCategory(cat.id)}
                                                className="h-8 w-8 border border-neutral-100 flex items-center justify-center hover:text-red-600 hover:border-red-600 transition-colors"
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </button>
                                        </div>
                                    </div>
                                    <p className="text-[10px] uppercase tracking-wider text-neutral-400 leading-relaxed truncate-2-lines">
                                        {cat.description}
                                    </p>
                                </div>
                                <div className="text-[9px] font-mono text-neutral-300 mt-4">
                                    ID: {cat.id}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : !selectedCategoryId ? (
                    /* DASHBOARD VIEW: Category Cards */
                    <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                        {categories.map((cat) => {
                            const count = documents.filter(d => d.category === cat.name).length;
                            const isComplete = count > 0;

                            return (
                                <button
                                    key={cat.id}
                                    onClick={() => setSelectedCategoryId(cat.id)}
                                    className="group text-left flex flex-col h-64 border border-neutral-200 bg-white hover:border-black transition-all p-8 relative"
                                >
                                    <div className="flex justify-between items-start mb-4">
                                        <div className={cn(
                                            "h-10 w-10 border flex items-center justify-center transition-colors",
                                            isComplete ? "bg-black border-black text-white" : "border-neutral-200 text-neutral-300"
                                        )}>
                                            <CheckSquare className="h-5 w-5" />
                                        </div>
                                        <span className="text-[10px] font-mono font-bold text-neutral-400 group-hover:text-black transition-colors">
                                            {count.toString().padStart(2, '0')} DOCS
                                        </span>
                                    </div>
                                    <div className="mt-auto">
                                        <h3 className="text-xl font-serif mb-2">{cat.name}</h3>
                                        <p className="text-[10px] uppercase tracking-wider text-neutral-400 leading-relaxed max-w-[80%]">
                                            {cat.description}
                                        </p>
                                    </div>
                                    <div className="absolute bottom-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Plus className="h-4 w-4" />
                                    </div>
                                </button>
                            );
                        })}

                        {categories.length === 0 && (
                            <div className="col-span-full py-32 border border-dashed border-neutral-100 flex flex-col items-center justify-center text-center">
                                <h3 className="text-lg font-serif mb-2">Checklist Vazio</h3>
                                <p className="text-[10px] uppercase tracking-widest text-neutral-400 mb-8">Nenhuma categoria cadastrada</p>
                                <Button onClick={() => setIsConfigMode(true)} variant="outline" className="border-black rounded-none">
                                    <Settings className="mr-2 h-4 w-4" /> Configurar Checklist
                                </Button>
                            </div>
                        )}
                    </div>
                ) : (
                    /* DETAIL VIEW: Document Grid */
                    <div className="space-y-8 animate-fade-in-up">
                        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                            {categoryDocs.map((doc) => (
                                <div key={doc.id} className="group/card flex flex-col border border-neutral-200 bg-white hover:border-black transition-all h-full animate-fade-in">
                                    <div className="aspect-[4/3] bg-neutral-50 border-b border-neutral-100 relative overflow-hidden flex items-center justify-center group-hover/card:bg-white transition-colors">
                                        {doc.fileType.startsWith('image/') ? (
                                            <img src={doc.data} alt={doc.fileName} className="w-full h-full object-cover opacity-80 group-hover/card:opacity-100 transition-opacity" />
                                        ) : (
                                            <div className="flex flex-col items-center gap-2">
                                                <FileText className="h-10 w-10 text-neutral-300" />
                                                <span className="text-[9px] font-mono text-neutral-400 uppercase">{doc.fileType.split('/')[1] || 'FILE'}</span>
                                            </div>
                                        )}
                                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/card:opacity-100 transition-opacity flex items-center justify-center">
                                            <button onClick={() => handlePreview(doc)} className="h-10 w-10 bg-white flex items-center justify-center hover:bg-neutral-100 transition-colors">
                                                <Eye className="h-5 w-5 text-black" />
                                            </button>
                                        </div>
                                    </div>
                                    <div className="p-4 flex-1 flex flex-col justify-between">
                                        <div className="space-y-1 mb-4">
                                            <p className="text-xs font-bold uppercase tracking-wider truncate mb-1">{doc.fileName}</p>
                                            <div className="flex items-center justify-between">
                                                <span className="text-[9px] text-neutral-400 font-mono">{(doc.fileSize / 1024).toFixed(1)} KB</span>
                                                <span className="text-[9px] text-neutral-400 font-mono italic">{new Date(doc.uploadDate).toLocaleDateString()}</span>
                                            </div>
                                            {/* Lab/City Info Badge */}
                                            {doc.labId && (() => {
                                                const labInfo = getLabInfo(doc.labId);
                                                return labInfo ? (
                                                    <div className="mt-2 pt-2 border-t border-neutral-100">
                                                        <span className="text-[8px] font-mono font-bold text-black uppercase tracking-widest bg-neutral-100 px-2 py-1 rounded-sm inline-block">
                                                            📍 {labInfo.name} - {labInfo.city}
                                                        </span>
                                                    </div>
                                                ) : null;
                                            })()}
                                        </div>
                                        <div className="flex items-center gap-2 pt-4 border-t border-neutral-100">
                                            <button onClick={() => handleDownload(doc)} className="flex-1 flex items-center justify-center py-2 border border-black hover:bg-black hover:text-white transition-colors text-[9px] font-bold uppercase tracking-widest">
                                                <Download className="mr-2 h-3 w-3" /> DOWNLOAD
                                            </button>
                                            <button onClick={() => handleDeleteDoc(doc.id)} className="p-2 text-neutral-300 hover:text-red-600 transition-colors">
                                                <Trash2 className="h-4 w-4" />
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}

                            {categoryDocs.length === 0 && (
                                <div className="col-span-full py-24 border border-dashed border-neutral-100 flex flex-col items-center justify-center text-center">
                                    <FileText className="h-12 w-12 text-neutral-100 mb-4" />
                                    <p className="text-[10px] uppercase tracking-[0.2em] text-neutral-300 font-bold max-w-xs">
                                        Nenhum documento anexado para esta categoria ainda.
                                    </p>
                                </div>
                            )}
                        </div>
                    </div>
                )
            }

            {/* Global Summary Status (Only on Main Dashboard) */}
            {
                !selectedCategoryId && !isConfigMode && (
                    <div className="border border-black p-8 bg-black text-white flex flex-col md:flex-row items-center justify-between gap-8 animate-fade-in">
                        <div className="flex-1 flex flex-col md:flex-row items-center gap-8">
                            <div className="h-12 w-12 border border-white/20 flex items-center justify-center shrink-0">
                                <ShieldCheck className="h-6 w-6" />
                            </div>
                            <div className="flex-1 w-full space-y-4">
                                <div className="flex items-end justify-between">
                                    <div>
                                        <p className="text-[10px] uppercase font-bold tracking-[0.2em] text-neutral-400 mb-1">Progresso de Conformidade</p>
                                        <h4 className="text-xl font-serif">
                                            {categories.filter(cat => documents.some(d => d.category === cat.name)).length} de {categories.length} Categorias Atendidas
                                        </h4>
                                    </div>
                                    <div className="text-right">
                                        <span className="text-3xl font-serif leading-none italic">
                                            {categories.length > 0 ? Math.round((categories.filter(cat => documents.some(d => d.category === cat.name)).length / categories.length) * 100) : 0}%
                                        </span>
                                    </div>
                                </div>

                                <div className="h-[2px] w-full bg-white/10 overflow-hidden relative">
                                    <div
                                        className="absolute inset-y-0 left-0 bg-white transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(255,255,255,0.5)]"
                                        style={{ width: `${categories.length > 0 ? (categories.filter(cat => documents.some(d => d.category === cat.name)).length / categories.length) * 100 : 0}%` }}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="shrink-0 text-right hidden md:block border-l border-white/10 pl-8">
                            <p className="text-[9px] font-mono text-neutral-500 uppercase">Status da Sessão</p>
                            <p className="text-xs font-bold uppercase tracking-widest text-emerald-400">Ambiente Criptografado</p>
                        </div>
                    </div>
                )
            }

            {/* MODAL: Edit Category */}
            {
                editingCategory && createPortal(
                    <div className="fixed inset-0 z-[120] bg-black/80 backdrop-blur-sm flex items-center justify-center p-8 animate-fade-in">
                        <div className="bg-white w-full max-w-lg border border-black p-10 space-y-8 animate-fade-in-up">
                            <div className="space-y-2">
                                <span className="text-[10px] uppercase tracking-widest text-neutral-400 font-mono">Editor de Checklist</span>
                                <h3 className="text-2xl font-serif">{editingCategory.id ? "Editar Categoria" : "Nova Categoria"}</h3>
                            </div>

                            <div className="space-y-6">
                                <div className="space-y-2">
                                    <label className="text-[9px] uppercase font-bold tracking-widest">Nome da Categoria</label>
                                    <Input
                                        value={editingCategory.name || ''}
                                        onChange={(e) => setEditingCategory({ ...editingCategory, name: e.target.value })}
                                        placeholder="Ex: Certificados de Calibração"
                                        className="h-12 border-b border-black rounded-none bg-transparent placeholder:text-neutral-200 focus:border-black focus:ring-0"
                                    />
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[9px] uppercase font-bold tracking-widest">Descrição / Observações</label>
                                    <Input
                                        value={editingCategory.description || ''}
                                        onChange={(e) => setEditingCategory({ ...editingCategory, description: e.target.value })}
                                        placeholder="Breve descrição dos requisitos..."
                                        className="h-12 border-b border-black rounded-none bg-transparent placeholder:text-neutral-200 focus:border-black focus:ring-0"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-4 pt-4">
                                <Button
                                    onClick={() => setEditingCategory(null)}
                                    variant="outline"
                                    className="flex-1 h-12 border-black rounded-none text-[10px] font-bold uppercase tracking-widest"
                                >
                                    Cancelar
                                </Button>
                                <Button
                                    onClick={handleSaveCategory}
                                    className="flex-1 h-12 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] font-bold uppercase tracking-widest"
                                >
                                    Salvar Categoria
                                </Button>
                            </div>
                        </div>
                    </div>,
                    document.body
                )
            }

            {/* MODAL: Preview Document */}
            {
                previewDoc && createPortal(
                    <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-sm flex items-center justify-center p-8 animate-fade-in">
                        <div className="bg-white w-full max-w-5xl h-full max-h-[90vh] flex flex-col relative">
                            <div className="p-4 border-b border-neutral-100 flex items-center justify-between">
                                <h3 className="text-sm font-bold uppercase tracking-widest">{previewDoc.fileName}</h3>
                                <button
                                    onClick={() => setPreviewDoc(null)}
                                    className="h-10 w-10 flex items-center justify-center hover:bg-neutral-50"
                                >
                                    <CloseIcon className="h-5 w-5" />
                                </button>
                            </div>
                            <div className="flex-1 bg-neutral-100 overflow-auto flex items-center justify-center p-4">
                                {previewDoc.fileType.startsWith('image/') ? (
                                    <img src={previewDoc.data || ''} className="max-w-full max-h-full object-contain shadow-2xl" />
                                ) : previewDoc.fileType === 'application/pdf' ? (
                                    <iframe src={previewDoc.data || ''} className="w-full h-full border-none" title="PDF Preview" />
                                ) : (
                                    <div className="text-center p-20 bg-white border border-neutral-200">
                                        <FileText className="h-16 w-16 text-neutral-200 mx-auto mb-4" />
                                        <p className="text-sm font-serif">Visualização não disponível para este tipo de arquivo.</p>
                                        <p className="text-[10px] text-neutral-400 font-mono mt-2 uppercase">Use o botão de download para visualizar conteúdo completo</p>
                                    </div>
                                )}
                            </div>
                            <div className="p-4 border-t border-neutral-100 flex justify-end">
                                <Button
                                    onClick={() => handleDownload(previewDoc)}
                                    className="h-12 bg-black text-white hover:bg-neutral-800 rounded-none text-[10px] font-bold uppercase tracking-[0.2em] px-10"
                                >
                                    <Download className="mr-2 h-4 w-4" /> Baixar Documento
                                </Button>
                            </div>
                        </div>
                    </div>,
                    document.body
                )
            }
        </div >
    );
}

import { useState, useEffect } from "react";
import { createPortal } from "react-dom";
import { useSearchParams, useNavigate } from "react-router-dom";
import {
    ArrowLeft,
    Trash2,
    Database,
    ArrowRight,
    Activity,
    FileDown
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import HVIUpload from "@/components/registro/HVIUpload";
import type { Lote } from "@/entities/Lote";
import { LoteService } from "@/entities/Lote";
import type { Sample } from "@/entities/Sample";
import { SampleService } from "@/entities/Sample";
import { OCRExtractionService, formatDecimalBR, type ExtractionResult, type HVIDataRow } from "@/services/ocrExtraction";
import { useToast } from "@/contexts/ToastContext";
import { useAuth } from "@/contexts/AuthContext";
import { AnalistaService } from "@/entities/Analista";
import { Modal } from "@/components/shared/Modal";
import { HVIFileGeneratorService } from "@/services/HVIFileGeneratorService";
import { cn } from "@/lib/utils";

const classifySample = (row: HVIDataRow): string => {
    const { mic, len, str } = row;

    // Critérios Premium (Verde)
    const isMicOk = mic >= 3.8 && mic <= 4.5;
    const isLenOk = len >= 1.12;
    const isStrOk = str >= 29;

    if (isMicOk && isLenOk && isStrOk) return "#10b981"; // Green (Premium)

    // Critérios Regular (Amarelo)
    const isMicRegular = (mic >= 3.5 && mic < 3.8) || (mic > 4.5 && mic <= 4.9);
    const isLenRegular = len >= 1.08;
    const isStrRegular = str >= 27;

    if (isMicRegular || (isLenRegular && isStrRegular)) return "#f59e0b"; // Yellow (Regular)

    // Fora dos padrões (Vermelho)
    return "#ef4444";
};

type PendingConfirmation = {
    file: File;
    previewUrl: string;
    data: ExtractionResult;
};

export default function Registro() {
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const { addToast } = useToast();
    const loteId = searchParams.get("loteId");

    const [lote, setLote] = useState<Lote | null>(null);
    const [samples, setSamples] = useState<Sample[]>([]);

    // States for the review flow
    // States for the review flow
    const [isProcessing, setIsProcessing] = useState(false); // Processamento bloqueante (foreground)
    const [isBackgroundProcessing, setIsBackgroundProcessing] = useState(false); // Processamento em background
    const [ocrProgress, setOcrProgress] = useState(0);
    const [processingStatus, setProcessingStatus] = useState("");

    const [uploadQueue, setUploadQueue] = useState<File[]>([]); // Arquivos aguardando
    const [processedQueue, setProcessedQueue] = useState<PendingConfirmation[]>([]); // Arquivos prontos para revisão

    // Item sendo revisado atualmente
    const [pendingReview, setPendingReview] = useState<PendingConfirmation | null>(null);

    // Efeito para processar filas em background enquanto o usuário trabalha
    useEffect(() => {
        const processNextInBackground = async () => {
            if (uploadQueue.length === 0 || isBackgroundProcessing || isProcessing) return;

            // Só processa em background se ainda tivermos trabalho pela frente
            // e não tivermos acumulado muitos processados (para economizar memória)
            if (processedQueue.length > 5) return;

            setIsBackgroundProcessing(true);
            const nextFile = uploadQueue[0];

            try {
                // Remove da fila de upload imediatamente para evitar duplicidade
                setUploadQueue(prev => prev.slice(1));

                const data = await OCRExtractionService.extractFromImage(nextFile, () => { }); // Progresso ignorado no background
                const previewUrl = URL.createObjectURL(nextFile);

                setProcessedQueue(prev => [...prev, { file: nextFile, previewUrl, data }]);
            } catch (error) {
                console.error("Erro no processamento background", error);
                // Se der erro, descartamos silenciosamente
            } finally {
                setIsBackgroundProcessing(false);
            }
        };

        const timer = setTimeout(processNextInBackground, 500); // Debounce
        return () => clearTimeout(timer);
    }, [uploadQueue, isBackgroundProcessing, isProcessing, processedQueue.length]);


    // Função que assume um item para revisão (seja da fila processada ou processando na hora)
    const loadNextForReview = async (item?: PendingConfirmation) => {
        let reviewItem = item;

        // Se não passou item, tenta pegar da fila de processados
        if (!reviewItem && processedQueue.length > 0) {
            reviewItem = processedQueue[0];
            setProcessedQueue(prev => prev.slice(1));
        }

        // Se ainda não tem item, mas tem na fila de upload (caso background não tenha terminado)
        // Processamos com prioridade (foreground)
        if (!reviewItem && uploadQueue.length > 0) {
            const nextFile = uploadQueue[0];
            setUploadQueue(prev => prev.slice(1));

            setIsProcessing(true);
            setOcrProgress(0);
            setProcessingStatus("Processando próxima imagem...");

            try {
                const data = await OCRExtractionService.extractFromImage(nextFile, (p) => setOcrProgress(p));
                const previewUrl = URL.createObjectURL(nextFile);
                reviewItem = { file: nextFile, previewUrl, data };
            } catch (error) {
                console.error(error);
                addToast({ title: "Erro no OCR", description: "Falha ao processar imagem.", type: "error" });
                setIsProcessing(false);
                setProcessingStatus("");
                return; // Aborta
            } finally {
                setIsProcessing(false);
                setProcessingStatus("");
            }
        }

        if (reviewItem) {
            // Setup do review
            setPendingReview(reviewItem);
            setEditingMala(reviewItem.data.mala || '');
            setEditingEtiqueta(reviewItem.data.etiqueta || '');

            setEditingRows(reviewItem.data.rows.length > 0 ? [...reviewItem.data.rows] : [{
                numero: '1', hvi: '1', data_analise: new Date().toLocaleDateString('pt-BR'), hora_analise: new Date().toLocaleTimeString('pt-BR'),
                mic: 0, len: 0, unf: 0, str: 0, rd: 0, b: 0
            }]);
            setCurrentRowIndex(0);
            setSelectedRows(new Set(reviewItem.data.rows.length > 0 ? reviewItem.data.rows.map((_, i) => i) : [0]));

            addToast({
                title: "Imagem Carregada",
                description: reviewItem.data.rows.length > 0 ? `${reviewItem.data.rows.length} registros.` : "Sem dados automáticos.",
                type: "success"
            });
        }
    };

    const handleUpload = async (files: File[]) => {
        if (!loteId || files.length === 0) return;

        // Se não tiver nada sendo revisado, o primeiro arquivo vai direto para review (caminho rápido)
        // O resto vai para a fila de upload para ser pego pelo background
        if (!pendingReview && processedQueue.length === 0 && uploadQueue.length === 0) {
            const [first, ...rest] = files;
            setUploadQueue(rest); // Fila para background

            // Processa o primeiro imediatamente
            setIsProcessing(true);
            setOcrProgress(0);
            try {
                const data = await OCRExtractionService.extractFromImage(first, p => setOcrProgress(p));
                const previewUrl = URL.createObjectURL(first);
                loadNextForReview({ file: first, previewUrl, data });
            } catch (e) {
                console.error(e);
            } finally {
                setIsProcessing(false);
            }
        } else {
            // Se já tem coisa rolando, joga tudo na fila
            setUploadQueue(prev => [...prev, ...files]);
            addToast({ title: "Adicionado à Fila", description: `${files.length} imagens adicionadas.`, type: "info" });
        }
    };

    // Nova estrutura para edição de múltiplas linhas
    const [editingMala, setEditingMala] = useState('');
    const [editingEtiqueta, setEditingEtiqueta] = useState('');
    const [editingRows, setEditingRows] = useState<HVIDataRow[]>([]);
    const [currentRowIndex, setCurrentRowIndex] = useState(0);
    const [selectedRows, setSelectedRows] = useState<Set<number>>(new Set());

    // Modal Confirmation State
    const [modalAction, setModalAction] = useState<{ type: 'delete', id?: string } | null>(null);

    // Core Hooks
    const { user } = useAuth();

    // Presence Logic
    const [coWorkers, setCoWorkers] = useState<any[]>([]);
    useEffect(() => {
        const checkPresence = async () => {
            const all = await AnalistaService.list();
            const now = new Date().getTime();
            const others = all.filter(a =>
                a.id !== user?.id &&
                a.current_lote_id === loteId &&
                a.last_active && (now - new Date(a.last_active).getTime() < 15000)
            );
            setCoWorkers(others);
        };
        const interval = setInterval(checkPresence, 3000);
        checkPresence();
        return () => clearInterval(interval);
    }, [loteId, user?.id]);

    useEffect(() => {
        if (loteId) {
            loadData();

            // Subscribe to real-time changes for samples
            const unsubSamples = SampleService.subscribe(() => {
                loadData();
            });
            const unsubLotes = LoteService.subscribe(() => {
                loadData();
            });

            return () => {
                unsubSamples();
                unsubLotes();
            };
        }
    }, [loteId, user]);



    const loadData = async () => {
        if (!loteId) return;
        const l = await LoteService.get(loteId);

        if (l) {
            // Security Check
            if (user?.acesso !== 'admin_global' && user?.lab_id && l.lab_id && l.lab_id !== user.lab_id) {
                addToast({ title: "Access Denied", description: "You cannot manage samples for other laboratories.", type: "error" });
                navigate("/");
                return;
            }
            setLote(l);
        }

        const s = await SampleService.listByLote(loteId);
        setSamples(s);
    };

    const handleDeleteSample = async (sampleId: string) => {
        try {
            await SampleService.delete(sampleId);
            addToast({ title: "Registro Removido", type: "info" });
            setModalAction(null);
            loadData();
        } catch (error) {
            addToast({ title: "Erro ao Remover", type: "error" });
        }
    };

    const handleExportHVI = async (sample: Sample) => {
        const result = await HVIFileGeneratorService.generateFileForSample(sample);
        addToast({
            title: result.success ? "Arquivo HVI Gerado" : "Erro",
            description: result.message,
            type: result.success ? "success" : "error"
        });
    };



    const updateCurrentRow = (field: keyof HVIDataRow, value: string | number) => {
        setEditingRows(rows => {
            const updated = [...rows];
            updated[currentRowIndex] = { ...updated[currentRowIndex], [field]: value };
            return updated;
        });
    };

    const handleSaveSelectedSamples = async () => {
        if (!loteId || !pendingReview || selectedRows.size === 0) return;

        try {
            let savedCount = 0;
            const rowsToSave = editingRows.filter((_, index) => selectedRows.has(index));

            for (const row of rowsToSave) {
                if (samples.length + savedCount >= 28) {
                    addToast({ title: "Limite Atingido", description: "Máximo de 28 amostras por lote.", type: "warning" });
                    break;
                }

                const nextId = (samples.length + savedCount + 1).toString().padStart(2, '0');
                await SampleService.create({
                    lote_id: loteId,
                    amostra_id: nextId,
                    hvi: row.hvi, // Número da máquina HVI
                    mala: editingMala,
                    etiqueta: editingEtiqueta,
                    data_analise: row.data_analise,
                    hora_analise: row.hora_analise,
                    mic: row.mic,
                    len: row.len,
                    unf: row.unf,
                    str: row.str,
                    rd: row.rd,
                    b: row.b,
                    cor: classifySample(row), // Auto-classificação precisa
                    historico_modificacoes: []
                });
                savedCount++;
            }

            addToast({ title: "Amostras Salvas", description: `${savedCount} registro(s) adicionado(s).`, type: "success" });
            URL.revokeObjectURL(pendingReview.previewUrl);
            setPendingReview(null);
            setEditingRows([]);
            setEditingMala('');
            setEditingEtiqueta('');
            setSelectedRows(new Set());
            await loadData();

            // Carrega próximo
            loadNextForReview();
        } catch (error) {
            addToast({ title: "Erro ao Salvar", type: "error" });
        }
    };

    const handleAbortReview = () => {
        if (pendingReview) {
            URL.revokeObjectURL(pendingReview.previewUrl);
        }
        setPendingReview(null);
        setEditingRows([]);
        setEditingMala('');
        setEditingEtiqueta('');
        setSelectedRows(new Set());

        // Carrega próximo
        loadNextForReview();
    };

    if (!loteId) return <div className="p-4 text-center font-black text-slate-300 uppercase tracking-widest text-[8px]">ID_LOTE_MISSING</div>;
    if (!lote) return <div className="p-4 text-center animate-pulse text-slate-400 font-bold uppercase tracking-widest text-[8px]">Carregando...</div>;

    // --- SIDE-BY-SIDE CONFIRMATION VIEW ---
    if (pendingReview && editingRows.length > 0) {
        const currentRow = editingRows[currentRowIndex];
        // Safety check to prevent crashes if index is out of bounds
        if (!currentRow) {
            console.error("Critical Error: Current row index out of bounds", currentRowIndex, editingRows.length);
            // Attempt recovery
            if (editingRows.length > 0) {
                setCurrentRowIndex(0);
                return null;
            } else {
                setPendingReview(null);
                return null;
            }
        }

        return createPortal(

            <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
                <div className="w-full max-w-6xl h-full lg:h-[85vh] max-h-screen bg-white flex flex-col lg:flex-row shadow-2xl border border-black overflow-hidden relative">

                    {/* Header Controls */}
                    <div className="absolute top-0 left-0 right-0 h-16 bg-white border-b border-black flex items-center justify-between px-8 z-20">
                        <div className="flex items-center gap-6">
                            <Button variant="ghost" size="icon" onClick={handleAbortReview} className="hover:bg-neutral-100 rounded-none h-10 w-10 border border-neutral-200">
                                <ArrowLeft className="h-4 w-4" />
                            </Button>
                            <div>
                                <h3 className="text-sm font-bold uppercase tracking-widest text-black">Verification Console</h3>
                                <p className="text-[10px] font-mono text-neutral-400 uppercase">Reviewing Digitized Data</p>
                            </div>
                        </div>
                        <div className="flex items-center gap-4">
                            <div className="flex items-center gap-3 px-4 border-r border-neutral-200">
                                <div className="text-right">
                                    <p className="text-[9px] font-bold uppercase tracking-widest text-neutral-400">Current Sample</p>
                                    <p className="text-xs font-mono font-bold">{currentRowIndex + 1} <span className="text-neutral-300">/</span> {editingRows.length}</p>
                                </div>
                            </div>
                            <Button onClick={handleSaveSelectedSamples} className="h-10 rounded-none bg-black text-white hover:bg-neutral-800 text-[10px] uppercase tracking-widest px-8 font-bold shadow-lg transition-all hover:scale-105">
                                Confirm & Save to Database
                            </Button>
                        </div>
                    </div>

                    {/* Left: Image Viewer Area */}
                    <div className="w-full lg:w-1/2 h-[40vh] lg:h-auto bg-neutral-100 border-b lg:border-b-0 lg:border-r border-black pt-16 flex flex-col relative group shrink-0">
                        <div className="absolute top-20 left-6 z-10 flex gap-2">
                            <div className="bg-black text-white text-[9px] uppercase tracking-widest px-3 py-1 font-bold shadow-sm">
                                Original Source
                            </div>
                        </div>

                        <div className="flex-1 overflow-auto p-6 lg:p-12 flex items-center justify-center">
                            <img
                                src={pendingReview.previewUrl}
                                alt="Source"
                                className="max-w-full max-h-full object-contain shadow-2xl border-4 border-white transition-transform duration-300 group-hover:scale-[1.02]"
                            />
                        </div>

                        {/* Filmstrip Navigation */}
                        {editingRows.length > 1 && (
                            <div className="h-16 lg:h-24 bg-white border-t border-black p-0 flex divide-x divide-black overflow-x-auto items-center shrink-0">
                                {editingRows.map((row, idx) => (
                                    <button
                                        key={idx}
                                        onClick={() => setCurrentRowIndex(idx)}
                                        className={cn(
                                            "h-full min-w-[60px] lg:min-w-[80px] flex flex-col items-center justify-center transition-all px-2 relative group-hover/strip:opacity-50 hover:!opacity-100",
                                            currentRowIndex === idx
                                                ? "bg-black text-white"
                                                : "bg-white text-black hover:bg-neutral-50"
                                        )}
                                    >
                                        <span className="text-[8px] lg:text-[10px] font-bold uppercase mb-1">Sample</span>
                                        <span className="font-mono text-lg lg:text-xl font-bold">#{row.numero}</span>
                                        {currentRowIndex === idx && (
                                            <div className="absolute bottom-2 w-1 h-1 bg-white rounded-full" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Right: Data Editor Form */}
                    <div className="w-full lg:w-1/2 bg-white lg:pt-16 overflow-y-auto flex-1 h-auto">
                        <div className="p-10 space-y-10">

                            {/* Section: Identifiers */}
                            <div className="space-y-6 animate-slide-up" style={{ animationDelay: '100ms' }}>
                                <div className="flex items-center gap-3 border-b-2 border-black pb-3">
                                    <div className="h-2 w-2 bg-blue-600 rounded-full animate-pulse" />
                                    <h3 className="text-sm font-bold uppercase tracking-[0.2em]">Identification</h3>
                                </div>

                                <div className="grid grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest">Bag ID</label>
                                        <Input
                                            value={editingMala}
                                            onChange={(e) => setEditingMala(e.target.value)}
                                            className="h-12 border-b-2 border-l-0 border-r-0 border-t-0 border-neutral-200 rounded-none font-mono text-lg bg-transparent px-0 focus:border-black focus:ring-0 placeholder:text-neutral-200"
                                            placeholder="UNIDENTIFIED"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest">Tag Reference</label>
                                        <Input
                                            value={editingEtiqueta}
                                            onChange={(e) => setEditingEtiqueta(e.target.value)}
                                            className="h-12 border-b-2 border-l-0 border-r-0 border-t-0 border-neutral-200 rounded-none font-mono text-lg bg-transparent px-0 focus:border-black focus:ring-0 placeholder:text-neutral-200"
                                            placeholder="NO TAG"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Section: Metrics */}
                            <div className="space-y-6 animate-slide-up" style={{ animationDelay: '200ms' }}>
                                <div className="flex items-center gap-3 border-b border-neutral-200 pb-3">
                                    <Activity className="h-4 w-4 text-neutral-400" />
                                    <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-neutral-500">Fiber Metrics</h3>
                                </div>
                                <div className="grid grid-cols-2 gap-x-8 gap-y-6">
                                    {[
                                        { label: "Micronaire", short: "MIC", key: "mic" as keyof HVIDataRow, decimals: 2 },
                                        { label: "Length", short: "LEN", key: "len" as keyof HVIDataRow, decimals: 2 },
                                        { label: "Uniformity", short: "UNF", key: "unf" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Strength", short: "STR", key: "str" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Reflectance", short: "RD", key: "rd" as keyof HVIDataRow, decimals: 1 },
                                        { label: "Yellowness", short: "+b", key: "b" as keyof HVIDataRow, decimals: 1 }
                                    ].map((field) => (
                                        <div key={field.key} className="flex items-center justify-between group">
                                            <div className="space-y-0.5">
                                                <label className="text-[9px] font-bold text-neutral-400 uppercase tracking-widest block group-hover:text-black transition-colors">{field.short}</label>
                                                <span className="text-[8px] font-mono text-neutral-300 uppercase">{field.label}</span>
                                            </div>
                                            <Input
                                                key={`${currentRowIndex}-${field.key}`}
                                                defaultValue={formatDecimalBR(currentRow[field.key] as number || 0, field.decimals)}
                                                onBlur={(e) => {
                                                    const inputValue = e.target.value.replace(',', '.');
                                                    const numValue = parseFloat(inputValue);
                                                    updateCurrentRow(field.key, isNaN(numValue) ? 0 : numValue);
                                                }}
                                                className="w-24 h-10 bg-neutral-50 border-transparent focus:bg-white focus:border-black rounded-none font-mono text-xl text-right focus:ring-0 transition-all font-bold"
                                            />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>,
            document.body
        );
    }


    // --- MAIN VIEW ---
    return (
        <div className="w-full h-screen flex flex-col bg-white text-black overflow-hidden animate-fade-in">
            {/* Header */}
            <div className="h-20 border-b border-black flex items-center justify-between px-8 shrink-0">
                <div className="flex items-center gap-6">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => navigate(-1)}
                        className="rounded-none hover:bg-neutral-100 text-black h-10 w-10 border border-neutral-200"
                    >
                        <ArrowLeft className="h-4 w-4" />
                    </Button>
                    <div className="space-y-1">
                        <div className="flex items-center gap-3">
                            <h1 className="text-2xl font-serif text-black leading-none">
                                Sample Registration
                            </h1>
                            {coWorkers.length > 0 && (
                                <div className="flex items-center gap-2 bg-yellow-100 px-2 py-1 rounded-full border border-yellow-200 animate-pulse">
                                    <span className="text-[9px] font-bold uppercase text-yellow-700">{coWorkers.length} other(s) editing</span>
                                    <div className="flex -space-x-1">
                                        {coWorkers.map(cw => (
                                            <div key={cw.id} className="w-5 h-5 rounded-full bg-neutral-200 border border-white overflow-hidden" title={cw.nome || 'Unknown'}>
