// Função para extrair número decimal do texto (padrão brasileiro: vírgula = decimal)
const extractDecimal = (text: string): number => {
    if (!text) return 0;

    // Remove espaços
    let cleaned = text.replace(/\s/g, '');

    // Se tem vírgula E ponto, o ponto é milhar e vírgula é decimal (ex: 1.234,56)
    if (cleaned.includes('.') && cleaned.includes(',')) {
        cleaned = cleaned.replace(/\./g, ''); // Remove pontos de milhar
        cleaned = cleaned.replace(',', '.'); // Vírgula vira ponto decimal
    }
    // Se só tem vírgula, ela é o separador decimal (ex: 4,20)
    else if (cleaned.includes(',')) {
        cleaned = cleaned.replace(',', '.');
    }
    // Se só tem ponto, mantém como está (ex: 4.20)

    const match = cleaned.match(/(\d+\.?\d*)/);
    if (match) {
        const value = parseFloat(match[1]);
        return isNaN(value) ? 0 : value;
    }
    return 0;
};

// Funções de correção inteligente baseadas em faixas típicas de HVI
const sanitizeValue = (val: number, type: 'mic' | 'len' | 'unf' | 'str' | 'rd' | 'b'): number => {
    if (val === 0) return 0;

    // Remove casas decimais extras se for um número inteiro muito grande que parece ser erro de ponto
    // Ex: 301.0 -> 301 -> tratado abaixo

    switch (type) {
        case 'mic':
            // MIC típico: 2.0 a 6.0
            if (val >= 20 && val < 100) return val / 10;
            if (val >= 200 && val < 1000) return val / 100;
            break;
        case 'len':
            // LEN típico: 20.0 a 40.0
            if (val >= 200 && val < 500) return val / 10;
            if (val >= 2000 && val < 5000) return val / 100;
            break;
        case 'unf':
            // UNF típico: 70.0 a 90.0
            if (val >= 700 && val < 1000) return val / 10;
            if (val >= 7000 && val < 10000) return val / 100;
            break;
        case 'str':
            // STR típico: 15.0 a 50.0 (Resistência)
            // Range aceitável expandido: 10.0 a 60.0
            if (val >= 100 && val <= 600) return val / 10; // ex: 301 -> 30.1
            if (val >= 1000 && val <= 6000) return val / 100; // ex: 3010 -> 30.1
            break;
        case 'rd':
            // RD típico: 70.0 a 90.0
            if (val >= 700 && val < 1000) return val / 10;
            if (val >= 7000 && val < 10000) return val / 100;
            break;
        case 'b':
            // +b típico: 4.0 a 18.0
            if (val >= 40 && val < 200) return val / 10;
            if (val >= 400 && val < 2000) return val / 100;
            break;
    }
    return val;
};

// Função para formatar número para exibição (padrão brasileiro)
export const formatDecimalBR = (value: number, decimals: number = 2): string => {
    return value.toFixed(decimals).replace('.', ',');
};

// Função para extrair a data e hora da coluna Análise
const extractDateTime = (text: string): { data: string; hora: string } => {
    // Procura por padrão de data DD/MM/YYYY HH:MM:SS
    const match = text.match(/(\d{2}\/\d{2}\/\d{4})\s*(\d{2}:\d{2}:\d{2})/);
    if (match) {
        return { data: match[1], hora: match[2] };
    }
    // Tenta padrão alternativo
    const dateMatch = text.match(/(\d{2}\/\d{2}\/\d{4})/);
    const timeMatch = text.match(/(\d{2}:\d{2}:\d{2})/);
    return {
        data: dateMatch ? dateMatch[1] : new Date().toLocaleDateString('pt-BR'),
        hora: timeMatch ? timeMatch[1] : new Date().toLocaleTimeString('pt-BR')
    };
};

// Parser principal para extrair dados do texto OCR
const parseHVIData = (text: string): ExtractionResult => {
    const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
    const result: ExtractionResult = {
        mala: '',
        etiqueta: '',
        rows: [],
        rawText: text
    };

    // Extrai Mala - procura por padrão próximo a "Mala" ou número de 8 dígitos no início
    const malaMatch = text.match(/Mala[:\s]*(\d{6,10})/i) ||
        text.match(/^(\d{8})/m) ||
        text.match(/(\d{8})\s+\d{15,}/);
    if (malaMatch) {
        result.mala = malaMatch[1];
    }

    // Extrai Etiqueta - número longo de 15+ dígitos
    const etiquetaMatch = text.match(/Etiqueta[:\s]*(\d{12,25})/i) ||
        text.match(/\d{8}\s+(\d{15,25})/) ||
        text.match(/(\d{18,25})/);
    if (etiquetaMatch) {
        result.etiqueta = etiquetaMatch[1];
    }

    // PRIORIDADE 1: Procura pela linha "Média" ou "Media" na tabela de descrição
    // Esta é a linha que o usuário quer extrair (destacada em vermelho)
    for (const line of lines) {
        // Procura por linha que contém "Média" ou "2- Média" seguida de valores numéricos
        const mediaMatch = line.match(
            /[2-]?\s*M[eé]dia[:\s]*([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)/i
        );

        if (mediaMatch) {
            const dateTime = extractDateTime(text); // Pega data/hora do texto geral

            // Tenta encontrar o número da máquina HVI:
            // 1. Procura explicitamente por HVI: X ou Inst: X
            // 2. Procura nas linhas da tabela (padrão: Num HVI Data ...)
            let hviNumber = '1';

            const labelMatch = text.match(/HVI\s*[:#]?\s*(\d+)/i) || text.match(/Inst\s*[:\.]?\s*(\d+)/i);
            if (labelMatch) {
                hviNumber = labelMatch[1];
            } else {
                // Tenta achar na tabela. Padrão comum: Número Sequencial | HVI | Data
                // Ex: "1 2 25/01/2024..." -> HVI é 2
                const tableRowMatch = text.match(/^\s*\d+\s+(\d+)\s+\d{2}\/\d{2}/m) ||
                    text.match(/^\s*\d+\s+(\d+)\s+\d{2}:\d{2}/m);
                if (tableRowMatch) {
                    hviNumber = tableRowMatch[1];
                }
            }

            result.rows.push({
                numero: 'M', // M de Média
                hvi: hviNumber,
                data_analise: dateTime.data,
                hora_analise: dateTime.hora,
                mic: sanitizeValue(extractDecimal(mediaMatch[1]), 'mic'),
                len: sanitizeValue(extractDecimal(mediaMatch[2]), 'len'),
                unf: sanitizeValue(extractDecimal(mediaMatch[3]), 'unf'),
                str: sanitizeValue(extractDecimal(mediaMatch[4]), 'str'),
                rd: sanitizeValue(extractDecimal(mediaMatch[5]), 'rd'),
                b: sanitizeValue(extractDecimal(mediaMatch[6]), 'b')
            });
            break; // Encontrou a média, para de procurar
        }
    }

    // PRIORIDADE 2: Se não encontrou Média, tenta extrair linhas individuais da tabela HVI
    if (result.rows.length === 0) {
        for (const line of lines) {
            // Procura por linha que começa com número e contém padrão de data
            const rowMatch = line.match(
                /^\s*(\d+)\s+(\d+)\s+(\d{2}\/\d{2}\/\d{4})\s*(\d{2}:\d{2}:\d{2})\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)\s+([\d,\.]+)/
            );

            if (rowMatch) {
                result.rows.push({
                    numero: rowMatch[1],
                    hvi: rowMatch[2],
                    data_analise: rowMatch[3],
                    hora_analise: rowMatch[4],
                    mic: sanitizeValue(extractDecimal(rowMatch[5]), 'mic'),
                    len: sanitizeValue(extractDecimal(rowMatch[6]), 'len'),
                    unf: sanitizeValue(extractDecimal(rowMatch[7]), 'unf'),
                    str: sanitizeValue(extractDecimal(rowMatch[8]), 'str'),
                    rd: sanitizeValue(extractDecimal(rowMatch[9]), 'rd'),
                    b: sanitizeValue(extractDecimal(rowMatch[10]), 'b')
                });
            }
        }
    }

    // PRIORIDADE 3: Se ainda não encontrou, tenta padrão mais flexível
    if (result.rows.length === 0) {
        const numberPattern = /(\d+[,\.]\d+)/g;

        for (const line of lines) {
            const numbers = line.match(numberPattern);
            // Uma linha de dados típica tem 6 valores numéricos (Mic, Len, Unf, Str, Rd, +b)
            if (numbers && numbers.length >= 6) {
                const dateTime = extractDateTime(line);
                const numMatch = line.match(/^\s*(\d+)/);

                result.rows.push({
                    numero: numMatch ? numMatch[1] : '1',
                    hvi: '1',
                    data_analise: dateTime.data,
                    hora_analise: dateTime.hora,
                    mic: sanitizeValue(extractDecimal(numbers[0]), 'mic'),
                    len: sanitizeValue(extractDecimal(numbers[1]), 'len'),
                    unf: sanitizeValue(extractDecimal(numbers[2]), 'unf'),
                    str: sanitizeValue(extractDecimal(numbers[3]), 'str'),
                    rd: sanitizeValue(extractDecimal(numbers[4]), 'rd'),
                    b: sanitizeValue(extractDecimal(numbers[5]), 'b')
                });
            }
        }
    }

    return result;
};

export const OCRExtractionService = {
    async extractFromImage(file: File, onProgress?: (progress: number) => void): Promise<ExtractionResult> {
        return new Promise(async (resolve, reject) => {
            try {
                const imageUrl = URL.createObjectURL(file);

                const result = await Tesseract.recognize(
                    imageUrl,
                    'por', // Português
                    {
                        logger: (m) => {
                            if (m.status === 'recognizing text' && onProgress) {
                                onProgress(Math.round(m.progress * 100));
                            }
                        }
                    }
                );

                URL.revokeObjectURL(imageUrl);

                const extractedData = parseHVIData(result.data.text);

                // Se não conseguiu extrair dados, retorna erro
                if (extractedData.rows.length === 0 && !extractedData.mala && !extractedData.etiqueta) {
                    // Tenta extrair com um parsing mais agressivo
                    console.log('OCR Raw Text:', result.data.text);

                    // Fallback: extrai valores numéricos encontrados
                    const allNumbers = result.data.text.match(/\d+[,\.]\d+/g) || [];
                    if (allNumbers.length >= 6) {
                        extractedData.rows.push({
                            numero: '1',
                            hvi: '1',
                            data_analise: new Date().toLocaleDateString('pt-BR'),
                            hora_analise: new Date().toLocaleTimeString('pt-BR'),
                            mic: extractDecimal(allNumbers[0] ?? '0'),
                            len: extractDecimal(allNumbers[1] ?? '0'),
                            unf: extractDecimal(allNumbers[2] ?? '0'),
                            str: extractDecimal(allNumbers[3] ?? '0'),
                            rd: extractDecimal(allNumbers[4] ?? '0'),
                            b: extractDecimal(allNumbers[5] ?? '0')
                        });
                    }
                }

                resolve(extractedData);
            } catch (error) {
                console.error('OCR Error:', error);
                reject(error);
            }
        });
    },

    // Converte uma linha de dados para o formato SingleSampleData
    rowToSingleSample(row: HVIDataRow, mala: string, etiqueta: string): SingleSampleData {
        return {
            mic: row.mic,
            len: row.len,
            unf: row.unf,
            str: row.str,
            rd: row.rd,
            b: row.b,
            mala: mala,
            etiqueta: etiqueta,
            data_analise: row.data_analise,
            hora_analise: row.hora_analise
        };
    }
};

import { supabase } from '../lib/supabase';

export interface ProducaoData {
    id?: string;
    lab_id: string;
    identificador_unico: string;
    data_producao: string;
    turno: string;
    produto: string;
    peso: number;
    metadata?: any;
    created_at?: string;
}

const STORAGE_KEY = 'fibertech_producao_data';

const isSupabaseEnabled = () => {
    const url = import.meta.env.VITE_SUPABASE_URL;
    const key = import.meta.env.VITE_SUPABASE_ANON_KEY;
    return !!url && url !== 'YOUR_SUPABASE_URL' && !!key && key !== 'YOUR_SUPABASE_ANON_KEY';
};

const getStoredProducao = (): ProducaoData[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        return data ? JSON.parse(data) : [];
    } catch {
        return [];
    }
};

const saveStoredProducao = (data: ProducaoData[]) => {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data.slice(-5000))); // Keep last 5000
    } catch (e) {
        console.warn("Storage full, could not save all production data:", e);
    }
};

export const producaoService = {
    async uploadData(data: ProducaoData[], _labId?: string) {
        if (data.length === 0) return;

        if (isSupabaseEnabled()) {
            try {
                // Chunking upload (batches of 1000)
                const BATCH_SIZE = 1000;
                for (let i = 0; i < data.length; i += BATCH_SIZE) {
                    const chunk = data.slice(i, i + BATCH_SIZE).map(d => ({
                        ...d,
                        created_at: new Date().toISOString() // Ensure fresh timestamp on upload
                    }));

                    const { error } = await supabase
                        .from('operacao_producao')
                        .upsert(chunk, {
                            onConflict: 'lab_id,identificador_unico',
                            ignoreDuplicates: false
                        });

                    if (error) throw error;
                }
                return; // Success
            } catch (err) {
                console.warn("Supabase upload failed, falling back to local:", err);
            }
        }

        // FALLBACK: Local Storage
        const local = getStoredProducao();
        // Upsert logic for local
        const updated = [...local];
        const now = new Date().toISOString();
        data.forEach(item => {
            const idx = updated.findIndex(u => u.identificador_unico === item.identificador_unico && u.lab_id === item.lab_id);
            if (idx >= 0) updated[idx] = { ...item, created_at: now } as any;
            else updated.push({ ...item, created_at: now } as any);
        });
        saveStoredProducao(updated);
    },

    async list(labId?: string): Promise<ProducaoData[]> {
        if (isSupabaseEnabled()) {
            try {
                // Background cleanup: DISABLED so older records don't get deleted automatically
                // supabase
                //     .from('operacao_producao')
                //     .delete()
                //     .lt('created_at', twentyFourHoursAgo)
                //     .then(({ error }) => {
                //         if (error) console.warn("Background cleanup error (producao):", error);
                //     });

                let query = supabase
                    .from('operacao_producao')
                    .select('*');

                if (labId !== 'all') {
                    query = query.eq('lab_id', labId);
                }

                const { data, error } = await query.order('data_producao', { ascending: true });
                if (error) throw error;
                return data || [];
            } catch (err) {
                console.warn("Supabase list failed, falling back to local:", err);
            }
        }

        // Local Storage filtering
        const local = getStoredProducao();
        const filtered = local;

        return labId === 'all' ? filtered : (labId ? filtered.filter(p => p.lab_id === labId) : filtered);
    },

    async deleteAll(labId: string) {
        if (isSupabaseEnabled()) {
            try {
                const { error } = await supabase
                    .from('operacao_producao')
                    .delete()
                    .eq('lab_id', labId);

                if (error) throw error;
            } catch (err) {
                console.warn("Supabase delete failed:", err);
            }
        }
        const local = getStoredProducao().filter(p => p.lab_id !== labId);
        saveStoredProducao(local);
    }
};

import { supabase } from "@/lib/supabase";

export interface StatusOS {
    id: string;
    os_numero: string;
    romaneio: string;
    cliente: string;
    fazenda: string;
    usina: string;
    variedade: string;
    data_registro: string;
    data_recepcao: string;
    data_acondicionamento: string;
    data_finalizacao: string;
    revisor: string;
    status: string;
    total_amostras: number;
    peso_mala: number;
    peso_medio: number;
    horas: number;
    nota_fiscal: string;
    fatura: string;
    lab_id?: string;
    created_at: string;
}

const STORAGE_KEY = 'fibertech_status_os_data';
const CACHE_TS_KEY = 'fibertech_status_os_ts'; // timestamp da última busca ao Supabase
const CACHE_TTL_MS = 60_000; // 60 segundos de validade do cache

const isSupabaseEnabled = () => {
    const url = import.meta.env.VITE_SUPABASE_URL;
    const key = import.meta.env.VITE_SUPABASE_ANON_KEY;
    return !!url && url !== 'YOUR_SUPABASE_URL' && !!key && key !== 'YOUR_SUPABASE_ANON_KEY';
};

const getStoredStatusOS = (): StatusOS[] => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        return data ? JSON.parse(data) : [];
    } catch {
        return [];
    }
};

const saveStoredStatusOS = (data: StatusOS[]) => {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data.slice(-5000))); // Keep last 5000
    } catch (e) {
        console.warn("Storage full, could not save all StatusOS data:", e);
    }
};

export const statusOSService = {
    async uploadData(data: any[], labId: string) {
        const now = new Date().toISOString();
        // Formata os dados para o banco
        const formattedData = data.map(item => ({
            lab_id: labId,
            os_numero: item.os_numero,
            romaneio: item.romaneio,
            cliente: item.cliente,
            fazenda: item.fazenda,
            usina: item.usina,
            variedade: item.variedade,
            data_registro: item.data_registro,
            data_recepcao: item.data_recepcao,
            data_acondicionamento: item.data_acondicionamento,
            data_finalizacao: item.data_finalizacao,
            revisor: item.revisor,
            status: item.status,
            total_amostras: item.total_amostras,
            peso_mala: item.peso_mala,
            peso_medio: item.peso_medio,
            horas: item.horas,
            nota_fiscal: item.nota_fiscal,
            fatura: item.fatura,
            created_at: now
        }));

        if (isSupabaseEnabled()) {
            try {
                // Chunking upload (batches of 1000)
                const BATCH_SIZE = 1000;
                for (let i = 0; i < formattedData.length; i += BATCH_SIZE) {
                    const chunk = formattedData.slice(i, i + BATCH_SIZE);
                    const { error } = await supabase
                        .from('status_os_hvi')
                        .upsert(chunk, { onConflict: 'os_numero,lab_id' });

                    if (error) {
                        // Fallback to older onConflict if lab_id is not part of it
                        const { error: fallbackError } = await supabase
                            .from('status_os_hvi')
                            .upsert(chunk, { onConflict: 'os_numero' });
                        if (fallbackError) throw fallbackError;
                    }
                }

                // SUCESSO NO SUPABASE: Atualizar o localStorage à imagem do Supabase
                // para evitar duplicação no próximo merge
                const local = getStoredStatusOS() as any[];
                const updated = [...local];
                formattedData.forEach(item => {
                    const idx = updated.findIndex(u => u.os_numero === item.os_numero && u.lab_id === item.lab_id);
                    if (idx >= 0) updated[idx] = { ...updated[idx], ...item };
                    else updated.push(item);
                });
                saveStoredStatusOS(updated);
                return; // Upload para Supabase concluído, não precisa do bloco offline
            } catch (err) {
                console.warn("Supabase upload failed, falling back primarily to local:", err);
            }
        }

        // FALLBACK OFFLINE: salvar apenas no localStorage
        const local = getStoredStatusOS() as any[];
        const updated = [...local];
        formattedData.forEach(item => {
            const idx = updated.findIndex(u => u.os_numero === item.os_numero && u.lab_id === item.lab_id);
            if (idx >= 0) updated[idx] = { ...updated[idx], ...item };
            else updated.push(item);
        });
        saveStoredStatusOS(updated);
    },

    async getAll(labId: string) {
        if (isSupabaseEnabled()) {
            // ── TTL: se dados foram buscados há menos de 60s, retorna cache local ────────
            try {
                const lastFetch = parseInt(localStorage.getItem(CACHE_TS_KEY) || '0', 10);
                const isRecent = (Date.now() - lastFetch) < CACHE_TTL_MS;
                if (isRecent && getStoredStatusOS().length > 0) {
                    const local = getStoredStatusOS();
                    return (labId === 'all' ? local : local.filter(d => d.lab_id === labId)) as StatusOS[];
                }
            } catch (_) { /* ignora falha de leitura do timestamp */ }

            try {
                const PAGE_SIZE = 5000; // Supabase suporta até 5000 por request

                // 1. Obtém o total de registros com uma query leve (count only)
                let countQuery = supabase
                    .from('status_os_hvi')
                    .select('*', { count: 'exact', head: true });
                if (labId !== 'all') countQuery = countQuery.eq('lab_id', labId);

                const { count, error: countError } = await countQuery;
                if (countError) throw countError;

                const total = count || 0;
                const totalPages = Math.ceil(total / PAGE_SIZE);

                // 2. Busca todas as páginas EM PARALELO com Promise.all
                const pageRequests = Array.from({ length: totalPages }, (_, i) => {
                    let q = supabase
                        .from('status_os_hvi')
                        .select('*')
                        .range(i * PAGE_SIZE, (i + 1) * PAGE_SIZE - 1);
                    if (labId !== 'all') q = q.eq('lab_id', labId);
                    return q;
                });

                const results = await Promise.all(pageRequests);

                let allData: any[] = [];
                for (const res of results) {
                    if (res.error) throw res.error;
                    if (res.data) allData = allData.concat(res.data);
                }

                // 3. Merge: Supabase é fonte de verdade.
                // Adiciona apenas itens offline do localStorage que não existem no Supabase.
                const local = getStoredStatusOS() as any[];
                const supabaseNums = new Set(allData.map((d: any) => `${d.os_numero}|${d.lab_id}`));
                local.forEach(localItem => {
                    const key = `${localItem.os_numero}|${localItem.lab_id}`;
                    const belongsToScope = labId === 'all' || localItem.lab_id === labId;
                    if (!supabaseNums.has(key) && belongsToScope) {
                        allData.push(localItem);
                    }
                });

                // 4. Atualiza localStorage como cache + registra timestamp
                if (allData.length > 0) {
                    saveStoredStatusOS(allData.slice(0, 10000)); // Cache dos 10k mais recentes
                    localStorage.setItem(CACHE_TS_KEY, String(Date.now())); // marca hora da busca
                }

                return allData as StatusOS[];
            } catch (err) {
                console.warn("Supabase getAll failed, falling back strictly to local:", err);
            }
        }
        // Fallback: dados do localStorage
        const local = getStoredStatusOS();
        const validLocal = local; // No more 24h cut-off for legacy data here based on user complaint

        return labId === 'all' ? validLocal : validLocal.filter(d => d.lab_id === labId);
    },

    async getStats(labId: string) {
        let allData: any[] = [];

        if (isSupabaseEnabled()) {
            try {
                const PAGE_SIZE = 5000;
                let countQ = supabase
                    .from('status_os_hvi')
                    .select('status, data_recepcao, data_finalizacao, total_amostras, created_at, lab_id', { count: 'exact', head: true });
                if (labId !== 'all') countQ = countQ.eq('lab_id', labId);
                const { count } = await countQ;
                const totalPages = Math.ceil((count || 0) / PAGE_SIZE);

                const reqs = Array.from({ length: totalPages }, (_, i) => {
                    let q = supabase
                        .from('status_os_hvi')
                        .select('status, data_recepcao, data_finalizacao, total_amostras, created_at, lab_id')
                        .range(i * PAGE_SIZE, (i + 1) * PAGE_SIZE - 1);
                    if (labId !== 'all') q = q.eq('lab_id', labId);
                    return q;
                });

                const results = await Promise.all(reqs);
                for (const res of results) {
                    if (res.data) allData = allData.concat(res.data);
                }

                // Merge itens offline pendentes
                const local = getStoredStatusOS();
                const offlineValid = local.filter(d => (labId === 'all' || d.lab_id === labId));
                offlineValid.forEach(item => {
                    if (!allData.find(d => d.os_numero === item.os_numero)) {
                        allData.push(item);
                    }
                });
            } catch (e) {
                console.warn("Stats fetch failed", e);
            }
        } else {
            const local = getStoredStatusOS();
            allData = local.filter(d => (labId === 'all' || d.lab_id === labId));
        }

        const data = allData;
        const total = data.length;
        const faturados = data.filter(d => d.status?.toLowerCase().includes('faturado')).length;
        const emAberto = total - faturados;
        const totalAmostras = data.reduce((acc, curr) => acc + (curr.total_amostras || 0), 0);

        return { total, faturados, emAberto, totalAmostras };
    },

    async clearData(labId: string) {
        if (isSupabaseEnabled()) {
            try {
                const { error } = await supabase
                    .from('status_os_hvi')
                    .delete()
                    .eq('lab_id', labId);

                if (error) throw error;
            } catch (err) {
                console.warn("Supabase clear failed:", err);
            }
        }
        const local = getStoredStatusOS().filter(d => d.lab_id !== labId);
        if (local.length === 0) {
            localStorage.removeItem(STORAGE_KEY);
        } else {
            saveStoredStatusOS(local);
        }
    },

    /**
     * Retorna dados em cache (localStorage) filtrados por labId.
     * Usado para renderização imediata (stale-while-revalidate).
     */
    getCached(labId: string): StatusOS[] {
        const local = getStoredStatusOS();
        if (labId === 'all') return local;
        return local.filter(d => d.lab_id === labId);
    }
};
